export type ReconStats = {
	calls: number;
	bashCalls: number;
	failures: number;
	lastCommandHash?: string;
	repeatedCommandCount: number;
	lastCommands: string[];
	active: boolean;
	selfReviewDue: boolean;
	lastRoute?: RoutePlan;
	currentMissionId?: string;
	sessionFile?: string;
	noSession?: boolean;
};

function allowNoSessionReconWriteback(): boolean {
	return (
		envBoolean("REPI_RUNTIME_WRITEBACK_NO_SESSION") ??
		envBoolean("REPI_MEMORY_WRITEBACK_NO_SESSION") ??
		false
	);
}

