type RuntimeFailureStatus = "failed" | "repair_queued" | "exhausted" | "blocked" | "rolled_back";
type RuntimeRepairAction = "rerun" | "replace-command" | "recapture-evidence" | "refresh-context" | "escalate" | "rollback";

