function buildExploitLabArtifact(options: {
	target?: string;
	mode?: "plan" | "run" | "bundle";
	runs?: number;
	timeoutMs?: number;
	executions?: ExploitLabExecution[];
	stabilityAnchors?: string[];
}): ExploitLabArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const target = inferExploitLabTarget(options.target);
	const targetKind = classifyRepiTarget(target).kind;
	const directoryMode = targetKind === "directory";
	const runs = Math.max(1, Math.min(25, Math.floor(options.runs ?? 5)));
	const timeoutMs = Math.max(1000, Math.min(300000, Math.floor(options.timeoutMs ?? 8000)));
	const command = directoryMode
		? `find ${shellQuote(target!)} -maxdepth 4 -type f \\( -perm -111 -o -name '*.py' -o -name '*.js' -o -name '*.sh' -o -name '*poc*' -o -name '*exploit*' \\) -exec file {} \\; 2>/dev/null | tee /tmp/repi-exploit-lab-candidates.txt | head -120`
		: target
		? exploitLabShellCommand(target, runs, timeoutMs)
		: "# missing target: pass PoC path or set REPI_EXPLOIT_CMD";
	const labMatrix = [
		`target=${target ?? "<missing>"}`,
		...(directoryMode ? ["target_type=directory", "mode=directory-candidate-selection"] : []),
		`mode=${options.mode ?? "plan"}`,
		`runs=${runs}`,
		`timeout_ms=${timeoutMs}`,
		"contract=inventory -> environment pin -> replay matrix -> flake triage -> bundle manifest",
		"runner=python3 harness with REPI_EXPLOIT_CMD override",
	];
	const pocInventory = [
		directoryMode
			? `directory=${target}: enumerate executable/script/PoC candidates; rerun re_exploit_lab plan <candidate> before replay`
			: target
			? `inventory target path/hash/executable/shebang for ${target}`
			: "inventory target path/hash/executable/shebang for <PoC>",
		"classify runner: python/node/bash/executable/REPI_EXPLOIT_CMD",
		"record payloads, local/remote endpoint assumptions, credentials/session inputs, and generated artifacts",
	];
	const environmentPins = [
		"pin python/node/ruby/go versions, uname/platform, cwd, PATH, package lock files, Dockerfile/compose, libc/loader when present",
		"record timeout, run count, ASLR/network/service assumptions, target hash and exploit command hash",
	];
	const replayMatrix = [
		`execute ${runs} bounded run(s) with timeout ${timeoutMs}ms`,
		"record exit, duration, stdout/stderr length, stdout_sha256, stderr_sha256, and timeout/nonzero state",
		"calculate success_rate, unique exits, unique output hashes, and stability verdict",
	];
	const flakeTriage = [
		"if success_rate < 1.0 or unique hashes drift, isolate timing, ASLR, network, heap/libc, race and cleanup assumptions",
		"rerun with REPI_EXPLOIT_CMD, pinned service reset, longer timeout, or per-run pre/post hooks",
	];
	const bundleManifest = [
		"/tmp/repi-exploit-lab-manifest.json captures inventory, command, run rows and stability stats",
		"bundle must include PoC, payload/config, target hash, replay matrix, stdout/stderr hashes and reproduction command",
	];
	const nextActions = Array.from(
		new Set(
			[
				target && (options.mode ?? "plan") !== "run"
					? directoryMode
						? `re_lane plan triage ${target} && re_exploit_lab plan <candidate-from-/tmp/repi-exploit-lab-candidates.txt>`
						: `re_exploit_lab run ${target} ${runs} ${timeoutMs}`
					: undefined,
				"re_verifier matrix",
				"re_compiler draft",
				"re_replayer run",
				"re_knowledge_graph build",
				"re_complete audit",
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 12);
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target,
		mode: options.mode ?? "plan",
		runs,
		timeoutMs,
		labMatrix,
		pocInventory,
		environmentPins,
		replayMatrix,
		flakeTriage,
		bundleManifest,
		labCommands: [command],
		executions: options.executions ?? [],
		stabilityAnchors: options.stabilityAnchors ?? [],
		nextActions,
		sourceArtifacts: [
			latestCompilerArtifactPath(),
			latestReplayerArtifactPath(),
			latestVerifierArtifactPath(),
			latestOperatorArtifactPath(),
			recentMarkdownArtifacts(evidenceRunsDir(), 1)[0],
			recentMarkdownArtifacts(evidenceMapsDir(), 1)[0],
		].filter((path): path is string => Boolean(path)),
	};
}

function formatExploitLab(lab: ExploitLabArtifact, path?: string): string {
	return [
		"exploit_lab:",
		path ? `exploit_lab_artifact: ${path}` : undefined,
		`timestamp: ${lab.timestamp}`,
		`mode: ${lab.mode}`,
		`mission_id: ${lab.missionId ?? "none"}`,
		`route: ${lab.route ?? "none"}`,
		`target: ${lab.target ?? "<missing>"}`,
		`runs: ${lab.runs}`,
		`timeout_ms: ${lab.timeoutMs}`,
		"lab_matrix:",
		...(lab.labMatrix.length ? lab.labMatrix.map((item) => `- ${item}`) : ["- none"]),
		"poc_inventory:",
		...(lab.pocInventory.length ? lab.pocInventory.map((item) => `- ${item}`) : ["- none"]),
		"environment_pins:",
		...(lab.environmentPins.length ? lab.environmentPins.map((item) => `- ${item}`) : ["- none"]),
		"replay_matrix:",
		...(lab.replayMatrix.length ? lab.replayMatrix.map((item) => `- ${item}`) : ["- none"]),
		"flake_triage:",
		...(lab.flakeTriage.length ? lab.flakeTriage.map((item) => `- ${item}`) : ["- none"]),
		"bundle_manifest:",
		...(lab.bundleManifest.length ? lab.bundleManifest.map((item) => `- ${item}`) : ["- none"]),
		"executions:",
		...(lab.executions.length
			? lab.executions.map(
					(item) =>
						`- ${item.label} [${item.status}] exit=${item.exit ?? "n/a"} stdout_sha256=${item.stdoutHash ?? "n/a"} stderr_sha256=${item.stderrHash ?? "n/a"}`,
				)
			: ["- planned lab; run re_exploit_lab run <PoC> [runs] [timeout-ms]"]),
		"stability_anchors:",
		...(lab.stabilityAnchors.length ? lab.stabilityAnchors.map((item) => `- ${item}`) : ["- none"]),
		"lab_commands:",
		...lab.labCommands.flatMap((command) => ["```bash", command, "```"]),
		"lab_next_actions:",
		...(lab.nextActions.length ? lab.nextActions.map((item) => `- ${item}`) : ["- re_verifier matrix"]),
		`next_lab_command: ${lab.mode === "plan" ? `re_exploit_lab run ${lab.target ?? "<PoC>"} ${lab.runs} ${lab.timeoutMs}` : "re_compiler draft"}`,
		"source_artifacts:",
		...(lab.sourceArtifacts.length ? lab.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeExploitLabArtifact(lab: ExploitLabArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceExploitLabDir(),
		`${lab.timestamp.replace(/[:.]/g, "-")}-${slug(lab.target ?? lab.route ?? "exploit-lab")}-${lab.mode}.md`,
	);
	writePrivateTextFile(
		path,
		[
			"# REPI Exploit Lab Artifact",
			"",
			formatExploitLab(lab, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(lab, null, 2),
			"```",
			"",
		].join("\n"),
	);
	appendEvidence({
		kind: lab.mode === "run" ? "runtime" : "artifact",
		title: `exploit-lab-${lab.mode} ${lab.target ?? lab.missionId ?? "no-target"}`,
		fact: `Exploit lab ${lab.mode}: target=${lab.target ?? "<missing>"}, runs=${lab.runs}, executions=${lab.executions.length}, anchors=${lab.stabilityAnchors.length}`,
		command: `re_exploit_lab ${lab.mode}${lab.target ? ` ${lab.target}` : ""}`,
		path,
		verify: `cat ${path}`,
		confidence: "exploit reliability lab artifact",
	});
	updateMissionCheckpoint("exploit_lab_ready", lab.mode === "run" && lab.executions.length === 0 ? "blocked" : "done", path);
	return path;
}

async function runExploitLab(
	pi: ExtensionAPI,
	options: { target?: string; runs?: number; timeoutMs?: number } = {},
): Promise<string> {
	const target = inferExploitLabTarget(options.target);
	const targetKind = classifyRepiTarget(target).kind;
	const runs = Math.max(1, Math.min(25, Math.floor(options.runs ?? 5)));
	const timeoutMs = Math.max(1000, Math.min(300000, Math.floor(options.timeoutMs ?? 8000)));
	if (!target) {
		const lab = buildExploitLabArtifact({ ...options, mode: "run", runs, timeoutMs });
		lab.executions.push({ label: "exploit-lab-replay", command: lab.labCommands[0] ?? "", status: "blocked" });
		lab.stabilityAnchors.push(
			"Exploit Lab blocked anchors: missing concrete PoC target; pass target or REPI_EXPLOIT_CMD",
		);
		const path = writeExploitLabArtifact(lab);
		return formatExploitLab(lab, path);
	}
	if (targetKind === "directory") {
		const lab = buildExploitLabArtifact({ ...options, target, mode: "run", runs, timeoutMs });
		const command = lab.labCommands[0] ?? "";
		const result = await pi.exec("bash", ["-lc", command], { timeout: Math.min(60000, timeoutMs + 10000) });
		lab.executions.push({
			label: "exploit-lab-candidate-selection",
			command,
			status: result.code === 0 ? "passed" : "failed",
			exit: result.code,
			killed: result.killed,
			stdoutHash: replayHash(result.stdout),
			stderrHash: replayHash(result.stderr),
			stdoutHead: truncateMiddle(result.stdout.trim(), 3000),
			stderrHead: truncateMiddle(result.stderr.trim(), 2000),
		});
		lab.stabilityAnchors.push(
			"Exploit Lab candidate selection anchors: directory target requires choosing a concrete PoC/executable before replay",
		);
		const path = writeExploitLabArtifact(lab);
		return [
			formatExploitLab(lab, path),
			result.stdout.trim() ? ["stdout:", "```", truncateMiddle(result.stdout.trim(), 6000), "```"].join("\n") : "",
			result.stderr.trim() ? ["stderr:", "```", truncateMiddle(result.stderr.trim(), 2000), "```"].join("\n") : "",
		]
			.filter(Boolean)
			.join("\n");
	}
	const command = exploitLabShellCommand(target, runs, timeoutMs);
	const result = await pi.exec("bash", ["-lc", command], { timeout: Math.min(900000, timeoutMs * runs + 20000) });
	const anchors = exploitLabAnchors(result.stdout, result.stderr);
	const lab = buildExploitLabArtifact({
		...options,
		target,
		mode: "run",
		runs,
		timeoutMs,
		executions: [
			{
				label: "exploit-lab-replay",
				command,
				status: result.code === 0 ? "passed" : "failed",
				exit: result.code,
				killed: result.killed,
				stdoutHash: replayHash(result.stdout),
				stderrHash: replayHash(result.stderr),
				stdoutHead: truncateMiddle(result.stdout.trim(), 3000),
				stderrHead: truncateMiddle(result.stderr.trim(), 2000),
			},
		],
		stabilityAnchors: anchors,
	});
	const path = writeExploitLabArtifact(lab);
	return [
		formatExploitLab(lab, path),
		result.stdout.trim() ? ["stdout:", "```", truncateMiddle(result.stdout.trim(), 6000), "```"].join("\n") : "",
		result.stderr.trim() ? ["stderr:", "```", truncateMiddle(result.stderr.trim(), 2000), "```"].join("\n") : "",
	]
		.filter(Boolean)
		.join("\n");
}

function buildExploitLabOutput(
	action: "plan" | "show" | "bundle" = "plan",
	options: { target?: string; runs?: number; timeoutMs?: number } = {},
): string {
	if (action === "show") {
		const path = latestExploitLabArtifactPath();
		if (!path) return "exploit_lab:\nstatus: missing\nnext: re_exploit_lab plan <PoC>";
		return truncateMiddle(readText(path), 22000);
	}
	const stabilityAnchors =
		action === "bundle" && latestExploitLabArtifactPath()
			? [
					`Exploit Lab artifact bundle anchors: source=${latestExploitLabArtifactPath()}`,
					...exploitLabAnchors(readText(latestExploitLabArtifactPath()!), ""),
				]
			: undefined;
	const lab = buildExploitLabArtifact({
		...options,
		mode: action === "bundle" ? "bundle" : "plan",
		stabilityAnchors,
	});
	const path = writeExploitLabArtifact(lab);
	return formatExploitLab(lab, path);
}

function latestMobileRuntimeArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("mobile_runtime", evidenceMobileRuntimeDir(), options);
}

function inferMobilePackageName(target?: string, packageName?: string): string | undefined {
	const explicit = packageName?.trim();
	if (explicit) return explicit.replace(/^package:/i, "");
	const trimmed = target?.trim();
	if (trimmed && /^[A-Za-z][\w]*(?:\.[A-Za-z][\w]*){1,}$/.test(trimmed) && !trimmed.endsWith(".apk")) return trimmed;
	for (const path of [recentMarkdownArtifacts(evidenceMapsDir(), 1)[0], latestMobileRuntimeArtifactPath()]) {
		if (!path) continue;
		const text = readText(path);
		const match = /(?:package(?:Name)?|applicationId)[:=\s"']+([A-Za-z][\w]*(?:\.[A-Za-z][\w]*)+)/i.exec(text)?.[1];
		if (match) return match;
	}
	return undefined;
}

function mobileRuntimeFridaHookScript(): string {
	return `'use strict';
function safe(v) { try { return String(v); } catch (_) { return '<err>'; } }
function hex(bytes, limit) {
  try {
    const n = Math.min(bytes.length, limit || 32);
    let out = [];
    for (let i = 0; i < n; i++) out.push(('0' + (bytes[i] & 0xff).toString(16)).slice(-2));
    return out.join('');
  } catch (_) { return '<hex-err>'; }
}
if (Java.available) {
  Java.perform(function () {
    console.log('[mobile-crypto-hook] Java.perform ready');
    try {
      const Debug = Java.use('android.os.Debug');
      Debug.isDebuggerConnected.implementation = function () {
        const ret = this.isDebuggerConnected();
        console.log('[mobile-anti-debug-hook] Debug.isDebuggerConnected ret=' + ret);
        return ret;
      };
    } catch (e) { console.log('[mobile-hook-miss] android.os.Debug ' + e); }
    try {
      const StringCls = Java.use('java.lang.String');
      StringCls.equals.implementation = function (other) {
        const ret = this.equals(other);
        console.log('[mobile-compare-hook] String.equals self=' + safe(this) + ' other=' + safe(other) + ' ret=' + ret);
        return ret;
      };
    } catch (e) { console.log('[mobile-hook-miss] java.lang.String.equals ' + e); }
    try {
      const Cipher = Java.use('javax.crypto.Cipher');
      Cipher.doFinal.overload('[B').implementation = function (input) {
        console.log('[mobile-crypto-hook] Cipher.doFinal in=' + hex(input, 48));
        const out = this.doFinal(input);
        console.log('[mobile-crypto-hook] Cipher.doFinal out=' + hex(out, 48));
        return out;
      };
    } catch (e) { console.log('[mobile-hook-miss] javax.crypto.Cipher.doFinal ' + e); }
    try {
      const MessageDigest = Java.use('java.security.MessageDigest');
      MessageDigest.digest.overload('[B').implementation = function (input) {
        console.log('[mobile-crypto-hook] MessageDigest.digest alg=' + this.getAlgorithm() + ' in=' + hex(input, 48));
        const out = this.digest(input);
        console.log('[mobile-crypto-hook] MessageDigest.digest out=' + hex(out, 48));
        return out;
      };
    } catch (e) { console.log('[mobile-hook-miss] MessageDigest.digest ' + e); }
    try {
      const Mac = Java.use('javax.crypto.Mac');
      Mac.doFinal.overload('[B').implementation = function (input) {
        console.log('[mobile-crypto-hook] Mac.doFinal alg=' + this.getAlgorithm() + ' in=' + hex(input, 48));
        const out = this.doFinal(input);
        console.log('[mobile-crypto-hook] Mac.doFinal out=' + hex(out, 48));
        return out;
      };
    } catch (e) { console.log('[mobile-hook-miss] Mac.doFinal ' + e); }
  });
} else {
  console.log('[mobile-runtime-blocked] reason=java_unavailable');
}
for (const name of ['strcmp', 'strncmp', 'memcmp', 'strstr']) {
  const ptr = Module.findExportByName(null, name);
  if (!ptr) continue;
  Interceptor.attach(ptr, {
    onEnter(args) {
      this.name = name;
      this.a0 = args[0];
      this.a1 = args[1];
      console.log('[mobile-native-hook] ' + name + ' a0=' + args[0] + ' a1=' + args[1]);
      try { console.log('[mobile-native-hook] ' + name + ' s0=' + args[0].readCString().slice(0, 160)); } catch (_) {}
      try { console.log('[mobile-native-hook] ' + name + ' s1=' + args[1].readCString().slice(0, 160)); } catch (_) {}
    },
    onLeave(retval) { console.log('[mobile-native-hook] ' + this.name + ' ret=' + retval); }
  });
}`;
}

function mobileRuntimeShellCommand(target?: string, packageName?: string, timeoutMs = 15000): string {
	const targetArg = shellQuote(target?.trim() ?? "");
	const packageArg = shellQuote(packageName?.trim() ?? "");
	const attachTimeout = Math.max(3, Math.ceil(timeoutMs / 1000));
	return [
		"set +e",
		`TARGET=${targetArg}`,
		`PKG=${packageArg}`,
		'printf "[mobile-env] adb=%s frida=%s frida_ps=%s jadx=%s apktool=%s gdb=%s\\n" "$(command -v adb || true)" "$(command -v frida || true)" "$(command -v frida-ps || true)" "$(command -v jadx || true)" "$(command -v apktool || true)" "$(command -v gdb || true)"',
		`if [ -n "$TARGET" ] && [ -e "$TARGET" ]; then printf "[mobile-apk] target=%s bytes=%s sha256=%s file=%s\\n" "$TARGET" "$(wc -c < "$TARGET" 2>/dev/null || echo 0)" "$(sha256sum "$TARGET" 2>/dev/null | awk '{print $1}')" "$(file -b "$TARGET" 2>/dev/null)"; else printf "[mobile-apk] target=%s exists=false\\n" "\${TARGET:-<missing>}"; fi`,
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ]; then strings -a "$TARGET" 2>/dev/null | grep -iE "frida|debug|root|xposed|substrate|ptrace|TracerPid|isDebuggerConnected|emulator|su\\b|magisk" | head -40 | sed "s/^/[mobile-anti-debug-check] /"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v jadx >/dev/null 2>&1; then echo "[mobile-static-command] jadx -q -d /tmp/repi-jadx $TARGET"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v apktool >/dev/null 2>&1; then echo "[mobile-static-command] apktool d -f -o /tmp/repi-apktool $TARGET"; fi',
		'if command -v adb >/dev/null 2>&1; then adb devices -l 2>&1 | sed "s/^/[mobile-device] /"; else echo "[mobile-runtime-blocked] reason=adb_missing"; fi',
		'if [ -n "$PKG" ] && command -v adb >/dev/null 2>&1; then adb shell pidof "$PKG" 2>&1 | sed "s/^/[mobile-process] pidof $PKG /"; adb shell ps -A 2>/dev/null | grep "$PKG" | head -20 | sed "s/^/[mobile-process] /"; fi',
		'if command -v frida-ps >/dev/null 2>&1; then frida-ps -Uai 2>&1 | head -80 | sed "s/^/[mobile-frida-process] /"; else echo "[mobile-runtime-blocked] reason=frida_ps_missing"; fi',
		"cat > /tmp/repi-mobile-frida-hooks.js <<'JS'",
		mobileRuntimeFridaHookScript(),
		"JS",
		'echo "[mobile-frida-hook-template] /tmp/repi-mobile-frida-hooks.js hooks=Java.crypto,String.equals,Debug.isDebuggerConnected,native.strcmp,memcmp"',
		'grep -nE "Java.perform|Cipher.doFinal|MessageDigest|Mac.doFinal|String.equals|Module.findExportByName|Interceptor.attach" /tmp/repi-mobile-frida-hooks.js | head -80 | sed "s/^/[mobile-hook-line] /"',
		`if [ -n "$PKG" ] && command -v frida >/dev/null 2>&1 && [ "\${REPI_MOBILE_ATTACH:-0}" = "1" ]; then timeout ${attachTimeout}s frida -U -f "$PKG" -l /tmp/repi-mobile-frida-hooks.js --no-pause 2>&1 | sed "s/^/[mobile-attach] /"; else echo "[mobile-runtime-blocked] reason=attach_skipped pkg=\${PKG:-<missing>} set_REPI_MOBILE_ATTACH=1_to_attach"; fi`,
	].join("\n");
}

function mobileRuntimeAnchors(stdout: string, stderr: string): string[] {
	const text = `${stdout}\n${stderr}`;
	return [
		...interestingLines(text, /\[mobile-env\]/i, 8).map(
			(line) => `mobile tool readiness anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-apk\]/i, 8).map(
			(line) => `mobile APK inventory anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-device\]/i, 12).map(
			(line) => `mobile device anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-process\]|\[mobile-frida-process\]/i, 20).map(
			(line) => `mobile process map anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-frida-hook-template\]|\[mobile-hook-line\]/i, 20).map(
			(line) => `mobile Frida hook template anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-crypto-hook\]|\[mobile-compare-hook\]/i, 20).map(
			(line) => `mobile Java crypto/compare hook anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-native-hook\]/i, 20).map(
			(line) => `mobile native compare hook anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-anti-debug/i, 20).map(
			(line) => `mobile anti-debug/root check anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-attach\]/i, 20).map(
			(line) => `mobile runtime attach anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[mobile-runtime-blocked\]/i, 12).map(
			(line) => `mobile runtime blocked anchors: ${truncateMiddle(line, 260)}`,
		),
	].slice(0, 100);
}

function buildMobileRuntimeArtifact(options: {
	target?: string;
	packageName?: string;
	mode?: "plan" | "run";
	timeoutMs?: number;
	executions?: MobileRuntimeExecution[];
	runtimeAnchors?: string[];
}): MobileRuntimeArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const target = options.target?.trim() || undefined;
	const packageName = inferMobilePackageName(target, options.packageName);
	const dynamicOnly = Boolean(packageName && !target);
	const timeoutMs = Math.max(3000, Math.min(180000, Math.floor(options.timeoutMs ?? 15000)));
	const captureScript = mobileRuntimeShellCommand(target, packageName, timeoutMs);
	const deviceMatrix = [
		dynamicOnly
			? "analysis_mode=dynamic-only: packageName supplied without APK; static APK inventory is skipped and ADB/Frida process/hook plan remains active"
			: "analysis_mode=static+dynamic when APK/path is supplied; dynamic-only when only packageName is supplied",
		"adb devices -l baseline and USB/emulator transport state",
		"frida-ps -Uai app/process visibility and package identifier confirmation",
		"pidof/ps for package runtime PID, architecture and user context when device is attached",
	];
	const apkInventory = [
		dynamicOnly
			? `target=<dynamic-only>: package=${packageName}; static APK analysis skipped, use adb/frida package runtime map`
			: target
			? `target=${target}: file/bytes/sha256/APK or native library metadata`
			: "target=<missing>: pass APK, package, or native library",
		"static strings for frida/debug/root/xposed/substrate/ptrace/TracerPid/isDebuggerConnected/emulator/Magisk",
		"optional jadx/apktool command scaffolds for manifest, smali, JNI and crypto call sites",
	];
	const processMap = [
		packageName
			? `package=${packageName}: pidof, ps, frida process map`
			: "package=<missing>: infer package from target or pass packageName",
		"capture package/process/PID before attaching hooks; record attach skipped/blocked reasons",
	];
	const hookPlan = [
		"Java.perform hook: android.os.Debug.isDebuggerConnected, java.lang.String.equals, Cipher.doFinal, MessageDigest.digest, Mac.doFinal",
		"native Interceptor.attach: strcmp, strncmp, memcmp, strstr via Module.findExportByName",
		"attach only when REPI_MOBILE_ATTACH=1 to keep default run observability-first and bounded",
	];
	const fridaHooks = [
		"/tmp/repi-mobile-frida-hooks.js contains Java crypto/compare and native compare hook template",
		packageName
			? `REPI_MOBILE_ATTACH=1 re_mobile_runtime run ${target ?? packageName} ${packageName} ${timeoutMs}`
			: "REPI_MOBILE_ATTACH=1 re_mobile_runtime run <apk-or-package> <packageName> <timeout-ms>",
	];
	const nativeTrace = [
		"native strcmp/strncmp/memcmp/strstr arguments and return values are logged when Frida attaches",
		"fallback native trace: gdb/lldb breakpoints on compare functions for extracted .so or running process",
	];
	const antiDebugChecks = [
		"string sweep for Frida/root/debug/emulator/xposed/substrate/Magisk/ptrace indicators",
		"runtime hook for Debug.isDebuggerConnected records return value without patching by default",
	];
	const replayCommands = [
		`re_mobile_runtime run ${target ?? packageName ?? "<apk-or-package>"}${packageName ? ` ${packageName}` : ""} ${timeoutMs}`,
		"adb devices -l && frida-ps -Uai",
		"cat /tmp/repi-mobile-frida-hooks.js",
		packageName
			? `REPI_MOBILE_ATTACH=1 timeout ${Math.ceil(timeoutMs / 1000)}s frida -U -f ${shellQuote(packageName)} -l /tmp/repi-mobile-frida-hooks.js --no-pause`
			: "REPI_MOBILE_ATTACH=1 frida -U -f <packageName> -l /tmp/repi-mobile-frida-hooks.js --no-pause",
	];
	const nextActions = Array.from(
		new Set([
			`re_mobile_runtime run ${target ?? packageName ?? "<apk-or-package>"}${packageName ? ` ${packageName}` : ""} ${timeoutMs}`,
			"re_lane plan runtime-proof <apk-or-package>",
			"re_verifier matrix",
			"re_compiler draft",
			"re_knowledge_graph build",
		]),
	).slice(0, 12);
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target,
		packageName,
		mode: options.mode ?? "plan",
		timeoutMs,
		captureScript,
		deviceMatrix,
		apkInventory,
		processMap,
		hookPlan,
		fridaHooks,
		nativeTrace,
		antiDebugChecks,
		replayCommands,
		executions: options.executions ?? [],
		runtimeAnchors: options.runtimeAnchors ?? [],
		nextActions,
		sourceArtifacts: [
			recentMarkdownArtifacts(evidenceMapsDir(), 1)[0],
			recentMarkdownArtifacts(evidenceRunsDir(), 1)[0],
			latestLiveBrowserArtifactPath(),
			latestVerifierArtifactPath(),
			latestCompilerArtifactPath(),
		].filter((path): path is string => Boolean(path)),
	};
}

function formatMobileRuntime(mobile: MobileRuntimeArtifact, path?: string): string {
	return [
		"mobile_runtime:",
		path ? `mobile_runtime_artifact: ${path}` : undefined,
		`timestamp: ${mobile.timestamp}`,
		`mode: ${mobile.mode}`,
		`mission_id: ${mobile.missionId ?? "none"}`,
		`route: ${mobile.route ?? "none"}`,
		`target: ${mobile.target ?? "<missing>"}`,
		`package_name: ${mobile.packageName ?? "<missing>"}`,
		`timeout_ms: ${mobile.timeoutMs}`,
		"device_matrix:",
		...(mobile.deviceMatrix.length ? mobile.deviceMatrix.map((item) => `- ${item}`) : ["- none"]),
		"apk_inventory:",
		...(mobile.apkInventory.length ? mobile.apkInventory.map((item) => `- ${item}`) : ["- none"]),
		"process_map:",
		...(mobile.processMap.length ? mobile.processMap.map((item) => `- ${item}`) : ["- none"]),
		"hook_plan:",
		...(mobile.hookPlan.length ? mobile.hookPlan.map((item) => `- ${item}`) : ["- none"]),
		"frida_hooks:",
		...(mobile.fridaHooks.length ? mobile.fridaHooks.map((item) => `- ${item}`) : ["- none"]),
		"native_trace:",
		...(mobile.nativeTrace.length ? mobile.nativeTrace.map((item) => `- ${item}`) : ["- none"]),
		"anti_debug_checks:",
		...(mobile.antiDebugChecks.length ? mobile.antiDebugChecks.map((item) => `- ${item}`) : ["- none"]),
		"executions:",
		...(mobile.executions.length
			? mobile.executions.map(
					(item) =>
						`- ${item.label} [${item.status}] exit=${item.exit ?? "n/a"} stdout_sha256=${item.stdoutHash ?? "n/a"} stderr_sha256=${item.stderrHash ?? "n/a"}`,
				)
			: ["- planned mobile runtime capture; run re_mobile_runtime run <apk-or-package> [packageName] [timeout-ms]"]),
		"runtime_anchors:",
		...(mobile.runtimeAnchors.length ? mobile.runtimeAnchors.map((item) => `- ${item}`) : ["- none"]),
		"replay_commands:",
		...(mobile.replayCommands.length ? mobile.replayCommands.map((item) => `- ${item}`) : ["- none"]),
		"capture_script:",
		"```bash",
		mobile.captureScript,
		"```",
		"mobile_next_actions:",
		...(mobile.nextActions.length ? mobile.nextActions.map((item) => `- ${item}`) : ["- re_verifier matrix"]),
		`next_mobile_command: ${mobile.mode === "run" ? "re_verifier matrix" : `re_mobile_runtime run ${mobile.target ?? mobile.packageName ?? "<apk-or-package>"}`}`,
		"source_artifacts:",
		...(mobile.sourceArtifacts.length ? mobile.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeMobileRuntimeArtifact(mobile: MobileRuntimeArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceMobileRuntimeDir(),
		`${mobile.timestamp.replace(/[:.]/g, "-")}-${slug(mobile.packageName ?? mobile.target ?? "mobile-runtime")}-${mobile.mode}.md`,
	);
	writePrivateTextFile(
		path,
		[
			"# REPI Mobile Runtime Artifact",
			"",
			formatMobileRuntime(mobile, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(mobile, null, 2),
			"```",
			"",
		].join("\n"),
	);
	appendEvidence({
		kind: mobile.mode === "run" ? "runtime" : "artifact",
		title: `mobile-runtime-${mobile.mode} ${mobile.packageName ?? mobile.target ?? "no-target"}`,
		fact: `Mobile runtime ${mobile.mode}: target=${mobile.target ?? "<missing>"}, package=${mobile.packageName ?? "<missing>"}, executions=${mobile.executions.length}, anchors=${mobile.runtimeAnchors.length}`,
		command: `re_mobile_runtime ${mobile.mode}${mobile.target ? ` ${mobile.target}` : ""}${mobile.packageName ? ` ${mobile.packageName}` : ""}`,
		path,
		verify: `cat ${path}`,
		confidence: "mobile APK/ADB/Frida/GDB runtime capture",
	});
	const blocked =
		mobile.mode === "run" &&
		mobile.executions.length > 0 &&
		mobile.executions.every((item) => item.status === "blocked");
	updateMissionCheckpoint("mobile_runtime_ready", blocked ? "blocked" : "done", path);
	return path;
}

async function runMobileRuntime(
	pi: ExtensionAPI,
	options: { target?: string; packageName?: string; timeoutMs?: number } = {},
): Promise<string> {
	const packageName = inferMobilePackageName(options.target, options.packageName);
	const timeoutMs = Math.max(3000, Math.min(180000, Math.floor(options.timeoutMs ?? 15000)));
	const command = mobileRuntimeShellCommand(options.target, packageName, timeoutMs);
	const result = await pi.exec("bash", ["-lc", command], { timeout: timeoutMs + 10000 });
	const anchors = mobileRuntimeAnchors(result.stdout, result.stderr);
	const mobile = buildMobileRuntimeArtifact({
		...options,
		packageName,
		mode: "run",
		timeoutMs,
		executions: [
			{
				label: "mobile-runtime-capture",
				command,
				status: result.code === 0 ? "passed" : "failed",
				exit: result.code,
				killed: result.killed,
				stdoutHash: replayHash(result.stdout),
				stderrHash: replayHash(result.stderr),
				stdoutHead: truncateMiddle(result.stdout.trim(), 3000),
				stderrHead: truncateMiddle(result.stderr.trim(), 2000),
			},
		],
		runtimeAnchors: anchors,
	});
	const path = writeMobileRuntimeArtifact(mobile);
	return [
		formatMobileRuntime(mobile, path),
		result.stdout.trim() ? ["stdout:", "```", truncateMiddle(result.stdout.trim(), 6000), "```"].join("\n") : "",
		result.stderr.trim() ? ["stderr:", "```", truncateMiddle(result.stderr.trim(), 2000), "```"].join("\n") : "",
	]
		.filter(Boolean)
		.join("\n");
}

function buildMobileRuntimeOutput(
	action: "plan" | "show" = "plan",
	options: { target?: string; packageName?: string; timeoutMs?: number } = {},
): string {
	if (action === "show") {
		const path = latestMobileRuntimeArtifactPath();
		if (!path) return "mobile_runtime:\nstatus: missing\nnext: re_mobile_runtime plan <apk-or-package>";
		return truncateMiddle(readText(path), 22000);
	}
	const mobile = buildMobileRuntimeArtifact({ ...options, mode: "plan" });
	const path = writeMobileRuntimeArtifact(mobile);
	return formatMobileRuntime(mobile, path);
}

function latestNativeRuntimeArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("native_runtime", evidenceNativeRuntimeDir(), options);
}

function inferNativeRuntimeTarget(target?: string): string | undefined {
	const trimmed = target?.trim();
	if (trimmed) return trimmed;
	for (const path of [
		recentMarkdownArtifacts(evidenceMapsDir(), 1)[0],
		recentMarkdownArtifacts(evidenceRunsDir(), 1)[0],
		latestNativeRuntimeArtifactPath(),
	]) {
		if (!path) continue;
		const text = readText(path);
		const explicit = /^target:\s*(.+)$/m.exec(text)?.[1]?.trim();
		if (explicit && !/^<.*>$|none$/i.test(explicit)) return explicit;
		const candidate = /binary[_ -]?candidate[^\n]*?([./\w-]+(?:\.elf|\.bin|\.so|vuln|challenge|license)?)/i
			.exec(text)?.[1]
			?.trim();
		if (candidate && !/^<.*>$|none$/i.test(candidate)) return candidate;
	}
	return undefined;
}

function nativeRuntimeGdbScript(): string {
	return `set pagination off
set confirm off
set breakpoint pending on
set disassembly-flavor intel
set follow-fork-mode child
set print pretty on
printf "[native-gdb-script] loaded\\n"
info files
info functions main
info functions strcmp
info functions strncmp
info functions memcmp
info functions strstr
info functions system
break main
rbreak strcmp
rbreak strncmp
rbreak memcmp
rbreak strstr
run
printf "[native-gdb-after-run] stopped\\n"
info registers
bt
x/16gx $sp
quit`;
}

function nativeRuntimePwntoolsScaffold(): string {
	return `#!/usr/bin/env python3
from pwn import *
import sys
path = sys.argv[1] if len(sys.argv) > 1 else './vuln'
context.binary = path
elf = ELF(path, checksec=False)
print(f"[native-pwn-scaffold] arch={elf.arch} entry={hex(elf.entry)} bits={elf.bits}")
print(f"[native-pwn-scaffold] cyclic_pattern={cyclic(128).hex()[:96]}")
print("[native-pwn-scaffold] TODO: set offset from native crash/register anchors, then build leak -> libc -> ROP verifier")`;
}

function nativeRuntimeShellCommand(target?: string, timeoutMs = 12000): string {
	const targetArg = shellQuote(target?.trim() ?? "");
	const runTimeout = Math.max(3, Math.ceil(timeoutMs / 1000));
	return [
		"set +e",
		`TARGET=${targetArg}`,
		'printf "[native-env] file=%s readelf=%s objdump=%s gdb=%s checksec=%s ldd=%s strings=%s ROPgadget=%s ropper=%s patchelf=%s\\n" "$(command -v file || true)" "$(command -v readelf || true)" "$(command -v objdump || true)" "$(command -v gdb || true)" "$(command -v checksec || true)" "$(command -v ldd || true)" "$(command -v strings || true)" "$(command -v ROPgadget || true)" "$(command -v ropper || true)" "$(command -v patchelf || true)"',
		`if [ -n "$TARGET" ] && [ -e "$TARGET" ]; then printf "[native-binary] target=%s bytes=%s sha256=%s mode=%s file=%s\\n" "$TARGET" "$(wc -c < "$TARGET" 2>/dev/null || echo 0)" "$(sha256sum "$TARGET" 2>/dev/null | awk '{print $1}')" "$(stat -c "%a" "$TARGET" 2>/dev/null || echo NA)" "$(file -b "$TARGET" 2>/dev/null)"; else printf "[native-binary] target=%s exists=false\\n" "$TARGET"; echo "[native-runtime-blocked] reason=missing_target"; fi`,
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v checksec >/dev/null 2>&1; then checksec --file="$TARGET" 2>&1 | sed "s/^/[native-checksec] /"; else echo "[native-runtime-blocked] reason=checksec_missing_or_target_missing"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v readelf >/dev/null 2>&1; then readelf -hW "$TARGET" 2>&1 | head -60 | sed "s/^/[native-readelf-header] /"; readelf -lW "$TARGET" 2>/dev/null | grep -E "GNU_STACK|GNU_RELRO|INTERP|LOAD" | sed "s/^/[native-readelf-program] /"; readelf -dW "$TARGET" 2>/dev/null | grep -E "NEEDED|RPATH|RUNPATH|BIND_NOW" | sed "s/^/[native-readelf-dynamic] /"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v objdump >/dev/null 2>&1; then objdump -T "$TARGET" 2>/dev/null | grep -Ei "strcmp|strncmp|memcmp|strstr|gets|system|execve|printf|scanf|malloc|free|read|write" | head -80 | sed "s/^/[native-symbol] /"; objdump -d "$TARGET" 2>/dev/null | grep -En "call.*(strcmp|memcmp|strstr|system|gets)|<main>|<win>|<vuln>" | head -80 | sed "s/^/[native-disasm] /"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v strings >/dev/null 2>&1; then strings -a "$TARGET" 2>/dev/null | grep -iE "flag|license|serial|password|key|/bin/sh|admin|debug|strcmp|memcmp|system" | head -80 | sed "s/^/[native-string] /"; fi',
		'if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v ldd >/dev/null 2>&1; then ldd "$TARGET" 2>&1 | sed "s/^/[native-ldd] /"; fi',
		"cat > /tmp/repi-native-gdb.gdb <<'GDB'",
		nativeRuntimeGdbScript(),
		"GDB",
		'echo "[native-gdb-script] /tmp/repi-native-gdb.gdb breakpoints=main,strcmp,strncmp,memcmp,strstr run_env=REPI_NATIVE_RUN"',
		`if [ -n "$TARGET" ] && [ -e "$TARGET" ] && command -v gdb >/dev/null 2>&1 && [ "$REPI_NATIVE_RUN" = "1" ]; then timeout ${runTimeout}s gdb -q -batch -x /tmp/repi-native-gdb.gdb --args "$TARGET" $REPI_NATIVE_ARGS 2>&1 | sed "s/^/[native-gdb] /"; else echo "[native-runtime-blocked] reason=gdb_run_skipped set_REPI_NATIVE_RUN=1 target=$TARGET"; fi`,
		"cat > /tmp/repi-native-pwn-scaffold.py <<'PY'",
		nativeRuntimePwntoolsScaffold(),
		"PY",
		'echo "[native-pwn-scaffold] /tmp/repi-native-pwn-scaffold.py target=$TARGET cyclic=128 rop=leak-libc-verifier"',
	].join("\n");
}

function nativeRuntimeAnchors(stdout: string, stderr: string): string[] {
	const text = `${stdout}\n${stderr}`;
	return [
		...interestingLines(text, /\[native-env\]/i, 8).map(
			(line) => `native tool readiness anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-binary\]|\[native-file\]/i, 8).map(
			(line) => `native binary inventory anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-checksec\]|\[native-readelf/i, 24).map(
			(line) => `native mitigation/header anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-ldd\]/i, 16).map(
			(line) => `native loader/libc anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-symbol\]|\[native-disasm\]|\[native-string\]/i, 30).map(
			(line) => `native symbol/string anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-gdb-script\]|\[native-gdb\]/i, 40).map(
			(line) => `native GDB trace anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /SIGSEGV|Program received signal|RIP|RSP|EIP|ESP|info registers|bt|backtrace/i, 30).map(
			(line) => `native crash/register anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-pwn-scaffold\]/i, 12).map(
			(line) => `native exploit scaffold anchors: ${truncateMiddle(line, 260)}`,
		),
		...interestingLines(text, /\[native-runtime-blocked\]/i, 12).map(
			(line) => `native runtime blocked anchors: ${truncateMiddle(line, 260)}`,
		),
	].slice(0, 120);
}

function buildNativeRuntimeArtifact(options: {
	target?: string;
	mode?: "plan" | "run";
	timeoutMs?: number;
	executions?: NativeRuntimeExecution[];
	runtimeAnchors?: string[];
}): NativeRuntimeArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const target = inferNativeRuntimeTarget(options.target);
	const timeoutMs = Math.max(3000, Math.min(180000, Math.floor(options.timeoutMs ?? 12000)));
	const captureScript = nativeRuntimeShellCommand(target, timeoutMs);
	const binaryInventory = [
		target
			? `target=${target}: file/bytes/sha256/mode/ELF interpreter inventory`
			: "target=<missing>: pass ELF/SO/native executable path",
		"collect file, stat, sha256, strings, imported symbols, exported symbols, disassembly hotspots and candidate compare/crypto sinks",
	];
	const mitigationMatrix = [
		"checksec/readelf: NX, PIE, RELRO, canary, GNU_STACK, BIND_NOW and interpreter",
		"map mitigations to primitive path: overflow -> crash offset, format string -> leak, heap -> allocator/tcache anchors",
	];
	const loaderLibc = [
		"ldd/readelf NEEDED captures loader/libc path and dynamic dependencies",
		"record libc/ld-linux hash when local exploit depends on offsets; pin with patchelf or container if needed",
	];
	const symbolMap = [
		"objdump symbols/disassembly for strcmp/strncmp/memcmp/strstr/system/gets/read/write/malloc/free call sites",
		"strings for flag/license/key/password/debug/binsh markers and protocol prompts",
	];
	const crashPlan = [
		"generate cyclic pattern and capture crash register/stack under GDB only when REPI_NATIVE_RUN=1",
		"convert RIP/EIP/SP controlled bytes to offset, then rerun with focused breakpoint and verifier payload",
	];
	const breakpointPlan = [
		"GDB batch script breaks main and regex-breaks strcmp/strncmp/memcmp/strstr; records registers/backtrace/stack",
		"for SO/mobile-native use Frida or gdbserver attach; for foreign arch run under qemu-user with matching loader/rootfs",
	];
	const gdbTrace = [
		"/tmp/repi-native-gdb.gdb contains bounded GDB trace script",
		"default run skips target execution; set REPI_NATIVE_RUN=1 and optional REPI_NATIVE_ARGS for live trace",
	];
	const exploitScaffold = [
		"/tmp/repi-native-pwn-scaffold.py emits pwntools ELF context and cyclic pattern",
		"next scaffold stage: leak source -> libc/one_gadget/ROP chain -> local verifier -> exploit lab replay",
	];
	const replayCommands = [
		`re_native_runtime run ${target ?? "<elf-or-so>"} ${timeoutMs}`,
		"cat /tmp/repi-native-gdb.gdb",
		"cat /tmp/repi-native-pwn-scaffold.py",
		target
			? `REPI_NATIVE_RUN=1 timeout ${Math.ceil(timeoutMs / 1000)}s gdb -q -batch -x /tmp/repi-native-gdb.gdb --args ${shellQuote(target)}`
			: "REPI_NATIVE_RUN=1 gdb -q -batch -x /tmp/repi-native-gdb.gdb --args <target>",
	];
	const nextActions = Array.from(
		new Set(
			[
				target && (options.mode ?? "plan") !== "run" ? `re_native_runtime run ${target} ${timeoutMs}` : undefined,
				"re_lane plan primitive <target>",
				"re_verifier matrix",
				"re_compiler draft",
				"re_exploit_lab plan <poc>",
				"re_knowledge_graph build",
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 12);
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target,
		mode: options.mode ?? "plan",
		timeoutMs,
		captureScript,
		binaryInventory,
		mitigationMatrix,
		loaderLibc,
		symbolMap,
		crashPlan,
		gdbTrace,
		breakpointPlan,
		exploitScaffold,
		replayCommands,
		executions: options.executions ?? [],
		runtimeAnchors: options.runtimeAnchors ?? [],
		nextActions,
		sourceArtifacts: [
			recentMarkdownArtifacts(evidenceMapsDir(), 1)[0],
			recentMarkdownArtifacts(evidenceRunsDir(), 1)[0],
			latestVerifierArtifactPath(),
			latestCompilerArtifactPath(),
			latestReplayerArtifactPath(),
			latestExploitLabArtifactPath(),
		].filter((path): path is string => Boolean(path)),
	};
}

function formatNativeRuntime(native: NativeRuntimeArtifact, path?: string): string {
	return [
		"native_runtime:",
		path ? `native_runtime_artifact: ${path}` : undefined,
		`timestamp: ${native.timestamp}`,
		`mode: ${native.mode}`,
		`mission_id: ${native.missionId ?? "none"}`,
		`route: ${native.route ?? "none"}`,
		`target: ${native.target ?? "<missing>"}`,
		`timeout_ms: ${native.timeoutMs}`,
		"binary_inventory:",
		...(native.binaryInventory.length ? native.binaryInventory.map((item) => `- ${item}`) : ["- none"]),
		"mitigation_matrix:",
		...(native.mitigationMatrix.length ? native.mitigationMatrix.map((item) => `- ${item}`) : ["- none"]),
		"loader_libc:",
		...(native.loaderLibc.length ? native.loaderLibc.map((item) => `- ${item}`) : ["- none"]),
		"symbol_map:",
		...(native.symbolMap.length ? native.symbolMap.map((item) => `- ${item}`) : ["- none"]),
		"crash_plan:",
		...(native.crashPlan.length ? native.crashPlan.map((item) => `- ${item}`) : ["- none"]),
		"gdb_trace:",
		...(native.gdbTrace.length ? native.gdbTrace.map((item) => `- ${item}`) : ["- none"]),
		"breakpoint_plan:",
		...(native.breakpointPlan.length ? native.breakpointPlan.map((item) => `- ${item}`) : ["- none"]),
		"exploit_scaffold:",
		...(native.exploitScaffold.length ? native.exploitScaffold.map((item) => `- ${item}`) : ["- none"]),
		"executions:",
		...(native.executions.length
			? native.executions.map(
					(item) =>
						`- ${item.label} [${item.status}] exit=${item.exit ?? "n/a"} stdout_sha256=${item.stdoutHash ?? "n/a"} stderr_sha256=${item.stderrHash ?? "n/a"}`,
				)
			: ["- planned native runtime capture; run re_native_runtime run <elf-or-so> [timeout-ms]"]),
		"runtime_anchors:",
		...(native.runtimeAnchors.length ? native.runtimeAnchors.map((item) => `- ${item}`) : ["- none"]),
		"replay_commands:",
		...(native.replayCommands.length ? native.replayCommands.map((item) => `- ${item}`) : ["- none"]),
		"capture_script:",
		"```bash",
		native.captureScript,
		"```",
		"native_next_actions:",
		...(native.nextActions.length ? native.nextActions.map((item) => `- ${item}`) : ["- re_verifier matrix"]),
		`next_native_command: ${native.mode === "run" ? "re_verifier matrix" : `re_native_runtime run ${native.target ?? "<elf-or-so>"}`}`,
		"source_artifacts:",
		...(native.sourceArtifacts.length ? native.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeNativeRuntimeArtifact(native: NativeRuntimeArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceNativeRuntimeDir(),
		`${native.timestamp.replace(/[:.]/g, "-")}-${slug(native.target ?? "native-runtime")}-${native.mode}.md`,
	);
	writePrivateTextFile(
		path,
		[
			"# REPI Native Runtime Artifact",
			"",
			formatNativeRuntime(native, path),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(native, null, 2),
			"```",
			"",
		].join("\n"),
	);
	appendEvidence({
		kind: native.mode === "run" ? "runtime" : "artifact",
		title: `native-runtime-${native.mode} ${native.target ?? "no-target"}`,
		fact: `Native runtime ${native.mode}: target=${native.target ?? "<missing>"}, executions=${native.executions.length}, anchors=${native.runtimeAnchors.length}`,
		command: `re_native_runtime ${native.mode}${native.target ? ` ${native.target}` : ""}`,
		path,
		verify: `cat ${path}`,
		confidence: "native ELF/GDB/pwn runtime capture",
	});
	const blocked =
		native.mode === "run" &&
		native.executions.length > 0 &&
		native.executions.every((item) => item.status === "blocked");
	updateMissionCheckpoint("native_runtime_ready", blocked ? "blocked" : "done", path);
	return path;
}

async function runNativeRuntime(
	pi: ExtensionAPI,
	options: { target?: string; timeoutMs?: number } = {},
): Promise<string> {
	const target = inferNativeRuntimeTarget(options.target);
	const timeoutMs = Math.max(3000, Math.min(180000, Math.floor(options.timeoutMs ?? 12000)));
	const command = nativeRuntimeShellCommand(target, timeoutMs);
	const result = await pi.exec("bash", ["-lc", command], { timeout: timeoutMs + 10000 });
	const anchors = nativeRuntimeAnchors(result.stdout, result.stderr);
	const native = buildNativeRuntimeArtifact({
		...options,
		target,
		mode: "run",
		timeoutMs,
		executions: [
			{
				label: "native-runtime-capture",
				command,
				status: /\[native-runtime-blocked\] reason=missing_target/i.test(`${result.stdout}\n${result.stderr}`)
					? "blocked"
					: result.code === 0
						? "passed"
						: "failed",
				exit: result.code,
				killed: result.killed,
				stdoutHash: replayHash(result.stdout),
				stderrHash: replayHash(result.stderr),
				stdoutHead: truncateMiddle(result.stdout.trim(), 3000),
				stderrHead: truncateMiddle(result.stderr.trim(), 2000),
			},
		],
		runtimeAnchors: anchors,
	});
	const path = writeNativeRuntimeArtifact(native);
	return [
		formatNativeRuntime(native, path),
		result.stdout.trim() ? ["stdout:", "```", truncateMiddle(result.stdout.trim(), 6000), "```"].join("\n") : "",
		result.stderr.trim() ? ["stderr:", "```", truncateMiddle(result.stderr.trim(), 2000), "```"].join("\n") : "",
	]
		.filter(Boolean)
		.join("\n");
}

function buildNativeRuntimeOutput(
	action: "plan" | "show" = "plan",
	options: { target?: string; timeoutMs?: number } = {},
): string {
	if (action === "show") {
		const path = latestNativeRuntimeArtifactPath();
		if (!path) return "native_runtime:\nstatus: missing\nnext: re_native_runtime plan <elf-or-so>";
		return truncateMiddle(readText(path), 22000);
	}
	const native = buildNativeRuntimeArtifact({ ...options, mode: "plan" });
	const path = writeNativeRuntimeArtifact(native);
	return formatNativeRuntime(native, path);
}

function parseLaneRunDecision(text: string, laneName: string): RunAutoDecision {
	const quality = numericMetadataValue(text, "score");
	const verdict = metadataValue(text, "verdict");
	const strategy = metadataValue(text, "mode");
	const skipped = numericMetadataValue(text, "skipped_count") ?? 0;
	const fallback = numericMetadataValue(text, "fallback_count") ?? 0;
	const hasSelfHeal = /self_heal_commands:/.test(text) || /\[auto:heal-/i.test(text);
	const nextLaneHint = metadataValue(text, "next_lane_hint");
	const advanced = /auto_lane_update: .* -> /.test(text);
	const noRunnable = /没有可直接运行的命令/.test(text);
	const toolBlocked = strategy === "blocked" || noRunnable;
	if (toolBlocked) {
		return {
			action: "stop",
			reason: `tool_strategy_${strategy ?? "blocked"}:${laneName}`,
			quality,
			verdict,
		};
	}
	if ((verdict === "weak" || (quality !== undefined && quality < 45)) && hasSelfHeal) {
		return {
			action: "continue_current",
			reason: `weak_evidence_self_heal:${laneName}`,
			nextLane: laneName,
			quality,
			verdict,
		};
	}
	if (skipped > 0 && fallback === 0) {
		return {
			action: "stop",
			reason: `skipped_without_fallback:${laneName}`,
			quality,
			verdict,
		};
	}
	if (advanced || nextLaneHint) {
		return {
			action: "continue_next",
			reason: `advance:${nextLaneHint ?? "active"}`,
			quality,
			verdict,
		};
	}
	if (verdict === "strong" || (quality !== undefined && quality >= 70)) {
		return { action: "continue_next", reason: `strong_evidence:${laneName}`, quality, verdict };
	}
	if (strategy === "tool-index-missing" && !hasSelfHeal) {
		return {
			action: "stop",
			reason: `tool_strategy_tool-index-missing:${laneName}`,
			quality,
			verdict,
		};
	}
	if ((verdict === "partial" || (quality !== undefined && quality >= 45)) && hasSelfHeal) {
		return {
			action: "continue_current",
			reason: `partial_evidence_self_heal:${laneName}`,
			nextLane: laneName,
			quality,
			verdict,
		};
	}
	return { action: "stop", reason: `no_adaptive_followup:${laneName}`, quality, verdict };
}

function formatRunAutoDecision(decision: RunAutoDecision): string {
	return [
		"adaptive_decision:",
		`action: ${decision.action}`,
		`reason: ${decision.reason}`,
		decision.nextLane ? `next_lane: ${decision.nextLane}` : undefined,
		decision.quality !== undefined ? `quality: ${decision.quality}` : undefined,
		decision.verdict ? `verdict: ${decision.verdict}` : undefined,
	]
		.filter(Boolean)
		.join("\n");
}

function splitMetadataList(value?: string): string[] {
	if (!value || value === "none") return [];
	return value
		.split(/[, ]+/)
		.map((item) => item.trim())
		.filter((item) => item && item !== "none");
}

function adaptiveRepairLaneSpec(params: {
	lane: MissionLane;
	decision: RunAutoDecision;
	text: string;
	target?: string;
}): { name: string; objective: string; next: string[]; blockCurrent: boolean } {
	const missingTools = splitMetadataList(metadataValue(params.text, "missing_tools"));
	const target = params.target ? shellQuote(params.target) : undefined;
	if (/tool_strategy|skipped_without_fallback/.test(params.decision.reason)) {
		const tools = missingTools.length ? missingTools.slice(0, 12) : ["checksec", "gdb", "r2", "rabin2"];
		return {
			name: "tool-bootstrap",
			objective: "补齐缺失工具或确认可用替代路径，再回到被阻塞 lane",
			blockCurrent: true,
			next: [
				`re_bootstrap plan ${tools.join(" ")}`,
				`[auto:tool-presence-audit] for t in ${tools.map((tool) => shellQuote(tool)).join(" ")}; do printf '%s=' "$t"; command -v "$t" || true; done # evidence: missing tool availability audit`,
				`[auto:tool-index-tail] sed -n '1,220p' ${shellQuote(toolIndexPath())} 2>/dev/null || true # evidence: current tool-index evidence`,
			],
		};
	}
	if (/no_adaptive_followup|weak_evidence|partial_evidence/.test(params.decision.reason)) {
		return {
			name: "evidence-repair",
			objective: "当前 lane 证据质量不足；扩大最小证据面并生成可运行 follow-up",
			blockCurrent: false,
			next: [
				target
					? `[auto:repair-target-baseline] file ${target}; sha256sum ${target}; strings -a -n 5 ${target} | grep -iE 'license|serial|key|valid|invalid|check|verify|flag|pass|fail|strcmp|memcmp|auth|token|sign' | head -220 # evidence: target baseline and high-signal strings`
					: "[auto:repair-target-discovery] pwd; find . -maxdepth 4 -type f | sort | head -260 # evidence: target candidate discovery",
				'[auto:repair-signal-sweep] rg -n "license|serial|key|valid|invalid|check|verify|flag|strcmp|memcmp|auth|session|jwt|sign|crypto|token|secret|admin|debug" . 2>/dev/null | head -260 # evidence: widened high-signal search',
				"[auto:repair-entry-map] find . -maxdepth 4 -type f \\( -name 'package.json' -o -name 'Dockerfile*' -o -name 'docker-compose*.yml' -o -name '*.service' -o -name '*route*' -o -name '*controller*' \\) | sort | head -180 # evidence: entry/config/route candidates",
			],
		};
	}
	return {
		name: "map-refresh",
		objective: "当前自动链没有稳定推进；刷新被动地图并重新选择证据面",
		blockCurrent: false,
		next: [
			"[auto:map-refresh-inventory] pwd; find . -maxdepth 5 -type f | sort | head -300 # evidence: refreshed workspace inventory",
			'[auto:map-refresh-routes] rg -n "route|router|auth|session|jwt|license|serial|flag|verify|sign|crypto|token|secret|admin|debug" . 2>/dev/null | head -260 # evidence: refreshed route/logic anchors',
		],
	};
}

function applyAdaptiveMultiLanePlan(params: {
	lane: MissionLane;
	decision: RunAutoDecision;
	text: string;
	target?: string;
}): MultiLanePlan {
	const mission = readCurrentMission();
	if (!mission) return { action: "none", reason: "no_active_mission", next: [] };
	const spec = adaptiveRepairLaneSpec({
		lane: params.lane,
		decision: params.decision,
		text: params.text,
		target: params.target,
	});
	const timestamp = new Date().toISOString();
	const currentIndex = findLaneIndex(mission, params.lane.name);
	const existingIndex = mission.lanes.findIndex((lane) => lane.name === spec.name);
	const existing = existingIndex >= 0 ? mission.lanes[existingIndex] : undefined;
	const mergedNext = [...(existing?.next ?? [])];
	for (const item of spec.next) {
		if (!mergedNext.includes(item)) mergedNext.push(item);
	}
	const plannerLane: MissionLane = {
		name: spec.name,
		objective: spec.objective,
		next: mergedNext,
		status: "in_progress",
		note: `adaptive_from=${params.lane.name}; reason=${params.decision.reason}`,
		updatedAt: timestamp,
	};
	const withoutExisting = mission.lanes.filter((_, index) => index !== existingIndex);
	const insertAfter = Math.max(
		0,
		currentIndex >= 0 ? currentIndex + (existingIndex >= 0 && existingIndex < currentIndex ? 0 : 1) : 0,
	);
	const nextLanes = [...withoutExisting];
	nextLanes.splice(Math.min(insertAfter, nextLanes.length), 0, plannerLane);
	const lanes = nextLanes.map((lane) => {
		if (lane.name === plannerLane.name) return lane;
		if (lane.name === params.lane.name) {
			return {
				...lane,
				status: spec.blockCurrent ? ("blocked" as const) : ("pending" as const),
				note: truncateMiddle(`adaptive_handoff=${plannerLane.name}; reason=${params.decision.reason}`, 500),
				updatedAt: timestamp,
			};
		}
		if (lane.status === "in_progress") return { ...lane, status: "pending" as const, updatedAt: timestamp };
		return lane;
	});
	writeCurrentMission({ ...mission, lanes });
	return {
		action: existing ? "reprioritized" : "added",
		lane: plannerLane.name,
		reason: params.decision.reason,
		next: spec.next,
	};
}

function formatMultiLanePlan(plan: MultiLanePlan): string {
	return [
		"multi_lane_plan:",
		`action: ${plan.action}`,
		plan.lane ? `lane: ${plan.lane}` : undefined,
		`reason: ${plan.reason}`,
		...(plan.next.length > 0 ? ["next:", ...plan.next.map((item) => `- ${item}`)] : []),
	]
		.filter(Boolean)
		.join("\n");
}

function caseMemoryMigrationScore(item: string): number {
	const match = /\bscore=(\d+)/i.exec(item);
	return match?.[1] ? Number(match[1]) : 0;
}

function caseMemoryAutoNext(pack: LaneCommandPack): string[] {
	const migrated = pack.commands.filter(
		(command) =>
			/case-memory|knowledge-|worker-promotion|adaptive-routing|dispatcher-feedback|dispatcher-promotion-playbook|autonomous-budget-ledger/i.test(
				command.label,
			) ||
			/knowledge|similarity|promotion|adaptive routing|case memory|dispatcher feedback|dispatcher routing|score_decay|historical_score_decay|autonomous budget|demote_dispatcher|demote_lane|high-score|formal_playbook/i.test(
				command.evidence,
			) ||
			/compact[-_]resume/i.test(command.label) ||
			/compact[_ -]resume|compact_resume_case_memory|compact_resume_routing_hints/i.test(command.evidence),
	);
	const selected = (migrated.length > 0 ? migrated : pack.commands).slice(0, 6);
	const next = selected.map((command) => {
		const label = `case-memory-${slug(command.label)}`;
		const evidence = truncateMiddle(command.evidence.replace(/\s+/g, " "), 240);
		return `[auto:${label}] ${command.command} # evidence: case_memory_lane_plan migrated command; ${evidence}`;
	});
	if (next.length === 0) {
		next.push(
			`[auto:case-memory-index] sed -n '1,240p' ${shellQuote(memoryPath("knowledge-graph-index.md"))} 2>/dev/null || true # evidence: case_memory_lane_plan knowledge graph index audit`,
		);
	}
	return next;
}

function caseMemoryProofLaneIndex(mission: MissionState, currentIndex: number): number {
	const proofPattern = /control-flow|runtime|proof|prove|verify|primitive|poc|exploit|pivot-proof|privilege/i;
	const after = mission.lanes.findIndex(
		(lane, index) => index > currentIndex && lane.status !== "done" && proofPattern.test(lane.name),
	);
	if (after >= 0) return after;
	return mission.lanes.findIndex(
		(lane, index) => index !== currentIndex && lane.status !== "done" && proofPattern.test(lane.name),
	);
}

function caseMemoryLanePlan(mission: MissionState, lane: MissionLane, pack: LaneCommandPack): CaseMemoryLanePlan {
	const migrations = (pack.caseMemoryMigrations ?? []).filter((item) => item.trim().length > 0);
	if (migrations.length === 0) {
		return { action: "none", reason: "no_case_memory_migrations", migrations: [], next: [] };
	}
	if (/\bcase_memory_lane_plan=/.test(lane.note ?? "")) {
		return { action: "none", reason: `case_memory_lane_plan_already_applied:${lane.name}`, migrations, next: [] };
	}

	const migrationText = migrations.join("\n");
	const scores = migrations.map(caseMemoryMigrationScore).filter((score) => score > 0);
	const highScore = scores.length > 0 ? Math.max(...scores) : 0;
	const next = caseMemoryAutoNext(pack);
	const currentIndex = findLaneIndex(mission, lane.name);
	const proofIndex = caseMemoryProofLaneIndex(mission, currentIndex);
	const lowValueCurrent = /^(map|triage|surface|observe|identity|principals)$|map|triage|surface|observe/i.test(
		lane.name,
	);
	const repairSignal =
		/knowledge-adaptive-routing-hints|adaptive[_ -]routing|evidence-repair|negative-control|repair:|needs_repair|weak_evidence|partial_evidence|blocked|failure_budget|low[_ -]?score|score_decay|repeated[_ -]failure|autonomous[_ -]budget/i.test(
			migrationText,
		) || /demote_dispatcher|retry_dispatcher|dispatcher[_ -]feedback.*(?:failed|repair|queued)/i.test(migrationText);
	const compactResumeRepairSignal =
		/compact[_ -]resume.*(?:status=(?:queued|blocked|partial)|queued|blocked|partial|repair|proof_loop_missing|proof_loop_entered=false)/i.test(
			migrationText,
		) || /compact_resume_routing.*(?:queued|blocked|proof_loop_missing)/i.test(migrationText);
	const compactResumeSuccessSignal =
		/compact[_ -]resume.*(?:status=done|success|resume_contract_survived=true|proof_loop_entered=true)/i.test(
			migrationText,
		);
	const promotionSignal =
		/knowledge-worker-promotion-queue|worker[_ -]promotion|promote:|re_reflect|playbook|pass\b/i.test(
			migrationText,
		) ||
		/promote_dispatcher|high[_ -]score|dispatcher[_ -]promotion[_ -]playbook|dispatcher[_ -]feedback.*passed/i.test(
			migrationText,
		) ||
		highScore >= 84;

	if (compactResumeRepairSignal) {
		const existingRepair = mission.lanes.find((candidate) => candidate.name === "compact-resume-repair");
		const repairLane = existingRepair?.name ?? "compact-resume-repair";
		return {
			action: existingRepair ? "reprioritized" : "added",
			reason: `compact_resume_repair_from_case_memory:score=${highScore || "unknown"}`,
			targetLane: repairLane,
			addedLane: existingRepair ? undefined : repairLane,
			migrations,
			next,
		};
	}

	if (compactResumeSuccessSignal && lowValueCurrent && proofIndex >= 0 && proofIndex !== currentIndex) {
		const targetLane = mission.lanes[proofIndex]?.name;
		if (targetLane) {
			return {
				action: "skipped",
				reason: `compact_resume_success_skip_low_value_lane:score=${highScore || "unknown"}`,
				targetLane,
				skippedLane: lane.name,
				migrations,
				next,
			};
		}
	}

	if (repairSignal) {
		const existingRepair = mission.lanes.find((candidate) =>
			/^(case-memory-repair|evidence-repair)$/.test(candidate.name),
		);
		const repairLane = existingRepair?.name ?? "case-memory-repair";
		return {
			action: existingRepair ? "reprioritized" : "added",
			reason: `case_memory_repair_from_knowledge_graph:score=${highScore || "unknown"}`,
			targetLane: repairLane,
			addedLane: existingRepair ? undefined : repairLane,
			migrations,
			next,
		};
	}

	if (promotionSignal && lowValueCurrent && proofIndex >= 0 && proofIndex !== currentIndex) {
		const targetLane = mission.lanes[proofIndex]?.name;
		if (targetLane) {
			return {
				action: "skipped",
				reason: `case_memory_high_score_skip_low_value_lane:score=${highScore || "unknown"}`,
				targetLane,
				skippedLane: lane.name,
				migrations,
				next,
			};
		}
	}

	return {
		action: "reprioritized",
		reason: `case_memory_promoted_current_lane:score=${highScore || "unknown"}`,
		targetLane: lane.name,
		migrations,
		next,
	};
}

function applyCaseMemoryLanePlan(params: {
	mission: MissionState;
	lane: MissionLane;
	pack: LaneCommandPack;
}): CaseMemoryLanePlan {
	const plan = caseMemoryLanePlan(params.mission, params.lane, params.pack);
	if (plan.action === "none") return plan;

	const mission = readCurrentMission() ?? params.mission;
	const timestamp = new Date().toISOString();
	const targetLane = plan.targetLane ?? plan.addedLane ?? params.lane.name;
	const mergeNext = (lane: MissionLane): string[] => {
		const next = [...lane.next];
		for (const item of plan.next) {
			if (!next.includes(item)) next.push(item);
		}
		return next;
	};
	let lanes: MissionLane[];
	if (plan.action === "added") {
		const currentIndex = findLaneIndex(mission, params.lane.name);
		const insertAfter = currentIndex >= 0 ? currentIndex + 1 : 0;
		const plannerLane: MissionLane = {
			name: targetLane,
			objective: /^compact_resume_/i.test(plan.reason)
				? "从 compact_resume_case_memory 恢复 compact 后上下文、operator、proof-loop 链路，闭合 queued/blocked 恢复命令后再恢复主线"
				: "从 knowledge_graph case_memory_migrations 迁移高价值 worker/playbook/command strategy，先修复证据面再恢复主线",
			next: plan.next,
			status: "in_progress",
			note: truncateMiddle(`case_memory_lane_plan=added; source=${params.lane.name}; reason=${plan.reason}`, 500),
			updatedAt: timestamp,
		};
		const withoutPlanner = mission.lanes.filter((lane) => lane.name !== targetLane);
		withoutPlanner.splice(Math.min(insertAfter, withoutPlanner.length), 0, plannerLane);
		lanes = withoutPlanner.map((lane) => {
			if (lane.name === plannerLane.name) return lane;
			if (lane.name === params.lane.name) {
				return {
					...lane,
					status: "pending" as const,
					note: truncateMiddle(
						`case_memory_lane_plan=handoff; target=${plannerLane.name}; reason=${plan.reason}`,
						500,
					),
					updatedAt: timestamp,
				};
			}
			if (lane.status === "in_progress") return { ...lane, status: "pending" as const, updatedAt: timestamp };
			return lane;
		});
	} else {
		lanes = mission.lanes.map((lane) => {
			if (lane.name === targetLane) {
				return {
					...lane,
					status: "in_progress" as const,
					next: mergeNext(lane),
					note: truncateMiddle(`case_memory_lane_plan=${plan.action}; reason=${plan.reason}`, 500),
					updatedAt: timestamp,
				};
			}
			if (plan.skippedLane && lane.name === plan.skippedLane) {
				return {
					...lane,
					status: "pending" as const,
					note: truncateMiddle(`case_memory_lane_plan=skipped; target=${targetLane}; reason=${plan.reason}`, 500),
					updatedAt: timestamp,
				};
			}
			if (lane.name === params.lane.name && targetLane !== params.lane.name) {
				return {
					...lane,
					status: "pending" as const,
					note: truncateMiddle(`case_memory_lane_plan=handoff; target=${targetLane}; reason=${plan.reason}`, 500),
					updatedAt: timestamp,
				};
			}
			if (lane.status === "in_progress") return { ...lane, status: "pending" as const, updatedAt: timestamp };
			return lane;
		});
	}
	const checkpoints = upsertMissionCheckpoint(
		mission.checkpoints,
		"memory_checked",
		"done",
		`case_memory_lane_plan:${plan.action}:${targetLane}`,
	);
	writeCurrentMission({ ...mission, lanes, checkpoints });
	return plan;
}

function formatCaseMemoryLanePlan(plan: CaseMemoryLanePlan): string {
	return [
		"case_memory_lane_plan:",
		`action: ${plan.action}`,
		`reason: ${plan.reason}`,
		plan.targetLane ? `target_lane: ${plan.targetLane}` : undefined,
		plan.addedLane ? `added_lane: ${plan.addedLane}` : undefined,
		plan.skippedLane ? `skipped_lane: ${plan.skippedLane}` : undefined,
		"migrations:",
		...(plan.migrations.length > 0 ? plan.migrations.map((item) => `- ${item}`) : ["- none"]),
		"next:",
		...(plan.next.length > 0 ? plan.next.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function currentCaseMemoryLanePlan(target?: string): CaseMemoryLanePlan | undefined {
	const mission = readCurrentMission();
	if (!mission) return undefined;
	const lane = activeLane(mission);
	if (!lane) return undefined;
	const pack = laneCommandPack(mission, lane, target);
	return caseMemoryLanePlan(mission, lane, pack);
}

function caseMemoryLanePlanLines(plan?: CaseMemoryLanePlan): string[] {
	if (!plan) return ["case_memory_lane_plan: none"];
	return [
		`case_memory_lane_plan: action=${plan.action} reason=${plan.reason}`,
		plan.targetLane ? `case_memory_target_lane=${plan.targetLane}` : undefined,
		plan.addedLane ? `case_memory_added_lane=${plan.addedLane}` : undefined,
		plan.skippedLane ? `case_memory_skipped_lane=${plan.skippedLane}` : undefined,
		`case_memory_migrations=${plan.migrations.length}`,
		...plan.migrations.slice(0, 6).map((item) => `case_memory_migration=${truncateMiddle(item, 220)}`),
	].filter((item): item is string => Boolean(item));
}

function caseMemoryOperatorCommands(plan: CaseMemoryLanePlan | undefined, target?: string): string[] {
	if (!plan || plan.migrations.length === 0) return [];
	const suffix = commandTargetSuffix(target);
	const targetLane = plan.targetLane ?? plan.addedLane;
	return Array.from(
		new Set([
			`re_autopilot plan${suffix}`,
			...(plan.action !== "none" ? [`re_autopilot run${suffix} 1`] : []),
			...(targetLane ? [`re_lane plan ${targetLane}${suffix}`, `re_lane run-auto ${targetLane} 2`] : []),
			"re_context pack",
			`re_operator dispatch${suffix} 1`,
		]),
	).slice(0, 8);
}

function caseMemoryProofBridge(plan: CaseMemoryLanePlan | undefined, target?: string): string[] {
	if (!plan || plan.migrations.length === 0) return [];
	const suffix = proofLoopCommandTarget(target);
	return [
		`case_memory_lane_plan action=${plan.action} reason=${plan.reason}`,
		`autopilot_plan="re_autopilot plan${suffix}"`,
		...(plan.action !== "none" ? [`autopilot_run="re_autopilot run${suffix} 1"`] : []),
		...(plan.targetLane ? [`target_lane="${plan.targetLane}"`] : []),
		...(plan.addedLane ? [`added_lane="${plan.addedLane}"`] : []),
		...(plan.skippedLane ? [`skipped_lane="${plan.skippedLane}"`] : []),
		`context_operator_bridge="re_context pack && re_operator dispatch${suffix} 1"`,
		...plan.migrations.slice(0, 4).map((item) => `migration=${truncateMiddle(item, 220)}`),
	];
}

function shouldEscalateAdaptiveDecision(decisions: RunAutoDecision[]): boolean {
	const last = decisions.at(-1);
	if (!last || last.action !== "continue_current") return false;
	const same = decisions.filter((decision) => decision.reason === last.reason);
	if (same.length < 2) return false;
	const previous = same.at(-2);
	if (!previous) return true;
	if (last.quality === undefined || previous.quality === undefined) return true;
	return last.quality <= previous.quality + 5;
}

function upsertMissionCheckpoint(
	checkpoints: MissionCheckpoint[],
	name: string,
	status: MissionCheckpointStatus,
	note?: string,
): MissionCheckpoint[] {
	const updatedAt = new Date().toISOString();
	if (checkpoints.some((checkpoint) => checkpoint.name === name)) {
		return checkpoints.map((checkpoint) => (checkpoint.name === name ? { ...checkpoint, status, note, updatedAt } : checkpoint));
	}
	return [...checkpoints, { name, status, note, updatedAt }];
}

function adaptiveSourceLaneName(lane: MissionLane): string | undefined {
	const match = /(?:^|;\s*)adaptive_from=([^;]+)/.exec(lane.note ?? "");
	const source = match?.[1]?.trim();
	return source || undefined;
}

function normalizeBootstrapToolToken(token: string): string | undefined {
	const normalized = token.replace(/^[`'"]+|[`'",;]+$/g, "").trim();
	if (!normalized || /^(re_bootstrap|plan|install|none)$/i.test(normalized)) return undefined;
	return normalized;
}

function bootstrapToolsFromLane(lane: MissionLane, text: string): string[] {
	const tools: string[] = [];
	const add = (value?: string) => {
		for (const item of splitMetadataList(value)) {
			const tool = normalizeBootstrapToolToken(item);
			if (tool && !tools.includes(tool)) tools.push(tool);
		}
	};
	const combined = [lane.note ?? "", lane.next.join("\n"), text].join("\n");
	for (const match of combined.matchAll(/\bre_bootstrap\s+(?:plan|install)\s+([^\n#]+)/g)) {
		add(match[1]);
	}
	add(metadataValue(text, "missing_tools"));
	for (const match of combined.matchAll(/missing_tools:\s*([^\n]+)/g)) {
		add(match[1]);
	}
	return tools.slice(0, 16);
}

function markToolBootstrapClosure(params: {
	laneName: string;
	sourceLane?: string;
	tools: string[];
	missing: string[];
	refreshedPath: string;
}): void {
	const mission = readCurrentMission();
	if (!mission) return;
	const timestamp = new Date().toISOString();
	const installCommand = params.missing.length > 0 ? `re_bootstrap install ${params.missing.join(" ")}` : undefined;
	const lanes = mission.lanes.map((lane) => {
		if (lane.name === params.laneName) {
			const next = [...lane.next];
			if (installCommand && !next.includes(installCommand)) next.unshift(installCommand);
			return {
				...lane,
				status: params.missing.length > 0 ? ("in_progress" as const) : ("done" as const),
				next,
				note: truncateMiddle(
					[
						params.missing.length > 0 ? "bootstrap_incomplete" : "bootstrap_closed",
						`tools=${params.tools.join(",") || "none"}`,
						params.missing.length > 0 ? `missing=${params.missing.join(",")}` : "missing=none",
						params.sourceLane ? `resume=${params.sourceLane}` : undefined,
					]
						.filter(Boolean)
						.join("; "),
					500,
				),
				updatedAt: timestamp,
			};
		}
		if (params.missing.length === 0 && params.sourceLane && lane.name === params.sourceLane) {
			return {
				...lane,
				status: "in_progress" as const,
				note: truncateMiddle(
					`bootstrap_resumed_from=${params.laneName}; tools=${params.tools.join(",") || "none"}; tool_index=${params.refreshedPath}`,
					500,
				),
				updatedAt: timestamp,
			};
		}
		if (params.missing.length === 0 && lane.status === "in_progress") {
			return { ...lane, status: "pending" as const, updatedAt: timestamp };
		}
		return lane;
	});
	const checkpoints = upsertMissionCheckpoint(
		mission.checkpoints,
		"tool_index_checked",
		params.missing.length > 0 ? "blocked" : "done",
		params.missing.length > 0
			? `missing after bootstrap refresh: ${params.missing.join(", ")}`
			: `bootstrap closure refreshed ${params.refreshedPath}`,
	);
	writeCurrentMission({ ...mission, lanes, checkpoints });
}

async function runToolBootstrapClosure(
	pi: ExtensionAPI,
	params: { lane: MissionLane; text: string },
): Promise<ToolBootstrapClosure | undefined> {
	if (params.lane.name !== "tool-bootstrap") return undefined;
	const sourceLane = adaptiveSourceLaneName(params.lane);
	const tools = bootstrapToolsFromLane(params.lane, params.text);
	const installRequested = /\bre_bootstrap\s+install\b/.test(params.lane.next.join("\n"));
	const bootstrapExecution = installRequested && tools.length > 0 ? await installBootstrapTools(pi, tools) : undefined;
	const refreshed = bootstrapExecution ? readText(toolIndexPath()) : await refreshToolIndex(pi);
	const plan = tools.length > 0 ? createBootstrapPlan(tools) : [];
	const missing = plan.filter((item) => item.known && !item.present).map((item) => item.tool);
	markToolBootstrapClosure({
		laneName: params.lane.name,
		sourceLane,
		tools,
		missing,
		refreshedPath: toolIndexPath(),
	});
	const text = [
		"tool_bootstrap_closure:",
		`tools: ${tools.join(", ") || "none"}`,
		`install_requested: ${installRequested ? "true" : "false"}`,
		`refreshed_tool_index: ${toolIndexPath()}`,
		`missing_after_refresh: ${missing.join(", ") || "none"}`,
		sourceLane ? `resumed_lane: ${missing.length === 0 ? sourceLane : "none"}` : "resumed_lane: none",
		missing.length > 0
			? `next_bootstrap_command: re_bootstrap install ${missing.join(" ")}`
			: "next_bootstrap_command: none",
		"",
		"bootstrap_plan_after_refresh:",
		formatBootstrapPlan(plan),
		...(bootstrapExecution ? ["", "bootstrap_execution:", truncateMiddle(bootstrapExecution, 6000)] : []),
		"",
		"refreshed_tool_index_tail:",
		truncateMiddle(refreshed, 3000),
	].join("\n");
	if (tools.length === 0) {
		return {
			text,
			decision: { action: "stop", reason: `tool_bootstrap_no_tools:${params.lane.name}` },
		};
	}
	if (missing.length > 0) {
		return {
			text,
			decision: {
				action: "stop",
				reason: `tool_bootstrap_incomplete:${missing.join(",")}`,
			},
		};
	}
	return {
		text,
		decision: {
			action: "continue_next",
			reason: `tool_bootstrap_closed:${sourceLane ?? params.lane.name}`,
			nextLane: sourceLane,
		},
		nextLane: sourceLane,
	};
}

async function runAutoLaneChain(
	pi: ExtensionAPI,
	params: {
		lane?: string;
		target?: string;
		maxSteps?: number;
		maxCommandsPerStep?: number;
		reasoning?: "regex" | "llm";
		dispatch?: "inline" | "specialist";
		cwd?: string;
	},
): Promise<string> {
	const maxSteps = Math.min(Math.max(Math.floor(params.maxSteps ?? 2), 1), 5);
	const maxCommandsPerStep = Math.min(Math.max(Math.floor(params.maxCommandsPerStep ?? 3), 1), 6);
	const outputs: string[] = [];
	let stopReason = "max_steps_reached";
	let requestedLane = params.lane;
	const decisions: RunAutoDecision[] = [];
	let caseMemoryPlanApplied = false;
	for (let step = 0; step < maxSteps; step++) {
		const mission = readCurrentMission();
		if (!mission) {
			stopReason = "no_active_mission";
			break;
		}
		const lane = activeLane(mission, requestedLane);
		requestedLane = undefined;
		if (!lane) {
			stopReason = "no_active_lane";
			break;
		}
		if (!caseMemoryPlanApplied) {
			const memoryPack = laneCommandPack(mission, lane, params.target);
			const plan = applyCaseMemoryLanePlan({ mission, lane, pack: memoryPack });
			if (plan.action !== "none" || plan.migrations.length > 0) {
				outputs.push(`## case-memory-lane-plan step ${step + 1}\n${formatCaseMemoryLanePlan(plan)}`);
				caseMemoryPlanApplied = true;
				if (plan.action !== "none") {
					requestedLane = plan.targetLane ?? plan.addedLane ?? lane.name;
					stopReason = `case_memory_lane_plan:${plan.action}:${requestedLane ?? "none"}`;
					continue;
				}
			}
		}
		// Opt-in specialist dispatch: hand the lane to a real specialist subagent
		// (reverser/explorer/operator/verifier) when dispatch==="specialist" and a
		// spec owns the lane. Falls through to the inline command-pack path
		// otherwise. Recursion-bound (dispatchLaneSpecialist checks REPI_AGENT_THREAD).
		if (params.dispatch === "specialist" && params.cwd && !envBoolean("REPI_AGENT_THREAD")) {
			try {
				const specialist = await dispatchLaneSpecialist({
					cwd: params.cwd,
					lane,
					mission,
					target: params.target,
				});
				if (specialist) {
					let decision = specialist.decision;
					const sections = [
						`## run-auto step ${step + 1}: ${lane.name} (specialist:${specialist.spec})`,
						truncateMiddle(specialist.text, 14000),
						specialist.note,
					];
					const bootstrapClosure = await runToolBootstrapClosure(pi, { lane, text: specialist.text });
					if (bootstrapClosure) {
						decision = bootstrapClosure.decision;
						sections.push(`## tool-bootstrap-closure step ${step + 1}\n${bootstrapClosure.text}`);
					}
					decisions.push(decision);
					sections.push(formatRunAutoDecision(decision));
					outputs.push(sections.join("\n"));
					if (shouldEscalateAdaptiveDecision(decisions)) {
						const plan = applyAdaptiveMultiLanePlan({ lane, decision, text: specialist.text, target: params.target });
						outputs.push(`## multi-lane-planner step ${step + 1}\n${formatMultiLanePlan(plan)}`);
						stopReason = `multi_lane_plan:${plan.lane ?? "none"}:${decision.reason}`;
						break;
					}
					if (decision.action === "continue_current") {
						requestedLane = decision.nextLane ?? lane.name;
						stopReason = step + 1 >= maxSteps ? `max_steps_reached_after:${decision.reason}` : "adaptive_continue_current";
						continue;
					}
					if (decision.action === "continue_next") {
						requestedLane = decision.nextLane;
						stopReason = step + 1 >= maxSteps ? `max_steps_reached_after:${decision.reason}` : "adaptive_continue_next";
						continue;
					}
					stopReason = decision.reason;
					break;
				}
			} catch (error) {
				outputs.push(
					`## run-auto step ${step + 1}: ${lane.name} (specialist_dispatch_failed: ${truncateMiddle(String((error as Error).message ?? error), 160)} — falling back to inline)`,
				);
			}
		}
		const { commands, rawItems } = autoCommandsForLane(lane, maxCommandsPerStep);
		if (commands.length === 0) {
			const bootstrapClosure = await runToolBootstrapClosure(pi, { lane, text: "" });
			if (bootstrapClosure) {
				const decision = bootstrapClosure.decision;
				decisions.push(decision);
				outputs.push(
					[
						`## run-auto step ${step + 1}: ${lane.name}`,
						`## tool-bootstrap-closure step ${step + 1}\n${bootstrapClosure.text}`,
						formatRunAutoDecision(decision),
					].join("\n"),
				);
				if (decision.action === "continue_next") {
					requestedLane = decision.nextLane;
					stopReason =
						step + 1 >= maxSteps ? `max_steps_reached_after:${decision.reason}` : "adaptive_continue_next";
					continue;
				}
				stopReason = decision.reason;
				break;
			}
			stopReason = `no_auto_commands:${lane.name}`;
			break;
		}
		removeLaneNextItems(lane.name, rawItems);
		const pack = autoLaneCommandPack(mission, lane, commands, params.target);
		const text = await runLaneCommandPack(pi, pack);
		let decision = parseLaneRunDecision(text, lane.name);
		let llmNote = "";
		if (params.reasoning === "llm" && params.cwd && !envBoolean("REPI_AGENT_THREAD")) {
			try {
				decision = await llmLaneRunDecision({ cwd: params.cwd, text, lane, mission, target: params.target });
				llmNote = "llm-step-planner: applied";
			} catch (error) {
				llmNote = `llm-step-planner: fallback_to_regex (${truncateMiddle(String((error as Error).message ?? error), 160)})`;
			}
		}
		const sections = [`## run-auto step ${step + 1}: ${lane.name}`, truncateMiddle(text, 14000)];
		if (llmNote) sections.push(llmNote);
		const bootstrapClosure = await runToolBootstrapClosure(pi, { lane, text });
		if (bootstrapClosure) {
			decision = bootstrapClosure.decision;
			sections.push(`## tool-bootstrap-closure step ${step + 1}\n${bootstrapClosure.text}`);
		}
		decisions.push(decision);
		sections.push(formatRunAutoDecision(decision));
		outputs.push(sections.join("\n"));
		if (shouldEscalateAdaptiveDecision(decisions)) {
			const plan = applyAdaptiveMultiLanePlan({ lane, decision, text, target: params.target });
			outputs.push(`## multi-lane-planner step ${step + 1}\n${formatMultiLanePlan(plan)}`);
			stopReason = `multi_lane_plan:${plan.lane ?? "none"}:${decision.reason}`;
			break;
		}
		if (decision.action === "continue_current") {
			requestedLane = decision.nextLane ?? lane.name;
			stopReason = step + 1 >= maxSteps ? `max_steps_reached_after:${decision.reason}` : "adaptive_continue_current";
			continue;
		}
		if (decision.action === "continue_next") {
			requestedLane = decision.nextLane;
			stopReason = step + 1 >= maxSteps ? `max_steps_reached_after:${decision.reason}` : "adaptive_continue_next";
			continue;
		}
		if (/^tool_bootstrap_/.test(decision.reason)) {
			stopReason = decision.reason;
			break;
		}
		const plan = applyAdaptiveMultiLanePlan({ lane, decision, text, target: params.target });
		outputs.push(`## multi-lane-planner step ${step + 1}\n${formatMultiLanePlan(plan)}`);
		stopReason =
			plan.action === "none" ? decision.reason : `multi_lane_plan:${plan.lane ?? "none"}:${decision.reason}`;
		break;
	}
	const stepsExecuted = decisions.length;
	const playbook =
		outputs.length > 0
			? writeRunAutoPlaybook({
					requestedLane: params.lane,
					target: params.target,
					maxSteps,
					stepsExecuted,
					stopReason,
					outputs,
				})
			: undefined;
	return [
		"run_auto_summary:",
		`max_steps: ${maxSteps}`,
		`steps_executed: ${stepsExecuted}`,
		`adaptive_decisions: ${decisions.length}`,
		`stop_reason: ${stopReason}`,
		...(playbook
			? [
					`playbook_path: ${playbook.path}`,
					`field_journal_anchor: ${playbook.journalAnchor}`,
					`evolution_anchor: ${playbook.evolutionAnchor}`,
				]
			: []),
		"",
		...outputs,
	].join("\n");
}

function archiveReconFileIfExists(path: string, archiveRoot: string, archived: string[]): void {
	try {
		if (!existsSync(path)) return;
		const relative = path.startsWith(reconDir()) ? path.slice(reconDir().length + 1) : artifactBasename(path);
		const target = join(archiveRoot, relative);
		mkdirSync(dirname(target), { recursive: true });
		renameSync(path, target);
		archived.push(`${path} -> ${target}`);
	} catch (error) {
		archived.push(`${path} -> archive_failed:${String(error).slice(0, 180)}`);
	}
}

function prepareAutopilotCleanState(params: { target?: string; task?: string }): string[] {
	ensureReconStorage();
	const timestamp = new Date().toISOString();
	const archiveRoot = join(reconArchiveDir(), `autopilot-clean-state-${timestamp.replace(/[:.]/g, "-")}`);
	mkdirSync(archiveRoot, { recursive: true });
	const archived: string[] = [];
	for (const path of [
		currentMissionPath(),
		memoryPath("dispatcher-feedback-board.md"),
		memoryPath("compaction-auto-resume-board.md"),
		memoryPath("compaction-resume-ledger.jsonl"),
		compactResumeTransitionLedgerPath(),
		memoryScopeIsolationReportPath(),
		memoryArtifactScopeFilterReportPath(),
	]) {
		archiveReconFileIfExists(path, archiveRoot, archived);
	}
	// Atomic (opt #208): temp+rename 0o644 so a crash mid-write cannot leave a
	// truncated archive manifest.json that a later restore reads as partial.
	atomicWriteFileSync(
		join(archiveRoot, "manifest.json"),
		`${JSON.stringify(
			{
				kind: "repi-autopilot-clean-state-archive",
				generatedAt: timestamp,
				target: sanitizeTargetForCommand(params.target),
				task: sanitizeMemoryText(params.task),
				archived,
				policy: "archive volatile mission/context/dispatcher state; keep tool-index and immutable evidence available through scoped filters",
			},
			null,
			2,
		)}\n`,
		0o644,
	);
	ensureReconStorage();
	return [`archive_root=${archiveRoot}`, ...archived.slice(0, 16)];
}

function ensureAutopilotMission(params: { task?: string; target?: string; cleanState?: boolean }): MissionState {
	const task =
		params.task?.trim() ||
		(readCurrentMission()?.task ?? `autopilot ${params.target ? `target ${params.target}` : "reverse/pentest task"}`);
	if (params.task || !readCurrentMission()) {
		return writeCurrentMission(createMission(task, routeReconTask(`${task} ${params.target ?? ""}`)));
	}
	return readCurrentMission()!;
}

/**
 * Route-aware real-path defaults for the autopilot/swarm. Out of the box REPI
 * now favors real specialists (dispatch=specialist), the LLM step-planner
 * (reasoning=llm), and the real process-isolated swarm (execution=real) — the
 * auth/handoff/timeout blockers that previously made these unsafe are cleared.
 * Set REPI_AUTOMODE_LEGACY=1 to revert to the deterministic mechanical path
 * (regex/inline/simulated) for cost-controlled or deterministic runs. The real
 * paths are still cwd-gated and recursion-bound, so worker threads and
 * ctx-less direct tool calls (tests) keep falling back to the inline path.
 */
function autoModeDefaults(): {
	reasoning: "regex" | "llm";
	dispatch: "inline" | "specialist";
	swarmExecution: "simulated" | "real";
} {
	if (envBoolean("REPI_AUTOMODE_LEGACY")) {
		return { reasoning: "regex", dispatch: "inline", swarmExecution: "simulated" };
	}
	return { reasoning: "llm", dispatch: "specialist", swarmExecution: "real" };
}

async function runAutopilot(
	pi: ExtensionAPI,
	params: {
		action?: "plan" | "run";
		task?: string;
		target?: string;
		lane?: string;
		mapDepth?: number;
		maxAutoSteps?: number;
		runAuto?: boolean;
		cleanState?: boolean;
		reasoning?: "regex" | "llm";
		dispatch?: "inline" | "specialist";
		cwd?: string;
	},
): Promise<string> {
	const action = params.action ?? "run";
	const cleanStateSummary = params.cleanState ? prepareAutopilotCleanState(params) : [];
	const mission = ensureAutopilotMission({ task: params.task, target: params.target });
	const lane = activeLane(mission, params.lane);
	if (!lane) return `autopilot_result:\nstatus: blocked\nreason: no active lane\n${formatMission(mission)}`;
	const initialPack = laneCommandPack(mission, lane, params.target);
	const initialCaseMemoryLanePlan = caseMemoryLanePlan(mission, lane, initialPack);
	const initialMap = latestPassiveMapContext();
	const initialBootstrap = autopilotBootstrapPlan(mission.route, initialPack, initialMap);
	const initialStrategy = autopilotExecutionStrategy(initialPack, initialBootstrap);
	if (action === "plan") {
		return [
			"autopilot_plan:",
			`mission_id: ${mission.id}`,
			`lane: ${lane.name}`,
			`target: ${initialPack.target ?? params.target ?? "<TARGET>"}`,
			`clean_state: ${params.cleanState ? "applied" : "off"}`,
			...(cleanStateSummary.length ? cleanStateSummary.map((item) => `clean_state_${item}`) : []),
			"stages:",
			"- re_map target/depth -> evidence/maps artifact",
			"- bootstrap plan from route/map/command-pack/tool-index",
			"- case_memory_migrations -> case_memory_lane_plan lane reprioritize/add/skip",
			"- re_lane plan/run using latest map artifact",
			"- re_lane run-auto bounded follow-up chain",
			"- re_complete audit",
			"",
			"## case-memory-lane-plan",
			formatCaseMemoryLanePlan(initialCaseMemoryLanePlan),
			"",
			"## bootstrap",
			formatAutopilotBootstrap(initialBootstrap),
			"",
			"## execution-strategy",
			formatAutopilotExecutionStrategy(initialStrategy),
			"",
			formatLaneCommandPack(initialStrategy.pack),
		].join("\n");
	}

	const outputs: string[] = [];
	outputs.push(`## mission\n${formatMission(mission)}`);
	outputs.push(
		`## map\n${await runPassiveMap(pi, { target: params.target ?? initialPack.target, depth: params.mapDepth })}`,
	);
	let mappedMission = readCurrentMission() ?? mission;
	let mappedLane = activeLane(mappedMission, params.lane) ?? lane;
	updateMissionCheckpoint("repro_commands_ready", "done", `autopilot:${mappedLane.name}`);
	let pack = laneCommandPack(mappedMission, mappedLane, params.target ?? initialPack.target);
	const caseMemoryPlan = applyCaseMemoryLanePlan({ mission: mappedMission, lane: mappedLane, pack });
	outputs.push(`## case-memory-lane-plan\n${formatCaseMemoryLanePlan(caseMemoryPlan)}`);
	if (caseMemoryPlan.action !== "none") {
		mappedMission = readCurrentMission() ?? mappedMission;
		mappedLane =
			activeLane(mappedMission, caseMemoryPlan.targetLane ?? caseMemoryPlan.addedLane ?? params.lane) ??
			activeLane(mappedMission) ??
			mappedLane;
		pack = laneCommandPack(mappedMission, mappedLane, params.target ?? initialPack.target);
		updateMissionCheckpoint("repro_commands_ready", "done", `autopilot:${mappedLane.name}:case_memory_lane_plan`);
	}
	const bootstrap = autopilotBootstrapPlan(mappedMission.route, pack, latestPassiveMapContext());
	const strategy = autopilotExecutionStrategy(pack, bootstrap);
	outputs.push(`## bootstrap\n${formatAutopilotBootstrap(bootstrap)}`);
	outputs.push(`## execution-strategy\n${formatAutopilotExecutionStrategy(strategy)}`);
	outputs.push(`## command-pack\n${formatLaneCommandPack(strategy.pack)}`);
	outputs.push(`## lane-run\n${await runLaneCommandPack(pi, strategy.pack, { strategy })}`);
	if (params.runAuto !== false) {
		const auto = autoModeDefaults();
		outputs.push(
			`## run-auto\n${await runAutoLaneChain(pi, {
				lane: undefined,
				target: strategy.pack.target ?? params.target,
				maxSteps: params.maxAutoSteps,
				reasoning: params.reasoning ?? auto.reasoning,
				dispatch: params.dispatch ?? auto.dispatch,
				cwd: params.cwd,
			})}`,
		);
	}
	const audit = formatCompletionAudit();
	outputs.push(`## completion-audit\n${audit}`);
	const anchor = appendJournal(
		"autopilot",
		`${mappedMission.route.domain} ${pack.target ?? params.target ?? "target"}`,
		[
			`mission_id=${mappedMission.id}`,
			`lane=${mappedLane.name}`,
			`target=${strategy.pack.target ?? params.target ?? "<none>"}`,
			`execution_strategy=${strategy.mode}`,
			`run_auto=${params.runAuto !== false}`,
			`audit=${audit.split(/\r?\n/)[0] ?? "unknown"}`,
		].join("\n"),
	);
	updateMissionCheckpoint("memory_or_evolution_written", "done", anchor);
	return [
		"autopilot_result:",
		`action: ${action}`,
		`mission_id: ${mappedMission.id}`,
		`lane: ${mappedLane.name}`,
		`target: ${strategy.pack.target ?? params.target ?? "<TARGET>"}`,
		`execution_strategy: ${strategy.mode}`,
		`clean_state: ${params.cleanState ? "applied" : "off"}`,
		...(cleanStateSummary.length ? cleanStateSummary.map((item) => `clean_state_${item}`) : []),
		`field_journal_anchor: ${anchor}`,
		"",
		...outputs.map((output) => truncateMiddle(output, 16000)),
	].join("\n");
}

function writeRunAutoPlaybook(params: {
	requestedLane?: string;
	target?: string;
	maxSteps: number;
	stepsExecuted: number;
	stopReason: string;
	outputs: string[];
}): { path: string; journalAnchor: string; evolutionAnchor: string } {
	ensureReconStorage();
	const mission = readCurrentMission();
	const timestamp = new Date().toISOString();
	const artifacts = uniqueMatches(params.outputs.join("\n"), /^evidence_artifact:\s*(.+)$/gm, 20);
	const autoUpdates = interestingLines(
		params.outputs.join("\n"),
		/auto_lane_update:|next_lane_hint:|followup_commands:/,
		40,
	);
	const metrics = runAutoPlaybookMetrics(params.outputs, params.stopReason);
	const title = `${mission?.route.domain ?? "security"} ${params.requestedLane ?? "auto-chain"}`;
	const path = join(memoryPlaybooksDir(), `${timestamp.replace(/[:.]/g, "-")}-${slug(title)}.md`);
	const body = [
		"# REPI Auto Playbook",
		"",
		`timestamp: ${timestamp}`,
		`mission_id: ${mission?.id ?? "none"}`,
		`task: ${mission?.task ?? "unknown"}`,
		`route: ${mission?.route.domain ?? "unknown"}`,
		`requested_lane: ${params.requestedLane ?? "active"}`,
		`target: ${params.target ?? "<none>"}`,
		`max_steps: ${params.maxSteps}`,
		`steps_executed: ${params.stepsExecuted}`,
		`stop_reason: ${params.stopReason}`,
		`quality_score: ${metrics.qualityScore}`,
		`artifact_count: ${metrics.artifactCount}`,
		`auto_advance_count: ${metrics.autoAdvanceCount}`,
		`followup_count: ${metrics.followupCount}`,
		`signal_count: ${metrics.signalCount}`,
		`failure_count: ${metrics.failureCount}`,
		"",
		"## Evidence artifacts",
		"",
		...(artifacts.length > 0 ? artifacts.map((artifact) => `- ${artifact}`) : ["- none parsed"]),
		"",
		"## Auto lane updates / follow-ups",
		"",
		...(autoUpdates.length > 0 ? autoUpdates.map((line) => `- ${truncateMiddle(line, 500)}`) : ["- none parsed"]),
		"",
		"## Mission snapshot",
		"",
		"```",
		mission ? formatMission(mission) : "no mission",
		"```",
		"",
		"## Run transcript",
		"",
		truncateMiddle(params.outputs.join("\n\n"), 24000),
		"",
	].join("\n");
	// Atomic temp+rename (0o600): read back via readText by maintainPlaybooks;
	// a torn writeFileSync would mis-rank/archive with no error. #43/#103.
	writePrivateTextFile(path, body);
	const journalAnchor = appendJournal(
		"run-auto-playbook",
		title,
		[
			`playbook: ${path}`,
			`steps_executed=${params.stepsExecuted}; stop_reason=${params.stopReason}`,
			`quality_score=${metrics.qualityScore}; artifacts=${metrics.artifactCount}; advances=${metrics.autoAdvanceCount}; signals=${metrics.signalCount}; failures=${metrics.failureCount}`,
			artifacts.length ? `artifacts=${artifacts.join(", ")}` : "artifacts=none parsed",
			autoUpdates.length ? `auto_updates=${autoUpdates.slice(0, 8).join(" | ")}` : "auto_updates=none parsed",
		].join("\n"),
	);
	const evolutionAnchor = appendEvolution(
		`run-auto playbook ${mission?.route.domain ?? "security"}`,
		[
			`Promoted bounded run-auto chain into reusable playbook: ${path}`,
			`route=${mission?.route.domain ?? "unknown"} lane=${params.requestedLane ?? "active"} steps=${params.stepsExecuted}`,
			`quality_score=${metrics.qualityScore}; followups=${metrics.followupCount}; signals=${metrics.signalCount}; failures=${metrics.failureCount}`,
			"Reuse rule: when run_auto_summary has evidence artifacts and follow-up commands, search memory/playbooks before repeating manual triage.",
		].join("\n"),
	);
	updateMissionCheckpoint("memory_or_evolution_written", "done", path);
	maintainPlaybooks({ archive: true });
	return { path, journalAnchor, evolutionAnchor };
}

function formatMission(mission: MissionState): string {
	return [
		`mission_id: ${mission.id}`,
		`task: ${mission.task}`,
		formatRoute(mission.route),
		formatLaneQueue(mission),
		"checkpoints:",
		...mission.checkpoints.map((checkpoint) => `- [${checkpoint.status}] ${checkpoint.name}${checkpoint.note ? ` — ${checkpoint.note}` : ""}`),
	].join("\n");
}

function buildMissionDigest(): string {
	const mission = readCurrentMission();
	return mission
		? truncateMiddle(formatMission(mission), 5000)
		: "无 active mission；调用 re_mission new 创建任务黑板。";
}

function missionCheckSummary(): string {
	const mission = readCurrentMission();
	if (!mission) return "no mission";
	return mission.checkpoints.map((checkpoint) => `${checkpoint.name}=${checkpoint.status}`).join(", ");
}

export function appendEvidence(
	record: Omit<EvidenceRecord, "timestamp" | "priority"> & { priority?: number },
): EvidenceRecord {
	const full = appendEvidenceRecord(record, {
		ensureStorage: ensureReconStorage,
		appendText,
		onLedgerUpdated: (updated) => updateMissionCheckpoint("evidence_ledger_updated", "done", updated.title),
	});
	// Tail-rotate the evidence ledger after append. The ledger is an append-only
	// markdown audit log (no hash chain, no per-record counts) appended via the
	// shared read-modify-write appendText; without rotation it grows unbounded
	// across sessions and every append's read-modify-write gets O(n) larger.
	// Readers already truncate to a tail window, so capping is behavior-preserving.
	rotateRuntimeEvidenceLedgerIfNeeded();
	return full;
}

function buildEvidenceDigest(query?: string): string {
	return buildRepiEvidenceDigest(query, { ensureStorage: ensureReconStorage, readText, truncate: truncateMiddle });
}

function buildStartupEvidenceDigest(options: { target?: string } = {}): string {
	return buildRepiStartupEvidenceDigest({
		...options,
		autoInject: envBoolean("REPI_EVIDENCE_AUTO_INJECT") === true,
		ensureStorage: ensureReconStorage,
		readText,
		truncate: truncateMiddle,
	});
}

function buildContextEvidenceTail(options: { target?: string } = {}): string {
	return buildRepiContextEvidenceTail({
		...options,
		autoContextPack: envBoolean("REPI_EVIDENCE_CONTEXT_PACK") === true,
		ensureStorage: ensureReconStorage,
		readText,
		truncate: truncateMiddle,
	});
}

function latestAttackGraphArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("attack_graph", evidenceGraphsDir(), options);
}

function attackGraphNextActions(mission: MissionState | undefined, map: PassiveMapContext | undefined): string[] {
	const actions: string[] = [];
	if (!mission) {
		return ["re_mission new <task>", "re_map <target> <depth>", "re_graph build"];
	}
	const active = mission ? activeLane(mission) : undefined;
	if (!map) actions.push("re_map <target> <depth>");
	if (active) {
		const target = inferTargetFromMap(map, mission) ?? map?.target;
		actions.push(`re_lane plan ${active.name}${target ? ` ${target}` : ""}`.trim());
		actions.push(`re_lane run ${active.name}${target ? ` ${target}` : ""}`.trim());
		if (active.next.some((item) => /^\[auto:/i.test(item))) actions.push(`re_lane run-auto ${active.name} 2`);
	}
	const missingTools = recommendedToolsForRoute(mission.route)
		.map((tool) => createBootstrapPlan([tool])[0])
		.filter((item): item is BootstrapPlan => Boolean(item) && item.known && !item.present)
		.map((item) => item.tool)
		.slice(0, 10);
	if (missingTools.length > 0) actions.push(`re_bootstrap plan ${missingTools.join(" ")}`);
	actions.push("re_complete audit");
	return Array.from(new Set(actions)).slice(0, 12);
}

function summarizeLatestLaneRun(mission: MissionState | undefined): string {
	const paths = recentMarkdownArtifacts(evidenceRunsDir(), 1);
	if (paths.length === 0) return "last_lane_run: (none yet)";
	const path = paths[0];
	let text = "";
	try {
		text = readText(path);
	} catch {
		return `last_lane_run: (unreadable artifact ${path})`;
	}
	const lane = mission ? (activeLane(mission)?.name ?? "") : "";
	const decision = parseLaneRunDecision(text, lane);
	const head = text.slice(0, 600).replace(/\s+\n/g, "\n").trim();
	return [
		`last_lane_run_artifact: ${path}`,
		`decision: action=${decision.action} quality=${decision.quality ?? "n/a"} verdict=${decision.verdict ?? "n/a"} nextLane=${decision.nextLane ?? "n/a"}`,
		`reason: ${truncateMiddle(decision.reason, 300)}`,
		"transcript_head:",
		truncateMiddle(head, 600),
	].join("\n");
}

type EvidenceLedgerTaskRecord = {
	index: number;
	evidenceId: string;
	timestamp: string;
	priority: number;
	kind: string;
	title: string;
	fact?: string;
	command?: string;
	path?: string;
	hash?: string;
	verify?: string;
	confidence?: string;
};

function evidenceLedgerBullet(block: string, key: string): string | undefined {
	const match = new RegExp(`^- ${key}: (.+)$`, "m").exec(block);
	return match?.[1]?.trim();
}

function evidenceLedgerCommand(block: string): string | undefined {
	const match = /^- command: `((?:\\`|[^`])*)`$/m.exec(block);
	return match?.[1]?.replace(/\\`/g, "`").trim();
}

function evidenceRecordHasCounterSignal(record: EvidenceLedgerTaskRecord): boolean {
	return /counter[_ -]?evidence|contradict|refut|negative|no[-_ ]?match|not reproduced|failed|blocked|error|反证|矛盾|失败|未复现/i.test(
		[record.title, record.fact, record.confidence, record.verify].filter(Boolean).join("\n"),
	);
}

function evidenceRecordHasHypothesisSignal(record: EvidenceLedgerTaskRecord): boolean {
	return /hypothesis|claim|candidate|suspect|assumption|assertion|proof|finding|假设|候选|断言|发现/i.test(
		[record.title, record.fact, record.confidence].filter(Boolean).join("\n"),
	);
}

function parseEvidenceLedgerTaskRecords(limit = 14): EvidenceLedgerTaskRecord[] {
	const text = readText(evidenceLedgerPath());
	const blocks = text
		.split(/^##\s+/m)
		.filter((block) => block.trim())
		.map((block) => `## ${block}`);
	const tail = blocks.slice(-limit);
	return tail.flatMap((block, index) => {
		const header = /^##\s+(.+?)\s+—\s+P(\d+)\s+—\s+(.+?)\s+—\s+(.+)$/m.exec(block);
		if (!header) return [];
		const title = header[4]?.trim() ?? "evidence";
		return [
			{
				index,
				evidenceId: `evidence:${index}:${slug(title)}`,
				timestamp: header[1]?.trim() ?? "",
				priority: Number.parseInt(header[2] ?? "7", 10),
				kind: header[3]?.trim() ?? "note",
				title,
				fact: evidenceLedgerBullet(block, "fact"),
				command: evidenceLedgerCommand(block),
				path: evidenceLedgerBullet(block, "path"),
				hash: evidenceLedgerBullet(block, "hash"),
				verify: evidenceLedgerBullet(block, "verify"),
				confidence: evidenceLedgerBullet(block, "confidence"),
			} satisfies EvidenceLedgerTaskRecord,
		];
	});
}

interface PentestingTaskTreeSnapshot {
	text: string;
	gapsCount: number;
	missingProofExits: number;
	lastRunVerdict?: string;
}

function buildPentestingTaskTreeSnapshot(options: { target?: string; focus?: string } = {}): PentestingTaskTreeSnapshot {
	const mission = readCurrentMission();
	const graph = buildAttackGraph();
	const decision = buildDecisionCore({ target: options.target, mode: "tick" });
	const closure = mission ? buildDomainProofExitClosure(mission) : buildDomainProofExitClosure();
	const evidenceTail = buildContextEvidenceTail({ target: options.target });
	const lastRun = summarizeLatestLaneRun(mission);
	const missingRows = closure.rows.filter((row) => row.status === "missing").slice(0, 8);
	const lines: string[] = ["# Pentesting Task Tree (PTT) snapshot"];
	if (options.focus) lines.push(`focus: ${options.focus}`);
	lines.push(
		"",
		"## root objective",
		mission?.task ?? "(no active mission — run re_route / re_kernel first)",
		`route: ${mission ? formatRoute(mission.route) : "(none)"}`,
		"",
		"## lanes (branches)",
		mission ? formatMission(mission) : "(no active mission)",
		"",
		"## attack graph",
		`critical_path: ${graph.criticalPath.length ? graph.criticalPath.join(" -> ") : "(none)"}`,
		`gaps (${graph.gaps.length}):`,
		...graph.gaps.slice(0, 16).map((gap) => `- ${gap}`),
		"next_actions:",
		...graph.nextActions.slice(0, 12).map((action) => `- ${action}`),
		"",
		"## decision core",
		`objective_stack: ${decision.objectiveStack.join(" / ") || "(empty)"}`,
		"decision_rules:",
		...decision.decisionRules.slice(0, 16).map((rule) => `- ${rule}`),
		"operator_queue:",
		...decision.operatorQueue.slice(0, 12).map((queue) => `- ${queue}`),
		"stop_conditions:",
		...decision.stopConditions.slice(0, 8).map((condition) => `- ${condition}`),
		"",
		"## domain proof-exit closure",
		`status: ${closure.status}`,
		`matched: ${closure.matchedProofExits.length ? closure.matchedProofExits.join(", ") : "(none)"}`,
		`missing: ${closure.missingProofExits.length ? closure.missingProofExits.join(", ") : "(none)"}`,
	);
	if (missingRows.length > 0) {
		lines.push("missing_rows:");
		for (const row of missingRows) {
			const expected = row.expectedEvidence.slice(0, 2).join("; ") || "(unspecified)";
			const commands = row.nextCommands.slice(0, 2).join("; ") || "(no command)";
			lines.push(`- ${row.proofExit}: expected ${expected} -> ${commands}`);
		}
	}
	lines.push(
		"",
		"## evidence ledger tail",
		truncateMiddle(evidenceTail, 3000),
		"",
		"## last lane-run",
		lastRun,
	);
	return {
		text: lines.join("\n"),
		gapsCount: graph.gaps.length,
		missingProofExits: closure.missingProofExits.length,
		lastRunVerdict: parseLaneRunDecisionVerdict(lastRun),
	};
}

function parseLaneRunDecisionVerdict(lastRunText: string): string | undefined {
	const match = lastRunText.match(/verdict=([^\s]+)/);
	return match ? match[1] : undefined;
}

export function parsePlannerDecision(mergeText: string): RunAutoDecision {
	const actionMatch = mergeText.match(/action:\s*(continue_current|continue_next|stop)/i);
	if (!actionMatch) throw new Error("llm-step-planner: no action in planner output");
	const action = actionMatch[1].toLowerCase() as RunAutoDecision["action"];
	const nextLaneMatch = mergeText.match(/nextLane:\s*([^\n]+)/i);
	const nextLaneRaw = nextLaneMatch ? nextLaneMatch[1].trim() : "";
	const nextLane = nextLaneRaw && nextLaneRaw.toLowerCase() !== "none" ? nextLaneRaw : undefined;
	const verdictMatch = mergeText.match(/verdict:\s*(strong|partial|weak)/i);
	const qualityMatch = mergeText.match(/quality:\s*(\d+)/i);
	const reasonMatch = mergeText.match(/reason:\s*([^\n]+)/i);
	return {
		action,
		reason: reasonMatch ? reasonMatch[1].trim() : `llm-step-planner action=${action}`,
		nextLane,
		verdict: verdictMatch ? (verdictMatch[1].toLowerCase() as "strong" | "partial" | "weak") : undefined,
		quality: qualityMatch ? Number(qualityMatch[1]) : undefined,
	};
}

async function llmLaneRunDecision(options: {
	cwd: string;
	text: string;
	lane: MissionLane;
	mission: MissionState | undefined;
	target?: string;
}): Promise<RunAutoDecision> {
	const snapshot = buildPentestingTaskTreeSnapshot({ target: options.target });
	const task = [
		"You are the REPI step-planner. Given the Pentesting Task Tree snapshot and the last lane-run transcript, decide the next action for the autopilot loop.",
		"Return exactly these lines and nothing else:",
		"action: continue_current | continue_next | stop",
		"nextLane: <lane name or none>",
		"verdict: strong | partial | weak",
		"quality: <integer 0-100>",
		"reason: <one line>",
		"Rules: continue_current = re-run the same lane with adjusted commands; continue_next = advance to a different lane (set nextLane); stop = no productive next step (tool-blocked, repeated failure, or objective met). Prefer stop over repeating a failing lane.",
		"",
		`active_lane: ${options.lane.name}`,
		"",
		"## PTT snapshot",
		snapshot.text,
		"",
		"## last lane-run transcript",
		truncateMiddle(options.text, 10000),
	].join("\n");
	const mgr = createAgentThreadManager({ cwd: options.cwd });
	const started = await mgr.spawnThread({ specName: "planner", task, timeoutMs: 180000, inheritMcp: true });
	await mgr.awaitRun(started.runId);
	const merge = mgr.mergeRun(started.runId);
	const mergeText = merge?.text ?? "";
	return parsePlannerDecision(mergeText);
}

/**
 * Opt-in specialist dispatch: hand the active lane to the real specialist
 * subagent that owns it (laneSpec → reverser/explorer/operator/verifier) via
 * the real AgentThreadManager, then parse the merge handoff as the lane
 * decision. Returns undefined when no specialist owns the lane (caller falls
 * back to the inline command-pack path). Recursion-bound: a worker never
 * dispatches a grandchild through autopilot.
 */
async function dispatchLaneSpecialist(options: {
	cwd: string;
	lane: MissionLane;
	mission: MissionState;
	target?: string;
}): Promise<{ text: string; decision: RunAutoDecision; spec: string; note: string } | undefined> {
	if (envBoolean("REPI_AGENT_THREAD")) return undefined;
	const spec = laneSpec(options.lane, options.mission.route);
	if (!spec) return undefined;
	const snapshot = buildPentestingTaskTreeSnapshot({ target: options.target });
	const task = [
		`You are the REPI ${spec} specialist. Own this mission lane end to end using your doctrine.`,
		`Lane: ${options.lane.name}`,
		`Objective: ${options.lane.objective}`,
		`Next steps queued: ${options.lane.next.join(", ") || "none"}`,
		options.target ? `Target: ${options.target}` : "",
		"Produce concrete evidence (commands run + output, offsets, artifact refs). Write your handoff to $REPI_WORKER_HANDOFF_PATH as your last action.",
		"Then emit a one-line decision for the autopilot loop:",
		"action: continue_current | continue_next | stop",
		"nextLane: <lane name or none>",
		"reason: <one line>",
		"",
		"## PTT snapshot",
		snapshot.text,
	]
		.filter(Boolean)
		.join("\n");
	const mgr = createAgentThreadManager({ cwd: options.cwd });
	const timeoutMs = spec === "reverser" ? 360000 : 240000;
	const started = await mgr.spawnThread({ specName: spec, task, timeoutMs, inheritMcp: true });
	await mgr.awaitRun(started.runId);
	const merge = mgr.mergeRun(started.runId);
	const mergeText = merge?.text ?? "";
	const decision = parsePlannerDecision(mergeText);
	return { text: mergeText, decision, spec, note: `specialist_dispatch: spec=${spec} status=${merge?.manifest.status ?? "unknown"}` };
}

type RuntimeAdapterExecutionGraphArtifact = RuntimeAdapterExecutionArtifactV1 & {
	stdoutHead?: string;
	stderrHead?: string;
};

type RuntimeAdapterGraphParserSummary = NonNullable<RuntimeAdapterExecutionArtifactV1["parserSignalSummary"]>;
type RuntimeAdapterGraphEvidenceRank = RuntimeAdapterGraphParserSummary["evidenceRanks"][number];

function runtimeAdapterParserSummaryForGraph(
	artifact: RuntimeAdapterExecutionGraphArtifact,
): RuntimeAdapterGraphParserSummary {
	if (artifact.parserSignalSummary) return artifact.parserSignalSummary;
	const matchedSignals = artifact.parserSignals.filter((signal) => Array.isArray(signal.matches) && signal.matches.length > 0);
	const matchedProofExitSignals = Array.from(
		new Set(matchedSignals.map((signal) => signal.proofExitSignal).filter((signal): signal is string => Boolean(signal))),
	);
	const missingProofExitSignals = artifact.proofExitSignals.filter(
		(signal) => !matchedProofExitSignals.includes(signal),
	);
	const evidenceRanks = Array.from(
		new Set(
			matchedSignals
				.map((signal) => signal.evidenceRank)
				.filter((rank): rank is RuntimeAdapterGraphEvidenceRank => Boolean(rank)),
		),
	);
	return {
		matchedRules: matchedSignals.length,
		totalRules: artifact.parserSignals.length,
		matchCount: matchedSignals.reduce((sum, signal) => sum + signal.matches.length, 0),
		evidenceRanks,
		matchedProofExitSignals,
		missingProofExitSignals,
	};
}

function isRuntimeAdapterExecutionGraphArtifact(row: unknown): row is RuntimeAdapterExecutionGraphArtifact {
	if (typeof row !== "object" || row === null) return false;
	const record = row as Record<string, unknown>;
	return (
		record.kind === "RuntimeAdapterExecutionArtifactV1" &&
		record.schemaVersion === 1 &&
		typeof record.adapterId === "string" &&
		typeof record.domainId === "string" &&
		typeof record.bridgeId === "string" &&
		typeof record.startedAt === "string" &&
		typeof record.finishedAt === "string" &&
		typeof record.command === "string" &&
		typeof record.stdoutSha256 === "string" &&
		typeof record.stderrSha256 === "string" &&
		Array.isArray(record.parserSignals) &&
		Array.isArray(record.artifactKinds) &&
		Array.isArray(record.ingestTargets) &&
		Array.isArray(record.proofExitSignals)
	);
}

function recentRuntimeAdapterExecutionArtifacts(
	limit = 8,
): Array<{ path: string; artifact: RuntimeAdapterExecutionGraphArtifact }> {
	const root = join(evidenceToolchainDir(), "runtime-adapters");
	try {
		return readdirSync(root, { withFileTypes: true })
			.filter((entry) => entry.isDirectory())
			.flatMap((entry) => {
				const dir = join(root, entry.name);
				return readdirSync(dir, { withFileTypes: true })
					.filter((file) => file.isFile() && file.name.endsWith(".json"))
					.map((file) => {
						const path = join(dir, file.name);
						let mtimeMs = 0;
						try {
							mtimeMs = statSync(path).mtimeMs;
						} catch {
							mtimeMs = 0;
						}
						return { path, mtimeMs };
					});
			})
			.sort((left, right) => right.mtimeMs - left.mtimeMs || right.path.localeCompare(left.path))
			.slice(0, limit)
			.map(({ path }) => {
				const artifact = readJsonObjectFile<unknown>(path);
				return isRuntimeAdapterExecutionGraphArtifact(artifact) ? { path, artifact } : undefined;
			})
			.filter((item): item is { path: string; artifact: RuntimeAdapterExecutionGraphArtifact } => Boolean(item));
	} catch {
		return [];
	}
}

function buildAttackGraph(): AttackGraphArtifact {
	ensureReconStorage();
	const timestamp = new Date().toISOString();
	const mission = readCurrentMission();
	const map = latestPassiveMapContext();
	const runtimeAdapterArtifacts = recentRuntimeAdapterExecutionArtifacts();
	const nodes = new Map<string, AttackGraphNode>();
	const edges: AttackGraphEdge[] = [];
	const taskTree: AttackGraphTaskTreeNode[] = [];
	const addNode = (node: AttackGraphNode) => {
		if (!nodes.has(node.id)) nodes.set(node.id, node);
	};
	const addEdge = (edge: AttackGraphEdge) => {
		if (!edges.some((item) => item.from === edge.from && item.to === edge.to && item.kind === edge.kind))
			edges.push(edge);
	};
	const addTask = (node: AttackGraphTaskTreeNode) => {
		if (!taskTree.some((item) => item.id === node.id)) taskTree.push(node);
	};
	const sourceArtifacts: string[] = [];
	const gaps: string[] = [];
	const criticalPath: string[] = [];

	if (!mission) {
		gaps.push("no active mission");
	} else {
		const missionId = `mission:${mission.id}`;
		addNode({ id: missionId, kind: "mission", label: mission.task, status: "active" });
		addTask({ id: missionId, kind: "mission", label: mission.task, status: "active", note: mission.route.domain });
		addNode({
			id: `route:${slug(mission.route.domain)}`,
			kind: "route",
			label: mission.route.domain,
			note: mission.route.intent,
		});
		addEdge({
			from: `mission:${mission.id}`,
			to: `route:${slug(mission.route.domain)}`,
			kind: "owns",
			label: "route",
		});
		criticalPath.push(`mission:${mission.id}`, `route:${mission.route.domain}`);
		let previousLane: string | undefined;
		for (const lane of mission.lanes) {
			const laneId = `lane:${slug(lane.name)}`;
			addNode({
				id: laneId,
				kind: "lane",
				label: lane.name,
				status: lane.status ?? "pending",
				note: lane.objective,
			});
			addTask({
				id: laneId,
				parentId: missionId,
				kind: "lane",
				label: lane.name,
				status: lane.status ?? "pending",
				evidence: lane.next.slice(0, 4),
				note: lane.objective,
			});
			addEdge({ from: `mission:${mission.id}`, to: laneId, kind: "owns", label: "lane" });
			if (previousLane) addEdge({ from: previousLane, to: laneId, kind: "orders" });
			previousLane = laneId;
			if (lane.status === "blocked") gaps.push(`blocked lane: ${lane.name}${lane.note ? ` — ${lane.note}` : ""}`);
			if ((lane.status === "in_progress" || lane.status === "pending") && criticalPath.length < 6) {
				criticalPath.push(`${lane.status}:${lane.name}`);
			}
		}
		for (const checkpoint of mission.checkpoints) {
			const checkId = `check:${slug(checkpoint.name)}`;
			addNode({ id: checkId, kind: "checkpoint", label: checkpoint.name, status: checkpoint.status, note: checkpoint.note });
			addTask({
				id: checkId,
				parentId: missionId,
				kind: "checkpoint",
				label: checkpoint.name,
				status: checkpoint.status,
				note: checkpoint.note,
			});
			addEdge({ from: `mission:${mission.id}`, to: checkId, kind: checkpoint.status === "blocked" ? "blocks" : "updates" });
			if (checkpoint.status !== "done")
				gaps.push(`${checkpoint.status} check: ${checkpoint.name}${checkpoint.note ? ` — ${checkpoint.note}` : ""}`);
		}
	}

	if (map) {
		sourceArtifacts.push(map.path);
		addNode({
			id: `map:${slug(artifactBasename(map.path))}`,
			kind: "map",
			label: map.target ?? "workspace map",
			status: `${map.signals.length} signals`,
			path: map.path,
			note: map.signals.slice(0, 5).join(" | "),
		});
		addTask({
			id: `map:${slug(artifactBasename(map.path))}`,
			parentId: mission ? `mission:${mission.id}` : undefined,
			kind: "map",
			label: map.target ?? "workspace map",
			status: `${map.signals.length} signals`,
			path: map.path,
			evidence: map.signals.slice(0, 5),
		});
		if (mission)
			addEdge({ from: `mission:${mission.id}`, to: `map:${slug(artifactBasename(map.path))}`, kind: "evidences" });
	} else {
		gaps.push("no passive map artifact");
	}

	for (const path of recentMarkdownArtifacts(evidenceRunsDir(), 8)) {
		sourceArtifacts.push(path);
		const text = readText(path);
		const lane = metadataValue(text, "lane") ?? artifactBasename(path);
		const verdict = metadataValue(text, "verdict");
		const score = metadataValue(text, "score");
		const runId = `run:${slug(artifactBasename(path))}`;
		addNode({
			id: runId,
			kind: "run",
			label: lane,
			status: verdict ?? "unknown",
			path,
			note: score ? `score=${score}` : undefined,
		});
		const laneId = `lane:${slug(lane)}`;
		addTask({
			id: runId,
			parentId: nodes.has(laneId) ? laneId : mission ? `mission:${mission.id}` : undefined,
			kind: "run",
			label: lane,
			status: verdict ?? "unknown",
			path,
			note: score ? `score=${score}` : undefined,
		});
		if (nodes.has(laneId)) addEdge({ from: laneId, to: runId, kind: "evidences", label: "lane-run" });
		if (verdict === "weak") gaps.push(`weak evidence run: ${path}`);
	}

	for (const { path, artifact } of runtimeAdapterArtifacts) {
		sourceArtifacts.push(path);
		const artifactBase = artifactBasename(path);
		const adapterId = `tool:runtime-adapter:${slug(artifact.adapterId)}`;
		const artifactId = `artifact:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}`;
		const commandId = `command:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}`;
		const parserMatchCount = artifact.parserSignals.reduce((sum, signal) => sum + signal.matches.length, 0);
		const parserSummary = runtimeAdapterParserSummaryForGraph(artifact);
		const parserSummaryId = `summary:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}`;
		const targetProfile = artifact.targetProfile;
		const targetProfileId = `target:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}`;

		addNode({
			id: adapterId,
			kind: "tool",
			label: artifact.adapterId,
			status: `${artifact.selectedRunner}/${artifact.domainId}`,
			note: `runtime-adapter bridge=${artifact.bridgeId} target=${artifact.target ?? "<none>"}`,
		});
		addTask({
			id: adapterId,
			parentId: mission ? `mission:${mission.id}` : undefined,
			kind: "tool",
			label: artifact.adapterId,
			status: `${artifact.selectedRunner}/${artifact.domainId}`,
			note: `runtime-adapter target=${artifact.target ?? "<none>"}`,
		});

		if (targetProfile) {
			addNode({
				id: targetProfileId,
				kind: "target_profile",
				label: truncateMiddle(targetProfile.target || artifact.target || "<none>", 160),
				status: `kinds=${targetProfile.targetKinds.join(",")} exists=${targetProfile.exists}`,
				note: [
					`path=${targetProfile.pathKind ?? "<none>"}`,
					`magic=${targetProfile.magic ?? "<none>"}`,
					`adapters=${targetProfile.adapterIds.join(",") || "<none>"}`,
					`reasons=${targetProfile.reasons.join(" | ") || "<none>"}`,
				].join(" "),
			});
			addTask({
				id: targetProfileId,
				parentId: adapterId,
				kind: "target_profile",
				label: truncateMiddle(targetProfile.target || artifact.target || "<none>", 180),
				status: `kinds=${targetProfile.targetKinds.join(",")} exists=${targetProfile.exists}`,
				evidence: targetProfile.signals
					.slice(0, 8)
					.map(
						(signal) =>
							`rank=${signal.evidenceRank} kind=${signal.targetKind} adapter=${signal.adapterId} reason=${signal.reason}`,
					),
				note: `runtime target profile magic=${targetProfile.magic ?? "<none>"}`,
			});
			addEdge({ from: targetProfileId, to: adapterId, kind: "supports", label: "target-profile-auto-detect" });
		}

		addNode({
			id: artifactId,
			kind: "artifact",
			label: artifactBase,
			status: `exit=${artifact.exitCode ?? "null"} parser_matches=${parserMatchCount}`,
			path,
			note: `stdout_sha256=${artifact.stdoutSha256} stderr_sha256=${artifact.stderrSha256}`,
		});
		addTask({
			id: artifactId,
			parentId: adapterId,
			kind: "artifact",
			label: artifactBase,
			status: `exit=${artifact.exitCode ?? "null"} parser_matches=${parserMatchCount}`,
			path,
			evidence: [
				`artifact_kinds=${artifact.artifactKinds.join(",")}`,
				`proof_exit=${artifact.proofExitSignals.join(" | ")}`,
				`stdout_sha256=${artifact.stdoutSha256}`,
				`stderr_sha256=${artifact.stderrSha256}`,
			],
		});

		addNode({
			id: commandId,
			kind: "command",
			label: truncateMiddle(artifact.command, 160),
			status: artifact.killed ? "killed" : `exit=${artifact.exitCode ?? "null"}`,
			note: `runner=${artifact.selectedRunner}`,
		});
		addTask({
			id: commandId,
			parentId: artifactId,
			kind: "command",
			label: truncateMiddle(artifact.command, 180),
			status: artifact.killed ? "killed" : `exit=${artifact.exitCode ?? "null"}`,
			command: artifact.command,
		});
		addEdge({ from: adapterId, to: commandId, kind: "requires", label: artifact.selectedRunner });
		addEdge({ from: commandId, to: artifactId, kind: "produces", label: "runtime-adapter-json" });
		if (targetProfile) addEdge({ from: targetProfileId, to: artifactId, kind: "evidences", label: "target-profile" });

		addNode({
			id: parserSummaryId,
			kind: "parser_summary",
			label: `parser_signal_summary ${artifact.adapterId}`,
			status: `matched=${parserSummary.matchedRules}/${parserSummary.totalRules} missing=${parserSummary.missingProofExitSignals.length}`,
			note: `ranks=${parserSummary.evidenceRanks.join(",") || "<none>"} matched_proof=${parserSummary.matchedProofExitSignals.join(" | ") || "<none>"}`,
		});
		addTask({
			id: parserSummaryId,
			parentId: artifactId,
			kind: "parser_summary",
			label: `parser_signal_summary ${artifact.adapterId}`,
			status: `matched=${parserSummary.matchedRules}/${parserSummary.totalRules} missing=${parserSummary.missingProofExitSignals.length}`,
			evidence: [
				`matched=${parserSummary.matchedRules}/${parserSummary.totalRules}`,
				`match_count=${parserSummary.matchCount}`,
				`ranks=${parserSummary.evidenceRanks.join(",") || "<none>"}`,
				`matched_proof=${parserSummary.matchedProofExitSignals.join(" | ") || "<none>"}`,
				`missing_proof=${parserSummary.missingProofExitSignals.join(" | ") || "<none>"}`,
			],
		});
		addEdge({ from: parserSummaryId, to: artifactId, kind: "verifies", label: "parser-signal-summary" });

		if (parserSummary.missingProofExitSignals.length > 0) {
			gaps.push(`runtime adapter missing proof: ${artifact.adapterId}: ${parserSummary.missingProofExitSignals.join("; ")}`);
			for (const missingProofExit of parserSummary.missingProofExitSignals.slice(0, 6)) {
				const gapId = `gap:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}:${slug(missingProofExit)}`;
				addNode({
					id: gapId,
					kind: "gap",
					label: missingProofExit,
					status: "missing-proof-exit",
					note: `adapter=${artifact.adapterId} parser_signal_summary missing_proof=${missingProofExit}`,
				});
				addTask({
					id: gapId,
					parentId: parserSummaryId,
					kind: "gap",
					label: missingProofExit,
					status: "missing-proof-exit",
					evidence: [`missing_proof=${missingProofExit}`, `adapter=${artifact.adapterId}`, `artifact=${path}`],
				});
				addEdge({ from: gapId, to: parserSummaryId, kind: "blocks", label: "missing-proof-exit" });
			}
		}

		if (mission) addEdge({ from: `mission:${mission.id}`, to: adapterId, kind: "requires", label: "runtime-adapter" });
		for (const [index, signal] of artifact.parserSignals.entries()) {
			const signalId = `verify:runtime-adapter:${slug(artifact.adapterId)}:${slug(artifactBase)}:${index + 1}:${slug(signal.ruleId)}`;
			const evidenceRank = signal.evidenceRank ?? "unranked";
			addNode({
				id: signalId,
				kind: "verification",
				label: `${signal.ruleId} => ${signal.proofExitSignal}`,
				status: signal.matches.length ? `rank=${evidenceRank} matches=${signal.matches.length}` : `rank=${evidenceRank} no-match`,
				note: signal.matches.slice(0, 4).join(" | ") || "parser signal did not match runner output",
			});
			addTask({
				id: signalId,
				parentId: artifactId,
				kind: "verification",
				label: `${signal.ruleId} => ${signal.proofExitSignal}`,
				status: signal.matches.length ? `rank=${evidenceRank} matches=${signal.matches.length}` : `rank=${evidenceRank} no-match`,
				evidence: [`rank=${evidenceRank}`, ...signal.matches.slice(0, 6)],
			});
			addEdge({ from: signalId, to: artifactId, kind: "verifies", label: `parser:${evidenceRank}` });
			addEdge({
				from: signalId,
				to: parserSummaryId,
				kind: signal.matches.length ? "supports" : "blocks",
				label: signal.matches.length ? "matched-rule" : "no-match",
			});
		}

		if (artifact.killed || (artifact.exitCode !== null && artifact.exitCode !== 0)) {
			gaps.push(`runtime adapter failed: ${artifact.adapterId} exit=${artifact.exitCode ?? "null"} killed=${artifact.killed}`);
		}
		if (parserMatchCount === 0) gaps.push(`runtime adapter parser no-match: ${artifact.adapterId}`);
	}

	for (const node of evidenceLedgerGraphNodes()) {
		addNode(node);
		if (mission)
			addEdge({ from: `mission:${mission.id}`, to: node.id, kind: "evidences", label: `P${node.priority}` });
	}
	for (const record of parseEvidenceLedgerTaskRecords()) {
		const parentId = mission ? `mission:${mission.id}` : undefined;
		addTask({
			id: record.evidenceId,
			parentId,
			kind: "evidence",
			label: record.title,
			status: `${record.kind}/P${record.priority}`,
			path: record.path,
			evidence: [record.fact, record.confidence].filter((item): item is string => Boolean(item)).slice(0, 3),
			note: record.timestamp,
		});
		if (record.command) {
			const commandId = `command:${record.index}:${slug(record.command)}`;
			addNode({
				id: commandId,
				kind: "command",
				label: truncateMiddle(record.command, 160),
				status: "recorded",
				note: record.title,
			});
			addTask({
				id: commandId,
				parentId: record.evidenceId,
				kind: "command",
				label: truncateMiddle(record.command, 180),
				status: "recorded",
				command: record.command,
			});
			addEdge({ from: commandId, to: record.evidenceId, kind: "produces", label: "stdout/fact" });
		}
		if (record.path) {
			const artifactId = `artifact:${record.index}:${slug(artifactBasename(record.path))}`;
			addNode({
				id: artifactId,
				kind: "artifact",
				label: artifactBasename(record.path),
				status: record.hash ? "hashed" : "referenced",
				path: record.path,
				note: record.hash,
			});
			addTask({
				id: artifactId,
				parentId: record.evidenceId,
				kind: "artifact",
				label: artifactBasename(record.path),
				status: record.hash ? "hashed" : "referenced",
				path: record.path,
				note: record.hash,
			});
			addEdge({ from: record.evidenceId, to: artifactId, kind: "produces", label: "artifact" });
			sourceArtifacts.push(record.path);
		}
		const shouldAddHypothesis =
			record.fact && (evidenceRecordHasHypothesisSignal(record) || evidenceRecordHasCounterSignal(record) || record.command || record.path);
		if (shouldAddHypothesis) {
			const hypothesisId = `hypothesis:${record.index}:${slug(record.title)}`;
			addNode({
				id: hypothesisId,
				kind: "hypothesis",
				label: truncateMiddle(record.fact ?? record.title, 160),
				status: record.confidence ?? "claim",
				note: record.title,
			});
			addTask({
				id: hypothesisId,
				parentId: record.evidenceId,
				kind: "hypothesis",
				label: truncateMiddle(record.fact ?? record.title, 180),
				status: record.confidence ?? "claim",
				evidence: [record.title],
			});
			addEdge({ from: record.evidenceId, to: hypothesisId, kind: "supports", label: `P${record.priority}` });
			if (record.verify) {
				const verifyId = `verify:${record.index}:${slug(record.verify)}`;
				addNode({
					id: verifyId,
					kind: "verification",
					label: truncateMiddle(record.verify, 160),
					status: "required",
					note: record.title,
				});
				addTask({
					id: verifyId,
					parentId: hypothesisId,
					kind: "verification",
					label: truncateMiddle(record.verify, 180),
					status: "required",
					command: record.verify,
				});
				addEdge({ from: verifyId, to: hypothesisId, kind: "verifies", label: "verify command" });
			}
		}
		if (evidenceRecordHasCounterSignal(record)) {
			const counterId = `counter:${record.index}:${slug(record.title)}`;
			addNode({
				id: counterId,
				kind: "counter_evidence",
				label: truncateMiddle(record.fact ?? record.title, 160),
				status: "present",
				note: record.confidence,
			});
			addTask({
				id: counterId,
				parentId: record.evidenceId,
				kind: "counter_evidence",
				label: truncateMiddle(record.fact ?? record.title, 180),
				status: "present",
				evidence: [record.title, record.verify].filter((item): item is string => Boolean(item)),
			});
			const hypothesisId = `hypothesis:${record.index}:${slug(record.title)}`;
			addEdge({ from: counterId, to: hypothesisId, kind: "refutes", label: "counter-evidence" });
		}
	}

	if (mission) {
		const recommended = recommendedToolsForRoute(mission.route).slice(0, 16);
		const missing = recommended
			.map((tool) => createBootstrapPlan([tool])[0])
			.filter((item): item is BootstrapPlan => Boolean(item) && item.known && !item.present)
			.map((item) => item.tool);
		addNode({
			id: "tool:recommended",
			kind: "tool",
			label: recommended.join(", ") || "none",
			status: missing.length ? `missing:${missing.join(",")}` : "ready",
		});
		addEdge({ from: `mission:${mission.id}`, to: "tool:recommended", kind: "requires", label: "tool-index" });
		if (missing.length > 0) gaps.push(`missing recommended tools: ${missing.join(", ")}`);
	}

	const nextActions = attackGraphNextActions(mission, map);
	for (const [index, action] of nextActions.entries()) {
		const id = `next:${index + 1}`;
		addNode({ id, kind: "next", label: action, status: "queued" });
		addTask({
			id,
			parentId: mission ? `mission:${mission.id}` : undefined,
			kind: "next",
			label: action,
			status: "queued",
			command: action,
		});
		if (mission) addEdge({ from: `mission:${mission.id}`, to: id, kind: "suggests" });
	}

	return {
		timestamp,
		missionId: mission?.id,
		route: mission?.route.domain,
		target: map?.target ?? runtimeAdapterArtifacts.find((item) => item.artifact.target)?.artifact.target,
		nodes: [...nodes.values()],
		edges,
		taskTree: taskTree.slice(0, 160),
		criticalPath: criticalPath.length ? criticalPath : ["no mission route selected"],
		gaps: Array.from(new Set(gaps)).slice(0, 24),
		nextActions,
		sourceArtifacts: Array.from(new Set(sourceArtifacts)).slice(0, 24),
	};
}

function writeAttackGraphArtifact(graph: AttackGraphArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceGraphsDir(),
		`${graph.timestamp.replace(/[:.]/g, "-")}-${slug(graph.route ?? "security")}.md`,
	);
	writePrivateTextFile(
		path,
		formatAttackGraphArtifactMarkdown(graph, { truncate: truncateMiddle }),
	);
	const evidence = appendEvidence({
		kind: "artifact",
		title: `attack-graph ${graph.missionId ?? "no-mission"}`,
		fact: `Built operation graph with ${graph.nodes.length} nodes, ${graph.edges.length} edges, ${graph.gaps.length} gap(s), ${graph.nextActions.length} next action(s)`,
		command: "re_graph build",
		path,
		verify: `cat ${path}`,
		confidence: "mission/evidence/tool graph",
	});
	updateMissionCheckpoint("attack_graph_ready", "done", path);
	return `${path}\n${evidence.timestamp} ${evidence.title}`;
}

function buildAttackGraphOutput(action: "build" | "show" = "build"): string {
	if (action === "show") {
		const path = latestAttackGraphArtifactPath();
		if (!path) return "attack_graph:\nstatus: missing\nnext: re_graph build";
		return truncateMiddle(readText(path), 12000);
	}
	const graph = buildAttackGraph();
	const writeResult = writeAttackGraphArtifact(graph);
	const [path] = writeResult.split(/\r?\n/, 1);
	return formatAttackGraph(graph, path);
}

function latestExploitChainArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("exploit_chain", evidenceChainsDir(), options);
}

function exploitChainSourceArtifacts(): string[] {
	return Array.from(
		new Set(
			[
				latestKernelArtifactPath(),
				recentMarkdownArtifacts(evidenceMapsDir(), 1)[0],
				latestLiveBrowserArtifactPath(),
				latestWebAuthzStateArtifactPath(),
				latestNativeRuntimeArtifactPath(),
				latestMobileRuntimeArtifactPath(),
				recentMarkdownArtifacts(evidenceRunsDir(), 2)[0],
				latestAttackGraphArtifactPath(),
				latestCampaignArtifactPath(),
				latestOperationArtifactPath(),
				latestExploitLabArtifactPath(),
				latestVerifierArtifactPath(),
				latestCompilerArtifactPath(),
				latestReplayerArtifactPath(),
				latestAutofixArtifactPath(),
				latestProofLoopArtifactPath(),
				latestKnowledgeGraphArtifactPath(),
			].filter((path): path is string => Boolean(path)),
		),
	);
}

function exploitChainEvidenceLines(paths: string[], pattern: RegExp, limit = 8): string[] {
	return paths
		.flatMap((path) =>
			interestingLines(readText(path), pattern, Math.max(2, limit)).map(
				(line) => `${path}: ${truncateMiddle(line.replace(/\s+/g, " "), 220)}`,
			),
		)
		.slice(0, limit);
}

function buildExploitChain(options: { target?: string; mode?: "plan" | "compose" } = {}): ExploitChainArtifact {
	ensureReconStorage();
	const mission = readCurrentMission();
	const target = options.target ?? mission?.task;
	const route = mission?.route.domain;
	const operatorFeedback = latestOperatorFeedback(target);
	const sourceArtifacts = exploitChainSourceArtifacts();
	const sourceText = sourceArtifacts.map((path) => readText(path)).join("\n");
	const lower = `${route ?? ""}\n${target ?? ""}\n${sourceText}`.toLowerCase();
	const isWeb = /web|api|graphql|jwt|oauth|session|cookie|idor|bola|browser|xhr|websocket|ssrf|xss|sqli/.test(lower);
	const isNative = /native|pwn|elf|rop|libc|gdb|crash|heap|tcache|binary|exploit|poc/.test(lower);
	const isMobile = /mobile|android|apk|frida|adb|jni|smali/.test(lower);
	const active = mission ? activeLane(mission) : undefined;
	const mapEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/passive_map_result|map_artifact|route-auth-search|manifest|binary candidates|url baseline/i,
	);
	const browserEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/live_browser|browser_artifact|request_response_log|auth_matrix|websocket|xhr|storage/i,
	);
	const authzEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/web_authz|principal_matrix|object_probes|sequence_replay|ownership_checks|rollback_checks|IDOR|BOLA/i,
	);
	const nativeEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/native_runtime|mobile_runtime|gdb_trace|crash_plan|mitigation_matrix|loader_libc|frida_hooks|anti_debug|process_map|cyclic|ROP|libc/i,
	);
	const exploitEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/exploit_lab|replay_matrix|success_rate|flake_triage|bundle_manifest|PoC|poc_inventory|stdout_sha256|stderr_sha256/i,
	);
	const verifyEvidence = exploitChainEvidenceLines(
		sourceArtifacts,
		/verifier_matrix|compiler_report|key_evidence_block|repro_commands|knowledge_graph|case_signatures|counter_evidence|contradictions/i,
	);
	const mapNode = exploitChainNode({
		id: "entry-map",
		stage: "entry_surface",
		objective: "从当前 target/workspace 固化入口、路由、配置、二进制候选、URL baseline 和可验证证据面",
		evidence: mapEvidence,
		commands: [`re_map ${target ?? "<target>"} 2`, `re_lane plan ${active?.name ?? "map"} ${target ?? "<target>"}`],
		gaps: mapEvidence.length ? [] : ["missing passive map artifact or route/binary baseline"],
	});
	const runtimeCommands = [
		isWeb ? `re_live_browser plan ${target ?? "<url>"}` : undefined,
		isWeb ? `re_web_authz_state plan ${target ?? "<url>"}` : undefined,
		isNative ? `re_native_runtime plan ${target ?? "<binary>"}` : undefined,
		isMobile ? `re_mobile_runtime plan ${target ?? "<apk-or-package>"}` : undefined,
		!isWeb && !isNative && !isMobile ? `re_lane run ${active?.name ?? "prove"} ${target ?? "<target>"}` : undefined,
	].filter((command): command is string => Boolean(command));
	const runtimeEvidence = [...browserEvidence, ...nativeEvidence];
	const runtimeNode = exploitChainNode({
		id: "runtime-boundary",
		stage: "runtime_boundary",
		objective: "捕获真实运行时边界：请求/会话/状态机、GDB/Frida hook、crash/register 或目标进程行为",
		evidence: runtimeEvidence,
		commands: runtimeCommands,
		gaps: runtimeEvidence.length ? [] : ["missing live runtime/browser/native/mobile artifact"],
		previousDone: mapNode.status === "done",
	});
	const authzNode = exploitChainNode({
		id: "authz-state",
		stage: "authorization_state",
		objective: "把身份、对象所有权、请求顺序、状态回滚和访问边界转成可比较矩阵",
		evidence: authzEvidence,
		commands: isWeb
			? [
					`re_web_authz_state plan ${target ?? "<url>"}`,
					`COOKIE_A=... COOKIE_B=... AUTH_A=... AUTH_B=... re_web_authz_state run ${target ?? "<url>"}`,
				]
			: [`re_lane plan ${active?.name ?? "prove"} ${target ?? "<target>"}`],
		gaps: authzEvidence.length ? [] : ["missing principal/object/sequence/rollback authorization evidence"],
		previousDone: runtimeNode.status === "done" || !isWeb,
	});
	const primitiveNode = exploitChainNode({
		id: "primitive-proof",
		stage: "primitive_or_state_transition",
		objective: isWeb
			? "证明最小可达的授权绕过、对象越权、状态转移或请求重放影响"
			: "证明最小 crash/control/leak/hook/config/credential primitive，并绑定偏移、寄存器、返回值或状态变化",
		evidence: nativeEvidence.length ? nativeEvidence : authzEvidence,
		commands: [
			isNative ? `re_native_runtime run ${target ?? "<binary>"}` : undefined,
			isMobile ? `re_mobile_runtime run ${target ?? "<apk-or-package>"}` : undefined,
			`re_lane run ${active?.name ?? "prove"} ${target ?? "<target>"}`,
		].filter((command): command is string => Boolean(command)),
		gaps: nativeEvidence.length || authzEvidence.length ? [] : ["missing primitive/state-transition proof artifact"],
		previousDone: runtimeNode.status === "done" || authzNode.status === "done",
	});
	const exploitNode = exploitChainNode({
		id: "stability-lab",
		stage: "exploit_reliability",
		objective: "把一次性 PoC/请求/primitive 升级为可重放矩阵、环境 pin、flake triage 和 bundle manifest",
		evidence: exploitEvidence,
		commands: [`re_exploit_lab plan ${target ?? "<poc-or-target>"}`, `re_replayer plan ${target ?? "<target>"}`],
		gaps: exploitEvidence.length ? [] : ["missing exploit_lab/replayer stability evidence"],
		previousDone: primitiveNode.status === "done",
	});
	const verifyNode = exploitChainNode({
		id: "verify-report",
		stage: "verify_compile_report",
		objective:
			"将链路声明绑定到 verifier counter-evidence、compiler key_evidence_block、repro_commands 和 knowledge graph",
		evidence: verifyEvidence,
		commands: [
			"re_verifier matrix",
			"re_compiler draft",
			"re_replayer run",
			"re_proof_loop run",
			"re_knowledge_graph build",
		],
		gaps: verifyEvidence.length ? [] : ["missing verifier/compiler/replayer/proof-loop/knowledge evidence"],
		previousDone: exploitNode.status === "done" || primitiveNode.status === "done",
	});
	const nodes = [mapNode, runtimeNode, authzNode, primitiveNode, exploitNode, verifyNode];
	const edges: ExploitChainEdge[] = [
		{ from: "entry-map", to: "runtime-boundary", kind: "feeds", label: "map selects runtime surface" },
		{
			from: "runtime-boundary",
			to: "authz-state",
			kind: "requires",
			label: "runtime requests/session feed authz matrix",
		},
		{
			from: "authz-state",
			to: "primitive-proof",
			kind: "proves",
			label: "state/object diff proves candidate impact",
		},
		{
			from: "primitive-proof",
			to: "stability-lab",
			kind: "stabilizes",
			label: "primitive becomes replayable PoC/lab matrix",
		},
		{
			from: "stability-lab",
			to: "verify-report",
			kind: "verifies",
			label: "replay/lab evidence feeds final assertions",
		},
	];
	const evidenceGaps = [
		...nodes.flatMap((node) => node.gaps.map((gap) => `${node.id}: ${gap}`)),
		...operatorFeedback.rows
			.filter((row) => !/category=(strong_evidence|worker_retry_progress)/i.test(row))
			.map((row) => `operator_feedback: ${row}`),
	].slice(0, 48);
	const firstOpen = nodes.find((node) => node.status !== "done");
	const replayCommands = Array.from(
		new Set([
			...(firstOpen?.commands ?? []),
			"re_verifier matrix",
			"re_compiler draft",
			"re_replayer run",
			"re_exploit_lab run <poc-or-target>",
			...operatorFeedback.commands,
		]),
	).slice(0, 12);
	const operatorQueue = Array.from(
		new Set([
			...operatorFeedback.commands,
			...nodes.filter((node) => node.status !== "done").flatMap((node) => node.next),
			"re_graph build",
			`re_chain compose ${target ?? "<target>"}`,
			"re_operator plan",
		]),
	).slice(0, 16);
	const doneNodes = nodes.filter((node) => node.status === "done").map((node) => node.id);
	const proofPath = [
		...doneNodes,
		...(operatorFeedback.rows.length ? [`operator-feedback:${operatorFeedback.rows.length}`] : []),
		...(firstOpen ? [`next:${firstOpen.id}`] : ["complete:verify-report"]),
	];
	const exploitPath = [
		"entry_surface",
		isWeb
			? "request/session capture"
			: isMobile
				? "mobile runtime hook"
				: isNative
					? "native primitive"
					: "runtime proof",
		isWeb ? "authz/object/state diff" : "control/leak/config primitive",
		"bounded replay / exploit lab",
		"verifier/compiler/replayer evidence",
	];
	const confidence =
		verifyNode.status === "done" && exploitNode.status === "done"
			? "strong"
			: nodes.filter((node) => node.status === "done").length >= 3
				? "partial"
				: "scaffold";
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route,
		target,
		mode: options.mode ?? "plan",
		nodes,
		edges,
		proofPath,
		exploitPath,
		evidenceGaps,
		operatorFeedback: operatorFeedback.rows,
		operatorFeedbackQueue: operatorFeedback.commands,
		replayCommands,
		operatorQueue,
		nextActions: operatorQueue.slice(0, 8),
		sourceArtifacts: Array.from(new Set([...sourceArtifacts, ...operatorFeedback.sourceArtifacts])).slice(0, 72),
		confidence,
	};
}

function writeExploitChainArtifact(chain: ExploitChainArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceChainsDir(),
		`${chain.timestamp.replace(/[:.]/g, "-")}-${slug(chain.route ?? "chain")}-${chain.mode}.md`,
	);
	// Atomic temp+rename (0o600): the artifact is read back via readText on
	// evidence-chain recall; a torn writeFileSync would surface truncated markdown
	// to selectRepiScopedMarkdownArtifacts with no error. Matches #43/#103.
	writePrivateTextFile(path, formatExploitChainArtifactMarkdown(chain));
	appendEvidence({
		kind: "artifact",
		title: `exploit-chain ${chain.mode}`,
		fact: `Composed exploit chain with ${chain.nodes.length} nodes, ${chain.evidenceGaps.length} evidence gap(s), operator_feedback=${chain.operatorFeedback.length}, confidence=${chain.confidence}`,
		path,
		command: `re_chain ${chain.mode}${chain.target ? ` ${chain.target}` : ""}`,
		confidence: chain.confidence,
	});
	updateMissionCheckpoint("exploit_chain_ready", "done", path);
	return path;
}

function buildExploitChainOutput(
	action: "plan" | "show" | "compose" = "plan",
	options: { target?: string } = {},
): string {
	if (action === "show") {
		const path = latestExploitChainArtifactPath();
		if (!path) return "exploit_chain:\nstatus: missing\nnext: re_chain plan <target>";
		return truncateMiddle(readText(path), 22000);
	}
	const chain = buildExploitChain({ target: options.target, mode: action === "compose" ? "compose" : "plan" });
	const path = writeExploitChainArtifact(chain);
	return formatExploitChain(chain, path);
}

function latestCampaignArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("campaign", evidenceCampaignsDir(), options);
}

function textHasAny(text: string, patterns: RegExp[]): boolean {
	return patterns.some((pattern) => pattern.test(text));
}

function matchingLaneNames(mission: MissionState | undefined, patterns: RegExp[]): string[] {
	if (!mission) return [];
	return mission.lanes
		.filter((lane) =>
			patterns.some((pattern) => pattern.test(`${lane.name}\n${lane.objective}\n${lane.next.join("\n")}`)),
		)
		.map((lane) => lane.name);
}

function phaseDoneFromLanes(mission: MissionState | undefined, lanes: string[]): boolean {
	if (!mission || lanes.length === 0) return false;
	return lanes.every((name) => mission.lanes.find((lane) => lane.name === name)?.status === "done");
}

function buildCampaignPhases(
	mission: MissionState | undefined,
	map: PassiveMapContext | undefined,
	target: string | undefined,
	toolGaps: string[],
	sourceArtifacts: string[],
): CampaignPhase[] {
	const taskText = [mission?.task, mission?.route.domain, target, map?.target, ...(map?.signals ?? [])].join("\n");
	const targetRef = target ?? map?.target ?? "<target>";
	const mkPhase = (
		name: string,
		objective: string,
		route: string,
		relevant: boolean,
		requiredEvidence: string[],
		lanePatterns: RegExp[],
		nextActions: string[],
		phaseToolGaps: string[] = toolGaps,
	): CampaignPhase | undefined => {
		if (!mission && name !== "recon-map") return undefined;
		if (!relevant && name !== "report-audit") return undefined;
		const candidateLanes = matchingLaneNames(mission, lanePatterns);
		const status: CampaignPhaseStatus = !mission
			? "blocked"
			: name === "recon-map" && map
				? "done"
				: phaseDoneFromLanes(mission, candidateLanes)
					? "done"
					: relevant
						? "ready"
						: "pending";
		return {
			name,
			objective,
			route,
			status,
			requiredEvidence,
			candidateLanes,
			nextActions,
			toolGaps: phaseToolGaps.slice(0, 10),
			sourceArtifacts: sourceArtifacts.slice(0, 10),
		};
	};
	const phases = [
		mkPhase(
			"recon-map",
			"建立目标/工作区被动地图，确认入口、配置、路由、二进制/样本/云身份与证据面",
			mission?.route.domain ?? "Security routing",
			true,
			["passive map artifact", "tool index", "target fingerprint"],
			[/map|surface|triage|inventory|identity/i],
			[`re_decision_core tick ${targetRef}`, `re_map ${targetRef} 3`, "re_tool_index refresh", "re_graph build"],
		),
		mkPhase(
			"web-authz",
			"把 Web/API/GraphQL/WebSocket 的认证、授权、对象所有权和状态转换证明成可 replay 的最小路径",
			"Web / API pentest",
			mission?.route.domain === "Web / API pentest" ||
				textHasAny(taskText, [/\bapi\b|websocket|graphql|jwt|oauth|idor|bola|session|cookie|csrf/i]),
			["browser/XHR/WS capture", "auth matrix", "IDOR/BOLA or authz-state evidence", "replay command"],
			[/surface|state|poc|auth|web|api/i],
			[
				`re_live_browser plan ${targetRef}`,
				`re_web_authz_state plan ${targetRef}`,
				`re_lane plan surface ${targetRef}`,
				`re_lane run surface ${targetRef}`,
				`re_lane plan state ${targetRef}`,
				`re_web_authz_state run ${targetRef} 9000`,
				"re_graph build",
			],
		),
		mkPhase(
			"credential-identity",
			"验证 cookie/JWT/API key/ticket/hash/serviceaccount 的可用性、作用域、过期和可转移边界",
			"Identity / credentials",
			mission?.route.domain === "Identity / Windows / AD" ||
				textHasAny(taskText, [
					/credential|凭据|token|jwt|cookie|kerberos|ntlm|ldap|spn|ticket|hash|serviceaccount/i,
				]),
			["credential inventory", "usable credential proof", "principal/scope evidence", "negative control"],
			[/credential|principal|identity|state|metadata/i],
			[
				`re_lane plan credentials ${targetRef}`,
				`re_lane run credentials ${targetRef}`,
				`re_lane plan principals ${targetRef}`,
			],
		),
		mkPhase(
			"cloud-container",
			"从运行配置、serviceaccount、metadata、IAM/RBAC 到最小 privilege edge 组织云/容器 pivot",
			"Cloud / container",
			mission?.route.domain === "Cloud / container" ||
				textHasAny(taskText, [
					/cloud|aws|azure|gcp|metadata|k8s|kubernetes|docker|container|rbac|iam|serviceaccount/i,
				]),
			["runtime config", "cloud identity", "metadata probe", "privilege edge"],
			[/identity|runtime-config|metadata|privilege|cloud|container/i],
			[
				`re_lane plan identity ${targetRef}`,
				`re_lane run identity ${targetRef}`,
				`re_lane plan privilege ${targetRef}`,
			],
		),
		mkPhase(
			"pwn-exploit",
			"把二进制/服务崩溃面推进到 primitive、leak、payload、稳定性和本地/远程一致性验证",
			"Pwn / exploit",
			mission?.route.domain === "Pwn / exploit" ||
				mission?.route.domain === "Exploit reliability" ||
				textHasAny(taskText, [/pwn|exploit|rop|heap|ret2libc|crash|primitive|autopwn|poc/i]),
			["mitigation fingerprint", "crash/control primitive", "offset/leak", "local verifier or replay matrix"],
			[/mitigation|primitive|exploit|replay|inventory|normalize|flake|bundle/i],
			[
				`re_lane plan primitive ${targetRef}`,
				`re_lane run primitive ${targetRef}`,
				`re_lane plan replay ${targetRef}`,
			],
		),
		mkPhase(
			"agentsec-boundary",
			"映射 prompt/tool/memory/RAG/MCP/sub-agent 边界并生成注入 replay harness 与隔离证据",
			"Agent / LLM boundary",
			mission?.route.domain === "Agent / LLM boundary" ||
				textHasAny(taskText, [/agent|llm|prompt injection|tool boundary|memory poisoning|mcp|rag|delegation/i]),
			["prompt surface", "tool schema/exec boundary", "memory poisoning path", "injection replay transcript"],
			[/surface|tool-boundary|memory|injection|delegation/i],
			[
				`re_lane plan surface ${targetRef}`,
				`re_lane run surface ${targetRef}`,
				`re_lane plan injection ${targetRef}`,
			],
		),
		mkPhase(
			"firmware-pcap-dfir",
			"串联固件/rootfs、PCAP/DFIR、恶意样本 IOC/config 与 transform chain 的证据链",
			"Firmware / PCAP / DFIR / Malware",
			mission?.route.domain === "Firmware / IoT" ||
				mission?.route.domain === "DFIR / PCAP / stego" ||
				mission?.route.domain === "Malware analysis" ||
				textHasAny(taskText, [/firmware|iot|rootfs|pcap|dfir|forensic|malware|ioc|yara|c2|binwalk|tshark/i]),
			[
				"image/pcap/sample fingerprint",
				"extracted artifact",
				"config/IOC or flow timeline",
				"transform/decode chain",
			],
			[/inventory|extract|filesystem|services|emulate|map|timeline|triage|static-config|behavior|decode/i],
			[`re_lane plan inventory ${targetRef}`, `re_lane run inventory ${targetRef}`, `re_lane plan map ${targetRef}`],
		),
		mkPhase(
			"report-audit",
			"收敛 campaign 证据、attack graph、复现命令、风险/影响、失败路线和下一步",
			mission?.route.domain ?? "Security reporting",
			true,
			["attack graph", "campaign artifact", "evidence ledger", "completion audit", "report scaffold"],
			[/report|bundle|writeup/i],
			["re_decision_core tick", "re_graph build", "re_campaign show", "re_complete audit", "re_complete scaffold"],
			[],
		),
	].filter((phase): phase is CampaignPhase => Boolean(phase));
	return phases;
}

function campaignPivotCandidates(
	mission: MissionState | undefined,
	phases: CampaignPhase[],
	map: PassiveMapContext | undefined,
): string[] {
	const text = [
		mission?.task,
		mission?.route.domain,
		map?.signals.join("\n"),
		phases.map((phase) => phase.name).join(" "),
	].join("\n");
	const pivots: string[] = [];
	if (textHasAny(text, [/jwt|cookie|session|oauth|api key|token/i]))
		pivots.push(
			"web-authz → credential-identity: reuse token/cookie/API key only after scope and negative-control proof",
		);
	if (textHasAny(text, [/websocket|ws\b|graphql|api/i]))
		pivots.push(
			"web-authz → replay/state machine: capture request order, WS frames, storage and auth matrix before PoC expansion",
		);
	if (textHasAny(text, [/cloud|k8s|metadata|serviceaccount|iam|rbac/i]))
		pivots.push(
			"credential-identity → cloud-container: test serviceaccount/metadata/IAM/RBAC as a minimal privilege edge",
		);
	if (textHasAny(text, [/pwn|exploit|binary|elf|rop|crash/i]))
		pivots.push("pwn-exploit → exploit reliability: convert primitive into replay matrix and artifact bundle");
	if (textHasAny(text, [/firmware|pcap|malware|ioc|dfir/i]))
		pivots.push(
			"firmware-pcap-dfir → credential-identity: extract secrets/IOCs/flows and verify usability separately",
		);
	if (textHasAny(text, [/agent|prompt|mcp|memory|tool/i]))
		pivots.push(
			"agentsec-boundary → evidence ledger: separate untrusted content injection from trusted tool outputs",
		);
	if (pivots.length === 0) pivots.push("recon-map → active lane: prove one end-to-end path before lateral expansion");
	return Array.from(new Set(pivots)).slice(0, 12);
}

function campaignEvidenceGaps(
	mission: MissionState | undefined,
	map: PassiveMapContext | undefined,
	graph: AttackGraphArtifact,
	phases: CampaignPhase[],
): string[] {
	const gaps: string[] = [];
	if (!mission) gaps.push("no active mission");
	if (!map) gaps.push("no passive map artifact");
	if (recentMarkdownArtifacts(evidenceRunsDir(), 3).length === 0) gaps.push("no recent lane run artifact");
	for (const phase of phases) {
		if (phase.status === "ready")
			gaps.push(`phase ready but unproven: ${phase.name} requires ${phase.requiredEvidence.join(", ")}`);
		if (phase.status === "blocked") gaps.push(`phase blocked: ${phase.name}`);
	}
	for (const gap of graph.gaps) gaps.push(`attack_graph: ${gap}`);
	return Array.from(new Set(gaps)).slice(0, 28);
}

function buildCampaign(options: { target?: string; task?: string } = {}): CampaignArtifact {
	ensureReconStorage();
	let mission = readCurrentMission();
	if (!mission && options.task?.trim()) {
		mission = writeCurrentMission(createMission(options.task.trim(), routeReconTask(options.task.trim())));
	}
	const map = latestPassiveMapContext();
	const target = options.target?.trim() || (mission ? inferTargetFromMap(map, mission) : undefined) || map?.target;
	const graph = buildAttackGraph();
	const graphWriteResult = writeAttackGraphArtifact(graph);
	const [graphPath] = graphWriteResult.split(/\r?\n/, 1);
	mission = readCurrentMission() ?? mission;
	const recommended = mission ? recommendedToolsForRoute(mission.route).slice(0, 24) : ["rg", "python3", "curl"];
	const missing = recommended
		.map((tool) => createBootstrapPlan([tool])[0])
		.filter((item): item is BootstrapPlan => Boolean(item) && item.known && !item.present)
		.map((item) => item.tool);
	const sourceArtifacts = Array.from(
		new Set(
			[
				map?.path,
				graphPath,
				...recentMarkdownArtifacts(evidenceRunsDir(), 8),
				...recentMarkdownArtifacts(evidenceGraphsDir(), 2),
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 24);
	const phases = buildCampaignPhases(mission, map, target, missing, sourceArtifacts);
	const pivots = campaignPivotCandidates(mission, phases, map);
	const gaps = campaignEvidenceGaps(mission, map, graph, phases);
	const targetRef = target ?? "<target>";
	const nextActions = Array.from(
		new Set(
			[
				!map ? `re_map ${targetRef} 3` : undefined,
				"re_graph build",
				...phases.flatMap((phase) => phase.nextActions).slice(0, 10),
				missing.length ? `re_bootstrap plan ${missing.slice(0, 10).join(" ")}` : undefined,
				"re_complete audit",
			].filter((item): item is string => Boolean(item)),
		),
	).slice(0, 16);
	return {
		timestamp: new Date().toISOString(),
		missionId: mission?.id,
		route: mission?.route.domain,
		target,
		phases,
		pivots,
		gaps,
		toolGaps: Array.from(new Set(missing)).slice(0, 16),
		nextActions,
		nextBootstrapCommand: missing.length ? `re_bootstrap plan ${missing.slice(0, 12).join(" ")}` : "none",
		sourceArtifacts,
	};
}

function formatCampaign(campaign: CampaignArtifact, path?: string): string {
	return [
		"campaign_graph:",
		path ? `campaign_artifact: ${path}` : undefined,
		`timestamp: ${campaign.timestamp}`,
		`mission_id: ${campaign.missionId ?? "none"}`,
		`route: ${campaign.route ?? "none"}`,
		`target: ${campaign.target ?? "<none>"}`,
		"phases:",
		...campaign.phases.flatMap((phase) => [
			`- ${phase.name} [${phase.status}] route=${phase.route}`,
			`  objective: ${phase.objective}`,
			`  candidate_lanes: ${phase.candidateLanes.length ? phase.candidateLanes.join(", ") : "none"}`,
			`  required_evidence: ${phase.requiredEvidence.join(", ")}`,
			`  next_actions: ${phase.nextActions.join(" | ")}`,
			`  tool_gaps: ${phase.toolGaps.length ? phase.toolGaps.join(", ") : "none"}`,
		]),
		"pivot_candidates:",
		...(campaign.pivots.length ? campaign.pivots.map((item) => `- ${item}`) : ["- none"]),
		"evidence_gaps:",
		...(campaign.gaps.length ? campaign.gaps.map((item) => `- ${item}`) : ["- none"]),
		"tool_gaps:",
		...(campaign.toolGaps.length ? campaign.toolGaps.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(campaign.nextActions.length ? campaign.nextActions.map((item) => `- ${item}`) : ["- none"]),
		`next_bootstrap_command: ${campaign.nextBootstrapCommand}`,
		"source_artifacts:",
		...(campaign.sourceArtifacts.length ? campaign.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeCampaignArtifact(campaign: CampaignArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceCampaignsDir(),
		`${campaign.timestamp.replace(/[:.]/g, "-")}-${slug(campaign.route ?? "campaign")}.md`,
	);
	writePrivateTextFile(
		path,
		[
			"# REPI Campaign Artifact",
			"",
			formatCampaign(campaign, path),
			"",
			"## Phases",
			"",
			...campaign.phases.map(
				(phase) =>
					`- ${phase.name} status=${phase.status} route=${phase.route} lanes=${phase.candidateLanes.join(",") || "none"} evidence=${phase.requiredEvidence.join(";")}`,
			),
			"",
			"## Pivots",
			"",
			...campaign.pivots.map((item) => `- ${item}`),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(campaign, null, 2),
			"```",
			"",
		].join("\n"),
	);
	appendEvidence({
		kind: "artifact",
		title: `campaign-plan ${campaign.missionId ?? "no-mission"}`,
		fact: `Built campaign graph with ${campaign.phases.length} phase(s), ${campaign.pivots.length} pivot(s), ${campaign.gaps.length} evidence gap(s), ${campaign.toolGaps.length} tool gap(s)`,
		command: "re_campaign plan",
		path,
		verify: `cat ${path}`,
		confidence: "mission/map/run/evidence/attack-graph campaign",
	});
	updateMissionCheckpoint("campaign_plan_ready", "done", path);
	return path;
}

function buildCampaignOutput(
	action: "plan" | "show" = "plan",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestCampaignArtifactPath();
		if (!path) return "campaign_graph:\nstatus: missing\nnext: re_campaign plan";
		return truncateMiddle(readText(path), 14000);
	}
	const campaign = buildCampaign(options);
	const path = writeCampaignArtifact(campaign);
	return formatCampaign(campaign, path);
}

function latestOperationArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("operation", evidenceOperationsDir(), options);
}

function parseCampaignArtifact(path: string): CampaignArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as CampaignArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildCampaign(options: { target?: string; task?: string } = {}): {
	campaign: CampaignArtifact;
	path: string;
} {
	const latest = !options.target && !options.task ? latestCampaignArtifactPath() : undefined;
	if (latest) {
		const campaign = parseCampaignArtifact(latest);
		if (campaign) return { campaign, path: latest };
	}
	const campaign = buildCampaign(options);
	const path = writeCampaignArtifact(campaign);
	return { campaign, path };
}

function operationCommandConcrete(command: string, target?: string): { command: string; blocked?: string } {
	const targetText = target?.trim();
	if (/<target>|<TARGET>|<URL>|<none>/i.test(command)) {
		if (!targetText) return { command, blocked: "target placeholder is unresolved" };
		return { command: command.replace(/<target>|<TARGET>|<URL>|<none>/gi, targetText) };
	}
	return { command };
}

function buildOperation(options: { target?: string; task?: string; mode?: "plan" | "run" } = {}): OperationArtifact {
	ensureReconStorage();
	const { campaign, path: campaignArtifact } = latestOrBuildCampaign(options);
	const seen = new Set<string>();
	const steps: OperationStep[] = [];
	const addStep = (phase: CampaignPhase, command: string) => {
		const normalized = command.trim();
		if (!normalized || seen.has(`${phase.name}:${normalized}`)) return;
		seen.add(`${phase.name}:${normalized}`);
		const concrete = operationCommandConcrete(normalized, options.target ?? campaign.target);
		steps.push({
			id: `op:${steps.length + 1}:${slug(phase.name)}`,
			phase: phase.name,
			command: concrete.command,
			status: phase.status === "done" ? "done" : concrete.blocked ? "blocked" : "ready",
			reason: concrete.blocked ?? (phase.status === "done" ? "campaign phase already done" : undefined),
			sourceArtifacts: phase.sourceArtifacts,
		});
	};
	for (const phase of campaign.phases) {
		for (const command of phase.nextActions) addStep(phase, command);
	}
	const blocked = steps
		.filter((step) => step.status === "blocked")
		.map((step) => `${step.id} ${step.command}${step.reason ? ` — ${step.reason}` : ""}`);
	const nextActions = steps
		.filter((step) => step.status === "ready")
		.slice(0, 10)
		.map((step) => `re_operation run ${campaign.target ?? options.target ?? "<target>"} 1 # ${step.id}`);
	return {
		timestamp: new Date().toISOString(),
		missionId: campaign.missionId,
		route: campaign.route,
		target: options.target ?? campaign.target,
		campaignArtifact,
		mode: options.mode ?? "plan",
		steps,
		executed: [],
		blocked,
		nextActions,
		sourceArtifacts: Array.from(new Set([campaignArtifact, ...campaign.sourceArtifacts])).slice(0, 28),
	};
}

function formatOperation(operation: OperationArtifact, path?: string): string {
	return [
		"operation_queue:",
		path ? `operation_artifact: ${path}` : undefined,
		`timestamp: ${operation.timestamp}`,
		`mode: ${operation.mode}`,
		`mission_id: ${operation.missionId ?? "none"}`,
		`route: ${operation.route ?? "none"}`,
		`target: ${operation.target ?? "<none>"}`,
		`campaign_artifact: ${operation.campaignArtifact ?? "none"}`,
		"phase_runner:",
		"- internal_dispatch: re_kernel | re_decision_core plan/tick/run | re_map | re_live_browser plan/run | re_web_authz_state plan/run | re_tool_index refresh | re_lane plan/run/run-auto | re_graph build | re_chain plan/compose | re_campaign plan/show | re_bootstrap plan | re_verifier/re_compiler/re_replayer/re_autofix/re_proof_loop/re_knowledge_graph | re_complete audit/scaffold",
		"steps:",
		...(operation.steps.length
			? operation.steps.map(
					(step) =>
						`- ${step.id} [${step.status}] phase=${step.phase} command=${step.command}${step.reason ? ` reason=${step.reason}` : ""}`,
				)
			: ["- none"]),
		`executed_steps: ${operation.executed.length}`,
		...(operation.executed.length
			? operation.executed.map(
					(item) =>
						`- ${item.stepId} [${item.status}] ${item.command} :: ${truncateMiddle(item.output.replace(/\s+/g, " "), 260)}`,
				)
			: []),
		"blocked:",
		...(operation.blocked.length ? operation.blocked.map((item) => `- ${item}`) : ["- none"]),
		"operator_next_actions:",
		...(operation.nextActions.length ? operation.nextActions.map((item) => `- ${item}`) : ["- re_complete audit"]),
		`next_operation_command: re_operation run ${operation.target ?? "<target>"} 1`,
		"source_artifacts:",
		...(operation.sourceArtifacts.length ? operation.sourceArtifacts.map((item) => `- ${item}`) : ["- none"]),
	]
		.filter(Boolean)
		.join("\n");
}

function writeOperationArtifact(operation: OperationArtifact): string {
	ensureReconStorage();
	const path = join(
		evidenceOperationsDir(),
		`${operation.timestamp.replace(/[:.]/g, "-")}-${slug(operation.route ?? "operation")}-${operation.mode}.md`,
	);
	writePrivateTextFile(
		path,
		[
			"# REPI Operation Artifact",
			"",
			formatOperation(operation, path),
			"",
			"## Executed",
			"",
			...(operation.executed.length
				? operation.executed.map((item) => `- ${item.stepId} status=${item.status} command=${item.command}`)
				: ["- none"]),
			"",
			"## JSON",
			"",
			"```json",
			JSON.stringify(operation, null, 2),
			"```",
			"",
		].join("\n"),
	);
	appendEvidence({
		kind: "artifact",
		title: `operation-${operation.mode} ${operation.missionId ?? "no-mission"}`,
		fact: `Built operation queue with ${operation.steps.length} step(s), ${operation.executed.length} executed, ${operation.blocked.length} blocked`,
		command: `re_operation ${operation.mode}`,
		path,
		verify: `cat ${path}`,
		confidence: "campaign/phase-runner operation queue",
	});
	updateMissionCheckpoint("operation_queue_ready", "done", path);
	return path;
}

async function executeOperationStep(
	pi: ExtensionAPI,
	step: OperationStep,
	target?: string,
): Promise<OperationExecution> {
	const command = step.command.trim();
	const done = (output: string): OperationExecution => ({ stepId: step.id, command, status: "done", output });
	const blocked = (output: string): OperationExecution => ({ stepId: step.id, command, status: "blocked", output });
	if (/<target>|<TARGET>|<URL>|<none>/i.test(command)) return blocked("unresolved target placeholder");
	const decisionMatch = /^re[-_]decision[-_]core\s+(plan|tick|run)\b(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (decisionMatch) {
		const action = decisionMatch[1] as "plan" | "tick" | "run";
		const decisionTarget = decisionMatch[2]?.trim() || target;
		const maxSteps = decisionMatch[3] ? Number(decisionMatch[3]) : 1;
		return done(
			action === "run"
				? await runDecisionCore(pi, { target: decisionTarget, maxSteps })
				: buildDecisionCoreOutput(action, { target: decisionTarget }),
		);
	}
	const laneMatch = /^re_lane\s+(plan|run|run-auto)\s+(\S+)(?:\s+(.+))?$/i.exec(command);
	if (laneMatch) {
		const action = laneMatch[1] as "plan" | "run" | "run-auto";
		const laneName = laneMatch[2];
		const laneTarget = laneMatch[3]?.trim() || target;
		if (action === "run-auto")
			return done(await runAutoLaneChain(pi, { lane: laneName, target: laneTarget, maxSteps: 1 }));
		const mission =
			readCurrentMission() ?? writeCurrentMission(createMission("manual mission", routeReconTask("reverse/pentest task")));
		const lane = activeLane(mission, laneName);
		if (!lane) return blocked(`lane not found: ${laneName}`);
		updateMissionCheckpoint("repro_commands_ready", "done", `operation:${step.id}:${lane.name}`);
		const pack = laneCommandPack(mission, lane, laneTarget);
		if (action === "plan") return done(formatLaneCommandPack(pack));
		return done(await runLaneCommandPack(pi, pack));
	}
	if (/^re_map\b/i.test(command)) {
		const parts = command.split(/\s+/).slice(1);
		const last = parts.at(-1);
		const depth = last && /^\d+$/.test(last) ? Number(parts.pop()) : undefined;
		const mapTarget = parts.join(" ") || target;
		return done(await runPassiveMap(pi, { target: mapTarget, depth }));
	}
	const kernelMatch = /^re[-_]kernel(?:\s+(build|show|audit))?(?:\s+(.+))?$/i.exec(command);
	if (kernelMatch)
		return done(
			buildKernelOutput((kernelMatch[1] as "build" | "show" | "audit") ?? "build", {
				target: kernelMatch[2]?.trim() || target,
			}),
		);
	const liveBrowserMatch = /^re[-_]live[-_]browser\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (liveBrowserMatch) {
		const action = (liveBrowserMatch[1] as "plan" | "show" | "run") ?? "plan";
		const browserTarget = liveBrowserMatch[2]?.trim() || target;
		const timeoutMs = liveBrowserMatch[3] ? Number(liveBrowserMatch[3]) : undefined;
		return done(
			action === "run"
				? await runLiveBrowser(pi, { target: browserTarget, timeoutMs })
				: buildLiveBrowserOutput(action, { target: browserTarget, timeoutMs }),
		);
	}
	const webAuthzStateMatch = /^re[-_]web[-_]authz[-_]state\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(
		command,
	);
	if (webAuthzStateMatch) {
		const action = (webAuthzStateMatch[1] as "plan" | "show" | "run") ?? "plan";
		const authzTarget = webAuthzStateMatch[2]?.trim() || target;
		const timeoutMs = webAuthzStateMatch[3] ? Number(webAuthzStateMatch[3]) : undefined;
		return done(
			action === "run"
				? await runWebAuthzState(pi, { target: authzTarget, timeoutMs })
				: buildWebAuthzStateOutput(action, { target: authzTarget, timeoutMs }),
		);
	}
	const mobileRuntimeMatch =
		/^re[-_]mobile[-_]runtime\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+([A-Za-z][\w]*(?:\.[A-Za-z][\w]*){1,}))?(?:\s+(\d+))?$/i.exec(
			command,
		);
	if (mobileRuntimeMatch) {
		const action = (mobileRuntimeMatch[1] as "plan" | "show" | "run") ?? "plan";
		const mobileTarget = mobileRuntimeMatch[2]?.trim() || target;
		const packageName = mobileRuntimeMatch[3]?.trim();
		const timeoutMs = mobileRuntimeMatch[4] ? Number(mobileRuntimeMatch[4]) : undefined;
		return done(
			action === "run"
				? await runMobileRuntime(pi, { target: mobileTarget, packageName, timeoutMs })
				: buildMobileRuntimeOutput(action, { target: mobileTarget, packageName, timeoutMs }),
		);
	}
	const nativeRuntimeMatch = /^re[-_]native[-_]runtime\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (nativeRuntimeMatch) {
		const action = (nativeRuntimeMatch[1] as "plan" | "show" | "run") ?? "plan";
		const nativeTarget = nativeRuntimeMatch[2]?.trim() || target;
		const timeoutMs = nativeRuntimeMatch[3] ? Number(nativeRuntimeMatch[3]) : undefined;
		return done(
			action === "run"
				? await runNativeRuntime(pi, { target: nativeTarget, timeoutMs })
				: buildNativeRuntimeOutput(action, { target: nativeTarget, timeoutMs }),
		);
	}
	const exploitLabMatch =
		/^re[-_]exploit[-_]lab\s+(plan|show|run|bundle)?(?:\s+(.+?))?(?:\s+(\d+))?(?:\s+(\d+))?$/i.exec(command);
	if (exploitLabMatch) {
		const action = (exploitLabMatch[1] as "plan" | "show" | "run" | "bundle") ?? "plan";
		const labTarget = exploitLabMatch[2]?.trim() || target;
		const runs = exploitLabMatch[3] ? Number(exploitLabMatch[3]) : undefined;
		const timeoutMs = exploitLabMatch[4] ? Number(exploitLabMatch[4]) : undefined;
		return done(
			action === "run"
				? await runExploitLab(pi, { target: labTarget, runs, timeoutMs })
				: buildExploitLabOutput(action, { target: labTarget, runs, timeoutMs }),
		);
	}
	if (/^re_tool_index\s+refresh$/i.test(command) || /^re-tools\s+refresh$/i.test(command)) {
		return done(await refreshToolIndex(pi));
	}
	if (/^re_graph\s+build$/i.test(command)) return done(buildAttackGraphOutput("build"));
	if (/^re[-_](?:exploit[-_])?chain\s+(plan|compose)\b/i.test(command)) {
		const action = /^re[-_](?:exploit[-_])?chain\s+compose\b/i.test(command) ? "compose" : "plan";
		const chainTarget = command.replace(/^re[-_](?:exploit[-_])?chain\s+(?:plan|compose)\b/i, "").trim() || target;
		return done(buildExploitChainOutput(action, { target: chainTarget }));
	}
	if (/^re_campaign\s+show$/i.test(command)) return done(buildCampaignOutput("show"));
	if (/^re_campaign\s+plan\b/i.test(command)) return done(buildCampaignOutput("plan", { target }));
	const verifierMatch = /^re[-_]verifier\s+(check|show|matrix)?(?:\s+(.+))?$/i.exec(command);
	if (verifierMatch)
		return done(
			buildVerifierOutput((verifierMatch[1] as "check" | "show" | "matrix") ?? "check", {
				target: verifierMatch[2]?.trim() || target,
			}),
		);
	const compilerMatch = /^re[-_]compiler\s+(draft|show|final)?(?:\s+(.+))?$/i.exec(command);
	if (compilerMatch)
		return done(
			buildCompilerOutput((compilerMatch[1] as "draft" | "show" | "final") ?? "draft", {
				target: compilerMatch[2]?.trim() || target,
			}),
		);
	const replayerMatch = /^re[-_]replayer\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?$/i.exec(command);
	if (replayerMatch) {
		const action = (replayerMatch[1] as "plan" | "show" | "run") ?? "plan";
		const replayTarget = replayerMatch[2]?.trim() || target;
		const maxSteps = replayerMatch[3] ? Number(replayerMatch[3]) : undefined;
		return done(
			action === "run"
				? await runReplayer(pi, { target: replayTarget, maxSteps })
				: buildReplayerOutput(action, { target: replayTarget }),
		);
	}
	const autofixMatch = /^re[-_]autofix\s+(plan|show|apply)?(?:\s+(.+))?$/i.exec(command);
	if (autofixMatch)
		return done(
			buildAutofixOutput((autofixMatch[1] as "plan" | "show" | "apply") ?? "plan", {
				target: autofixMatch[2]?.trim() || target,
			}),
		);
	const proofLoopMatch = /^re[-_]proof[-_]loop\s+(plan|show|run)?(?:\s+(.+?))?(?:\s+(\d+))?(?:\s+(\d+))?$/i.exec(
		command,
	);
	if (proofLoopMatch) {
		const action = (proofLoopMatch[1] as "plan" | "show" | "run") ?? "plan";
		const loopTarget = proofLoopMatch[2]?.trim() || target;
		const maxSteps = proofLoopMatch[3] ? Number(proofLoopMatch[3]) : undefined;
		const replaySteps = proofLoopMatch[4] ? Number(proofLoopMatch[4]) : undefined;
		return done(
			action === "run"
				? await runProofLoop(pi, { target: loopTarget, maxSteps, replaySteps })
				: buildProofLoopOutput(action, { target: loopTarget, maxSteps, replaySteps }),
		);
	}
	const knowledgeMatch = /^re[-_]knowledge(?:[-_]graph)?\s+(build|show|query)?(?:\s+(.+))?$/i.exec(command);
	if (knowledgeMatch)
		return done(
			buildKnowledgeGraphOutput((knowledgeMatch[1] as "build" | "show" | "query") ?? "build", {
				target,
				query: knowledgeMatch[2]?.trim(),
			}),
		);
	if (/^re_bootstrap\s+plan\b/i.test(command)) {
		const tools = command
			.replace(/^re_bootstrap\s+plan\b/i, "")
			.trim()
			.split(/\s+/)
			.filter(Boolean);
		return done(
			formatBootstrapPlan(
				createBootstrapPlan(tools.length ? tools : ["checksec", "gdb", "radare2", "binwalk", "nmap", "ffuf"]),
			),
		);
	}
	if (/^re_complete\s+audit$/i.test(command)) return done(formatCompletionAudit());
	if (/^re_complete\s+scaffold\b/i.test(command))
		return done(`${writeReportScaffold()}\n\n${formatCompletionAudit()}`);
	return blocked(`unsupported operation command: ${command}`);
}

async function runOperationQueue(
	pi: ExtensionAPI,
	options: { target?: string; task?: string; maxSteps?: number } = {},
): Promise<string> {
	const operation = buildOperation({ target: options.target, task: options.task, mode: "run" });
	const maxSteps = Math.max(1, Math.min(10, Math.floor(options.maxSteps ?? 1)));
	for (const step of operation.steps.filter((item) => item.status === "ready").slice(0, maxSteps)) {
		const result = await executeOperationStep(pi, step, operation.target);
		operation.executed.push(result);
		step.status = result.status === "blocked" ? "blocked" : "done";
		step.reason = result.status === "blocked" ? result.output : step.reason;
		if (result.status === "blocked") operation.blocked.push(`${step.id} ${step.command} — ${result.output}`);
	}
	operation.nextActions = operation.steps
		.filter((step) => step.status === "ready")
		.slice(0, 10)
		.map((step) => `re_operation run ${operation.target ?? "<target>"} 1 # ${step.id}`);
	const path = writeOperationArtifact(operation);
	return formatOperation(operation, path);
}

function buildOperationOutput(
	action: "plan" | "show" | "next" = "plan",
	options: { target?: string; task?: string } = {},
): string {
	if (action === "show") {
		const path = latestOperationArtifactPath();
		if (!path) return "operation_queue:\nstatus: missing\nnext: re_operation plan";
		return truncateMiddle(readText(path), 14000);
	}
	const operation = buildOperation({ ...options, mode: "plan" });
	const path = writeOperationArtifact(operation);
	if (action === "next") {
		const next = operation.steps.find((step) => step.status === "ready");
		return [
			formatOperation(operation, path),
			"",
			"next_ready_step:",
			next ? `- ${next.id} ${next.command}` : "- none",
		].join("\n");
	}
	return formatOperation(operation, path);
}

function latestDelegateArtifactPath(options: ArtifactScopeFilterOptions = {}): string | undefined {
	return latestScopedMarkdownArtifact("delegation", evidenceDelegationsDir(), options);
}

function parseOperationArtifact(path: string): OperationArtifact | undefined {
	const match = /```json\s*([\s\S]*?)\s*```/m.exec(readText(path));
	if (!match?.[1]) return undefined;
	try {
		return JSON.parse(match[1]) as OperationArtifact;
	} catch {
		return undefined;
	}
}

function latestOrBuildOperation(options: { target?: string; task?: string } = {}): {
	operation: OperationArtifact;
	path: string;
} {
	const latest = !options.target && !options.task ? latestOperationArtifactPath() : undefined;
	if (latest) {
		const operation = parseOperationArtifact(latest);
		if (operation) return { operation, path: latest };
	}
	const operation = buildOperation({ target: options.target, task: options.task, mode: "plan" });
	const path = writeOperationArtifact(operation);
	return { operation, path };
}

function delegateWorkerForStep(step: OperationStep): DelegateWorker {
	const text = `${step.phase}\n${step.command}`;
	if (/web-authz|surface|state|poc|api|websocket|graphql|jwt|cookie|session|idor|bola|authz/i.test(text))
		return "web-authz";
	if (/credential|principal|kerberos|ldap|ntlm|ticket|hash|identity/i.test(text)) return "identity";
	if (/cloud|container|k8s|kubernetes|metadata|serviceaccount|iam|rbac|privilege/i.test(text)) return "cloud";
	if (/mobile|android|ios|apk|ipa|frida|objection|smali|jni|objc|swift|emulator/i.test(text)) return "mobile-runtime";
	if (/pwn|exploit|primitive|mitigation|rop|heap|overflow|shellcode|pwntools|flake|bundle/i.test(text))
		return "pwn-exploit";
	if (/native|elf|pe|macho|binary|gdb|lldb|checksec|r2|radare|ghidra|ida|symbol|breakpoint|loader|libc/i.test(text))
		return "native-runtime";
	if (/firmware|pcap|dfir|forensic|rootfs|tshark|binwalk|extract|filesystem|emulate|timeline|decode/i.test(text))
		return "firmware-dfir";
	if (/agentsec|agent|prompt|tool-boundary|memory|injection|delegation|mcp|rag/i.test(text)) return "agentsec";
	if (/malware|ioc|yara|capa|floss|static-config|behavior|c2/i.test(text)) return "malware";
	if (/report|complete|scaffold|audit|writeup/i.test(text)) return "reporting";
	return "general";
}

function delegateObjective(worker: DelegateWorker): string {
	const objectives: Record<DelegateWorker, string> = {
		"web-authz": "证明 Web/API/WS 的认证、授权、对象所有权、状态机和 replay 边界",
		identity: "验证 credential/principal/ticket/hash/token/serviceaccount 的可用性、范围和负控",
		cloud: "证明云/K8s/container runtime config、metadata、IAM/RBAC 与最小 privilege edge",
		"mobile-runtime": "用 Frida/ADB/objection/静态清单证明移动端 runtime、hook 点、签名/加密与 native bridge",
		"native-runtime": "用 GDB/LLDB/r2/checksec 证明 native binary 的 loader/libc、符号、断点、trace 与控制流",
		"pwn-exploit": "把 binary/exploit phase 推进到 primitive、offset/leak、payload 和 replay reliability",
		"firmware-dfir": "组织 firmware/rootfs/PCAP/DFIR artifact、flow timeline、secret/config 和 transform chain",
		agentsec: "映射 prompt/tool/memory/RAG/MCP/sub-agent 边界并生成 injection replay 证据",
		malware: "提取 malware static/behavior/config/IOC 证据并沉淀可复用 rule/report",
		reporting: "合并证据、图谱、复现命令、失败路线和完成审计",
		general: "执行未归类 operation steps 并把证据回写到 ledger/checkpoints",
	};
	return objectives[worker];
}

