function runtimeBridgeSecretLike(value: string): boolean {
	return /(sk-[A-Za-z0-9_-]{10,}|ghp_[A-Za-z0-9_]{10,}|github_pat_[A-Za-z0-9_]{10,}|AKIA[0-9A-Z]{12,}|-----BEGIN [A-Z ]+PRIVATE KEY-----)/.test(value);
}

function buildProfessionalRuntimeBridgesGate(bridgeFilter?: string): ProfessionalRuntimeBridgesCheckV1 {
	ensureReconStorage();
	const index = parseToolIndex();
	const corpus = [RECON_SYSTEM_PROMPT, RECON_APPEND_SYSTEM_PROMPT, JSON.stringify(PROFESSIONAL_RUNTIME_BRIDGE_MATRIX), buildToolDigest()].join("\n");
	const specs = bridgeFilter
		? PROFESSIONAL_RUNTIME_BRIDGE_MATRIX.filter((bridge) => bridge.id === bridgeFilter || bridge.id.includes(bridgeFilter))
		: PROFESSIONAL_RUNTIME_BRIDGE_MATRIX;
	const bridges = specs.map<ProfessionalRuntimeBridgeRowV1>((bridge) => {
		const presentPreferred = bridge.preferredTools.filter((tool) => indexedToolPresent(index, tool) === true);
		const presentFallbacks = bridge.fallbackTools.filter((tool) => indexedToolPresent(index, tool) === true);
		const missingPreferred = bridge.preferredTools.filter((tool) => indexedToolPresent(index, tool) !== true);
		const proofExitFound = bridge.proofExit.filter((marker) => corpus.includes(marker));
		const artifactPlanOk = bridge.artifactPlan.length >= 3 && bridge.artifactPlan.every((path) => path.startsWith(".repi/evidence") || path.startsWith(".repi/recon"));
		const envRefOnly = bridge.envRefs.every((ref) => /^[A-Z][A-Z0-9_]+$/.test(ref) && !runtimeBridgeSecretLike(ref));
		const executableTemplateCount = bridge.commandTemplates.filter((template) => /\bre_[a-z0-9_]+\b|\bcurl\b|\bfrida\b|\bgdb\b|\bpython3\b|\bnode\b/.test(template)).length;
		return {
			bridgeId: bridge.id,
			title: bridge.title,
			status: presentFallbacks.length > 0 ? "runtime-ready" : "blocked",
			domains: bridge.domains,
			preferredTools: bridge.preferredTools,
			fallbackTools: bridge.fallbackTools,
			presentPreferred,
			presentFallbacks,
			missingPreferred,
			fallback_available: presentFallbacks.length > 0,
			commandTemplates: bridge.commandTemplates,
			artifactPlan: bridge.artifactPlan,
			artifactPlanOk,
			envRefs: bridge.envRefs,
			envRefOnly,
			proofExit: bridge.proofExit,
			proofExitFound,
			proofExitMissing: bridge.proofExit.filter((marker) => !proofExitFound.includes(marker)),
			executableTemplateCount,
			narrativeOnly: executableTemplateCount === 0,
			nextRuntimeCommands: [
				"re_runtime_bridge refresh",
				`re_runtime_bridge show ${bridge.id}`,
				bridge.id === "web-cdp-replay" ? "re_live_browser run <url>" : undefined,
				bridge.id === "mobile-frida" ? "re_mobile_runtime run <package>" : undefined,
				bridge.id === "exploit-verifier-runtime" ? "re_exploit_lab run <target> 5" : undefined,
				"re_domain_proof_exit write <domain>",
			].filter((item): item is string => Boolean(item)),
		};
	});
	return {
		kind: "ProfessionalRuntimeBridgesCheckV1",
		schemaVersion: 1,
		generatedAt: new Date().toISOString(),
		ProfessionalRuntimeBridgesCheckV1: true,
		runtime: "runtime:professional-runtime-bridges",
		toolIndexPath: toolIndexPath(),
		requiredChecks: ["professional_runtime_bridge_check", "runtime_execution_bridge_matrix", "real_toolchain_bridge_contract", "exploit_verifier_runtime_contract", "web_cdp_replay_contract", "mobile_frida_dynamic_bridge_contract", "artifact_backed_tool_execution_plan", "env_ref_secret_boundary"],
		bridges,
		closure: {
			allBridgeSpecsPresent: bridges.length === PROFESSIONAL_RUNTIME_BRIDGE_MATRIX.length || Boolean(bridgeFilter),
			allFallbacksAvailable: bridges.every((bridge) => bridge.fallback_available),
			allHaveExecutableTemplates: bridges.every((bridge) => !bridge.narrativeOnly && bridge.executableTemplateCount >= 3),
			allHaveArtifactPlans: bridges.every((bridge) => bridge.artifactPlanOk),
			allHaveProofExitMappings: bridges.every((bridge) => bridge.proofExit.length >= 5 && bridge.proofExitMissing.length === 0),
			allEnvRefsSecretFree: bridges.every((bridge) => bridge.envRefOnly),
		},
		nextRuntimeCommands: ["re_runtime_bridge show", "re_runtime_bridge refresh", "re_runtime_bridge show web-cdp-replay", "re_runtime_bridge show mobile-frida", "re_exploit_lab run <target> 5", "re_live_browser run <url>", "re_mobile_runtime run <package>"],
		invariants: ["professional_runtime_bridge_check", "runtime_execution_bridge_matrix", "real_toolchain_bridge_contract", "exploit_verifier_runtime_contract", "web_cdp_replay_contract", "mobile_frida_dynamic_bridge_contract", "artifact_backed_tool_execution_plan", "env_ref_secret_boundary", "narrative_only_bridge_rejected"],
	};
}

function writeProfessionalRuntimeBridgesArtifact(report: ProfessionalRuntimeBridgesCheckV1): string {
	ensureReconStorage();
	const path = join(evidenceToolchainDir(), `${report.generatedAt.replace(/[:.]/g, "-")}-professional-runtime-bridges.md`);
	writePrivateTextFile(path, `${formatProfessionalRuntimeBridgesGate(report, path)}\n\n## JSON\n\n\`\`\`json\n${JSON.stringify(report, null, 2)}\n\`\`\`\n`);
	appendEvidence({
		kind: "artifact",
		title: "professional-runtime-bridges",
		fact: `ProfessionalRuntimeBridgesCheckV1 bridges=${report.bridges.length} fallback=${report.closure.allFallbacksAvailable} executable=${report.closure.allHaveExecutableTemplates}`,
		command: "re_runtime_bridge show",
		path,
		verify: `cat ${path}`,
		confidence: "runtime:professional-runtime-bridges runtime_execution_bridge_matrix artifact_backed_tool_execution_plan env_ref_secret_boundary",
	});
	return path;
}

function formatProfessionalRuntimeBridgesGate(report: ProfessionalRuntimeBridgesCheckV1, path?: string): string {
	return [
		"professional_runtime_bridges:",
		"ProfessionalRuntimeBridgesCheckV1: true",
		"runtime: runtime:professional-runtime-bridges",
		path ? `artifact: ${path}` : undefined,
		`tool_index: ${report.toolIndexPath}`,
		`closure: specs=${report.closure.allBridgeSpecsPresent} fallback=${report.closure.allFallbacksAvailable} executable=${report.closure.allHaveExecutableTemplates} artifact=${report.closure.allHaveArtifactPlans} proof=${report.closure.allHaveProofExitMappings} env_ref=${report.closure.allEnvRefsSecretFree}`,
		"bridges:",
		...report.bridges.flatMap((bridge) => [
			`- bridge:${bridge.bridgeId} status=${bridge.status} fallback_available=${bridge.fallback_available}`,
			`  domains: ${bridge.domains.join(", ")}`,
			`  preferred_present: ${bridge.presentPreferred.join(", ") || "none"}`,
			`  fallback_present: ${bridge.presentFallbacks.join(", ") || "none"}`,
			`  command_templates: ${bridge.commandTemplates.join(" | ")}`,
			`  artifact_plan: ${bridge.artifactPlan.join(" | ")}`,
			`  env_refs: ${bridge.envRefs.join(", ")}`,
			`  proof_exit: ${bridge.proofExit.join("; ")}`,
			`  next: ${bridge.nextRuntimeCommands.join(" | ")}`,
		]),
		"next_runtime_commands:",
		...report.nextRuntimeCommands.map((item) => `- ${item}`),
		"invariants:",
		...report.invariants.map((item) => `- ${item}`),
	].filter(Boolean).join("\n");
}

function buildProfessionalRuntimeBridgeOutput(action: "show" | "refresh" = "show", bridgeFilter?: string): string {
	if (action === "refresh") return buildToolDigest();
	const report = buildProfessionalRuntimeBridgesGate(bridgeFilter);
	const path = writeProfessionalRuntimeBridgesArtifact(report);
	return formatProfessionalRuntimeBridgesGate(report, path);
}





function buildRuntimeAdapterExecutionGate(adapterFilter?: string): RuntimeAdapterExecutionCheckV1 {
	ensureReconStorage();
	const index = parseToolIndex();
	return buildRuntimeAdapterExecutionGateReport(adapterFilter, {
		toolIndexPath: toolIndexPath(),
		isToolPresent: (tool) => indexedToolPresent(index, tool),
	});
}

function writeRuntimeAdapterExecutionArtifact(report: RuntimeAdapterExecutionCheckV1): string {
	ensureReconStorage();
	const path = join(evidenceToolchainDir(), `${report.generatedAt.replace(/[:.]/g, "-")}-runtime-adapter-execution.md`);
	writePrivateTextFile(path, `${formatRuntimeAdapterExecutionGate(report, path)}\n\n## JSON\n\n\`\`\`json\n${JSON.stringify(report, null, 2)}\n\`\`\`\n`);
	appendEvidence({ kind: "artifact", title: "runtime-adapter-execution", fact: `RuntimeAdapterExecutionCheckV1 adapters=${report.adapters.length} runner=${report.closure.allHaveRunnerTemplates} parser=${report.closure.allHaveParserRules} ingest=${report.closure.allHaveIngestTargets}`, command: "re_runtime_adapter show", path, verify: `cat ${path}`, confidence: "runtime:adapter-execution adapter_runner_parser_ingest_contract evidence-ledger knowledge-graph memory-event" });
	return path;
}

async function runRuntimeAdapterExecution(pi: ExtensionAPI, options: { adapter?: string; target?: string; timeoutMs?: number }): Promise<string> {
	const inferredAdapter = options.adapter ?? detectRuntimeAdapterIds(options.target)[0];
	const report = buildRuntimeAdapterExecutionGate(inferredAdapter ?? options.target);
	const adapter = report.adapters.find((row) => row.adapterId === inferredAdapter) ?? report.adapters[0];
	if (!adapter) return "runtime_adapter_execution:\nstatus: missing\nnext: re_runtime_adapter show";
	if (!options.target?.trim()) return `${formatRuntimeAdapterExecutionGate(report)}\n\nblocked: target_required\nnext: re_runtime_adapter run ${adapter.adapterId} <target>`;
	const selectedRunner = adapter.present ? "native" : "fallback";
	const selectedTemplate = selectedRunner === "native" ? adapter.commandTemplate : adapter.fallbackCommandTemplate;
	const command = materializeRuntimeAdapterCommand(selectedTemplate, options.target);
	const timeout = Math.max(5000, Math.min(options.timeoutMs ?? Number(process.env.REPI_RUNTIME_ADAPTER_TIMEOUT_MS ?? 60000), 600000));
	const startedAt = new Date().toISOString();
	const result = await pi.exec("bash", ["-lc", `set +e\nexport REPI_ADAPTER_TARGET=${shellQuote(options.target)}\n${command}`], { timeout });
	const finishedAt = new Date().toISOString();
	const combined = `${result.stdout}\n${result.stderr}`;
	const parserSignals = parseRuntimeAdapterSignals(adapter, combined);
	const artifact: RuntimeAdapterExecutionArtifactV1 = {
		kind: "RuntimeAdapterExecutionArtifactV1",
		schemaVersion: 1,
		adapterId: adapter.adapterId,
		domainId: adapter.domainId,
		bridgeId: adapter.bridgeId,
		target: options.target,
		targetProfile: inspectRuntimeAdapterTarget(options.target),
		startedAt,
		finishedAt,
		selectedRunner,
		command,
		exitCode: result.code,
		killed: result.killed,
		stdoutSha256: sha256Text(result.stdout),
		stderrSha256: sha256Text(result.stderr),
		parserSignals,
		parserSignalSummary: summarizeRuntimeAdapterSignals(adapter, parserSignals),
		artifactKinds: adapter.artifactKinds,
		ingestTargets: adapter.ingestTargets,
		proofExitSignals: adapter.proofExitSignals,
	};
	const dir = join(evidenceToolchainDir(), "runtime-adapters", adapter.adapterId);
	mkdirSync(dir, { recursive: true });
	const path = join(dir, `${startedAt.replace(/[:.]/g, "-")}.json`);
	// Atomic (opt #208): temp+rename 0o644 — a torn writeFileSync would leave a
	// truncated runtime-adapter artifact JSON that the evidence-ledger `verify:
	// cat ${path}` step then points at a partial file. Matches the nearby
	// runtime-artifact atomic writes (18366/18625).
	atomicWriteFileSync(path, `${JSON.stringify({ ...artifact, stdoutHead: truncateMiddle(result.stdout, 8000), stderrHead: truncateMiddle(result.stderr, 4000) }, null, 2)}\n`, 0o644);
	appendEvidence({ kind: "runtime", title: `runtime-adapter ${adapter.adapterId}`, fact: `RuntimeAdapterExecutionCheckV1 adapter=${adapter.adapterId} runner=${selectedRunner} exit=${result.code} parser_matches=${artifact.parserSignals.reduce((sum, row) => sum + row.matches.length, 0)} ingest=evidence-ledger,knowledge-graph,memory-event`, command: `re_runtime_adapter run ${adapter.adapterId} ${options.target}`, path, verify: `cat ${path}`, confidence: "runtime:adapter-execution adapter_runner_parser_ingest_contract runner_output_parser_must_write_artifact" });
	return formatRuntimeAdapterExecutionArtifact(artifact, path);
}


